-- Poems batch 249
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('92c3a85a-395b-4b0e-94e8-e131d9dda33b','題西施捧心圖','姚勉','宋','宋诗','song-poetry','','[]','紵羅山頭浣紗餘，酥胸嬌擁顰不舒。',64,'全唐诗/poet.song.224000.json','["紵羅山頭浣紗餘，酥胸嬌擁顰不舒。", "高軒直蓋填寒閭，東家少婦羞弗如。", "越宮選進吳王側，光照姑蘇春奪色。", "鴟夷心痛痛更深，亦自顰眉但憂國。"]'),
('3269dec1-223f-4abd-ad23-7388b84d8a97','贊張英玉所畫山谷老蟻蝶圖','姚勉','宋','宋诗','song-poetry','','[]','穹碑一立承天寺，吟骨遂重宜州樓。',48,'全唐诗/poet.song.224000.json','["穹碑一立承天寺，吟骨遂重宜州樓。", "當年羣蟻亦策勳，豈知須臾夢封侯。", "南柯一散風雨惡，未若栩栩爲莊周。"]'),
('3ee0d7b2-f147-4cb9-9bb3-f71f2763c777','贊張英玉蟬驚螳螂圖','姚勉','宋','宋诗','song-poetry','','[]','一螳踉蹡上枯柳，一螳欲上鼓劍走。',64,'全唐诗/poet.song.224000.json','["一螳踉蹡上枯柳，一螳欲上鼓劍走。", "驚蟬側翅著樹枝，性命幾成落渠手。", "物生遠害當知幾，不知猶可况已知。", "千枝何處無風露，莫曳殘聲急飛去。"]'),
('9d9a4c40-cef4-4417-bc10-d29e56991fb1','禽言十詠 不如歸去','姚勉','宋','宋诗','song-poetry','','[]','翠煙深樾江村雨，蜀魄催春勸歸去。',64,'全唐诗/poet.song.224000.json','["翠煙深樾江村雨，蜀魄催春勸歸去。", "勸春春去勸未休，客子傷春慘心緒。", "只今蜀土錦城荒，蜀客望西悲故鄉。", "故鄉蜀客歸不得，何况當時蜀帝王。"]'),
('a68106a8-f841-407d-a3ad-eb7625cd9a5a','禽言十詠 泥活活','姚勉','宋','宋诗','song-poetry','','[]','黄梅蒸雨已幾時，路泥活活沒馬蹄。',64,'全唐诗/poet.song.224000.json','["黄梅蒸雨已幾時，路泥活活沒馬蹄。", "前山咫尺似千里，十步九跌行人疲。", "漫塍白水秧欲老，黄雲漸黑麥欹倒。", "泥汙后土何時乾，天若憐農放晴好。"]'),
('babccf7b-9c2a-47dc-a1bc-376bef6e507d','禽言十詠 著新脫故','姚勉','宋','宋诗','song-poetry','','[]','繰車欲動蠶春暮，水足秧青行白鷺。',64,'全唐诗/poet.song.224000.json','["繰車欲動蠶春暮，水足秧青行白鷺。", "著新脫故山禽呼，也似催人闊耕布。", "著新脫故也自奇，闊耕闊布也自宜。", "冬苗夏絹星火急，欲著無新耕亦饑。"]'),
('21fee26a-f98e-4bc1-a7fa-b14f133dc186','禽言十詠 郭公','姚勉','宋','宋诗','song-poetry','','[]','郭公古時亡國餘，姓名尚掛春秋書。',64,'全唐诗/poet.song.224000.json','["郭公古時亡國餘，姓名尚掛春秋書。", "問其故國何丘墟，知善不用惡不除。", "今人皆知笑亡郭，胸中亦自鏡善惡。", "不知山高正呼君，身是郭公猶未覺。"]'),
('5f488705-1722-40a4-bf2b-f7c076191bfb','禽言十詠 麥熟也哥哥','姚勉','宋','宋诗','song-poetry','','[]','晨起凉潤疑秋肅，格磔軥輈叫雲木。',64,'全唐诗/poet.song.224000.json','["晨起凉潤疑秋肅，格磔軥輈叫雲木。", "似催農父急腰鐮，村北村南麥皆熟。", "屋頭場地初雨乾，柳聲拍拍兒童歡。", "田家未敢冀一飽，父老相呼先了官。"]'),
('4eff13ac-75aa-47fc-95fb-2fca7e0fbd9b','禽言十詠 看蠶娘子得幾許','姚勉','宋','宋诗','song-poetry','','[]','流鶑前身織絲女，猶拋金梭學機杼。',64,'全唐诗/poet.song.224000.json','["流鶑前身織絲女，猶拋金梭學機杼。", "隔窗嬌喚看蠶姑，娘子看蠶得幾許。", "今年蠶慳熟處稀，採餘桑葉青滿枝。", "一年養蠶四番熟，安得長似開元時。"]'),
('7cd3ebba-caa7-452f-b5a7-9819adb751ec','禽言十詠 婆餠焦','姚勉','宋','宋诗','song-poetry','','[]','趁晴割麥收雲黄，熬爐新熟餠餌香。',64,'全唐诗/poet.song.224000.json','["趁晴割麥收雲黄，熬爐新熟餠餌香。", "阿婆炙餠半焦赤，阿婦駡兒嗔不食。", "山禽戲語婆勿嗔，有餠可焦猶食新。", "西家割遲麥爛死，婦姑對泣空酸辛。"]'),
('93bda133-9f5b-4d17-bb65-80f72753e502','禽言十詠 姑惡','姚勉','宋','宋诗','song-poetry','','[]','煙林望帝聲思歸，風枝齊后音悽悲。',64,'全唐诗/poet.song.224000.json','["煙林望帝聲思歸，風枝齊后音悽悲。", "如何入水化爲鳥，猶訴姑惡無停時。", "純孝通神泉鯉躍，冤氣感天霜爲虐。", "蠐螬有味安得珍，婦自不賢姑不惡。"]'),
('a5fdb233-d4be-4c6f-8d9e-8d8110655a01','禽言十詠 提葫蘆沽美酒','姚勉','宋','宋诗','song-poetry','','[]','晴煙如潑春光濃，萬花笑日爭嫣紅。',64,'全唐诗/poet.song.224000.json','["晴煙如潑春光濃，萬花笑日爭嫣紅。", "百金沽酒直取醉，有酒不醉孤東風。", "不如遂我豐年願，秫米價如黄土賤。", "家家有酒不用沽，何用提葫苦相勸。"]'),
('b2402af6-e0ab-46ff-834e-b208e32d4f39','禽言十詠 百舌','姚勉','宋','宋诗','song-poetry','','[]','百禽巧作百種音，一禽却學百種禽。',64,'全唐诗/poet.song.224000.json','["百禽巧作百種音，一禽却學百種禽。", "晴風暖日意自樂，圓吭變換皆清吟。", "多能不如止一得，多言不如止一默。", "一朝閉口不敢聲，莫有讒人在君側。"]'),
('11cc39ac-8e60-4abf-8b7b-6163c6bb694a','問鴈','姚勉','宋','宋诗','song-poetry','','[]','家山已作一月疎，囑鴈爲取秋風書。',224,'全唐诗/poet.song.224000.json','["家山已作一月疎，囑鴈爲取秋風書。", "鴈飛竟去已幾日，乃爾寂寂知何如。", "曉霜鴈聲又東去，急起出門呼鴈住。", "前時囑爾爲寄書，汝今將書落何處。", "鴈言丈夫志非常，桑弧蓬矢示四方。", "顧家安足就大事，底用屑屑悲故鄉。", "吁嗟來汝空中鴈，黄耳猶能書往返。", "飛奴解遞丞相箋，鷾鴯亦傳商婦簡。", "帛書自古倩汝傳，詩人流詠知幾年。", "汝今何事倦來往，應我不如蘇武賢。", "鴈言君擬乃如此，信史不如無此史。", "當年常侍枉教欺，我亦安能書萬里。", "湖田漠漠多菰蒲，就食聊寄江南居。", "書郵安得爲人作，君欲覓書尋鯉魚。"]'),
('0e0df621-6aca-441a-8ea6-d6a34aef384c','聞鶑','姚勉','宋','宋诗','song-poetry','','[]','風吹微湍入松篁，雲幢葉蓋相低昂。',96,'全唐诗/poet.song.224000.json','["風吹微湍入松篁，雲幢葉蓋相低昂。", "山禽此時似得意，雜奏一曲娛新凉。", "流鶑頗嫌無宮商，飛來中間作笙簧。", "廣寒一闋新霓裳，天遣鼓吹吟詩腸。", "取書細讀與相和，金舂玉應聲琅琅。", "曲終書罷各無語，林影滿庭清晝長。"]'),
('ca85a890-2d98-459b-8697-b4f209472656','觀風馬','姚勉','宋','宋诗','song-poetry','','[]','簷間鐵馬何威獰，霜刀雪劍爭鮮明。',64,'全唐诗/poet.song.224000.json','["簷間鐵馬何威獰，霜刀雪劍爭鮮明。", "秋風一吹陣脚動，跳梁舂擊聲鏦錚。", "何時真提十萬兵，金戈鐵甲相磨鳴。", "縛俘斬馘墟龍庭，歸來馬後笳鼓聲。"]'),
('20be8513-b0a5-4140-8a5e-278f24d2c198','烏鵲吟','姚勉','宋','宋诗','song-poetry','','[]','鵲噪人所憐，烏啼人所唾。',91,'全唐诗/poet.song.224000.json','["鵲噪人所憐，烏啼人所唾。", "謂鵲能報喜，謂烏常送禍。", "烏啼鵲噪何心然，孰爲此者皆其天。", "預言禍至使人避，比鵲以烏烏更賢。", "欲忠於人反嗔己，喜諛惡直常如此。", "君不見九齡去國林甫相，崇侯得君比干死。"]'),
('11e3ecec-aa53-4163-aae4-fcb59116c2c6','錢唐吟','姚勉','宋','宋诗','song-poetry','','[]','錢唐家家重生女，自小無人識機杼。',144,'全唐诗/poet.song.224000.json','["錢唐家家重生女，自小無人識機杼。", "教成歌舞十二三，花燕身材柳鶑語。", "去年學得琵琶成，今年學得彈秦箏。", "豪家亟輦明珠斛，來換綠珠入金谷。", "啟行小女肩輿來，親情送別羅酒盃。", "拜辭父母登車去，歡喜出門不回顧。", "親恩無復雉將雛，兒意亦忘鴉反哺。", "阿婆八十泣送門，自憐終身無阿孫。", "笑言阿婆不須泣，舟子乘潮渡江急。"]'),
('5dbe3c73-91f1-4d14-90e7-0d833218127e','義娼吟','姚勉','宋','宋诗','song-poetry','','[]','燕子樓中一搦春，十年紅袖消香塵。',144,'全唐诗/poet.song.224000.json','["燕子樓中一搦春，十年紅袖消香塵。", "尚書墓上白楊拱，曉燈猶伴孤眠人。", "楚樓佳麗清梅似，識得詞中秦學士。", "玉盂一笑古藤陰，便學斷腸河滿子。", "燕樓寂寞楚樓空，鄭家雲英千古同。", "崔徽心事照秋月，玉京舊恨啼春風。", "人生交態分貴賤，况是死生情分變。", "域蘞未綠拜無人，千里素車那復見。", "知義如今到此流，冠猴襟馬皆堪羞。"]'),
('4fd09591-1d14-4711-ac78-47bea9183743','聽箏','姚勉','宋','宋诗','song-poetry','','[]','春簷雪乾初日長，簾花深壓梅影香。',256,'全唐诗/poet.song.224000.json','["春簷雪乾初日長，簾花深壓梅影香。", "美人帳中午睡起，釵橫鬢嚲慵添粧。", "文窗窈窕鮫綃綠，卧按古箏橫漆玉。", "微揎翠袖露春葱，學弄梁州初遍曲。", "拂絃輕揠三兩聲，問渠學曲成未成。", "已成未成君莫問，聽取軮軋伊嚶鳴。", "七絃一似焦琴樣，立鴈參差相下上。", "左按天孫織錦絲，右斡仙人飛海杖。", "輕拔淺揠聲短長，疾徐洪纖抑復揚。", "瓶笙吐韻出蚓竅，雲車碾響升羊腸。", "雙龍曉日吟秋水，孤鸞春風悲鏡裏。", "清猿嘹喨萬松間，雛鶑惺鬆百花底。", "平生有耳喜此聽，手不能作心自醒。", "除却高山與流水，琵琶箜篌俱逕庭。", "樓中弄玉吹簫侶，同學丹山鳳凰語。", "鳳凰鳳凰來不來，蕭史行雲在何許。"]'),
('b6533bf2-439d-43ec-a85f-933f82f6ab91','贈王生','姚勉','宋','宋诗','song-poetry','','[]','三年刻楮多苦心，不龜手方只百金。',192,'全唐诗/poet.song.224000.json','["三年刻楮多苦心，不龜手方只百金。", "近來自笑巧成拙，捨去二藝趨雞林。", "文章小巧蟲雕刻，大巧天機五雲色。", "單傳此印到人間，君亦當成近朱赤。", "松麓先生嘆數窮，請君專志毋分功。", "悲絲正謂可白黑，斲雕庶得還淳風。", "方今天詔興賢急，家家倒屣迎君入。", "試按春風官柳汁，更刊進士題名集。", "從此君應百不憂，十萬腰纏鶴揚州。", "雖然文章亦徒耳，萬言不直一盃水。", "聞君一藝尤更精，明珠爲人買娉婷。", "血色羅裙掩雕字，囊金柜帛當充庭。"]'),
('688480bb-d02c-43cb-9b86-13daa9afaf3b','友山李道士抱琴來爲予作三曲請詩各爲之操 九臯','姚勉','宋','宋诗','song-poetry','','[]','青山鬰兮白雪深，四無人聲兮鶴鳴在陰。',42,'全唐诗/poet.song.224000.json','["青山鬰兮白雪深，四無人聲兮鶴鳴在陰。", "聲聞于天兮而有遐心。", "吁嗟乎，有美一人兮無密爾林。"]'),
('eb5a273f-e178-480d-b5c3-2aa4c9b5446a','友山李道士抱琴來爲予作三曲請詩各爲之操 君臣慶會','姚勉','宋','宋诗','song-poetry','','[]','衣裳治兮帝巖廊，五絃歌詠兮民物阜康。',42,'全唐诗/poet.song.224000.json','["衣裳治兮帝巖廊，五絃歌詠兮民物阜康。", "禹臯夔龍兮劍佩鏘鏘。", "吁嗟乎，安得君臣兮如此一堂。"]'),
('ceddf2d4-ecab-40aa-b12e-f80f95e02832','友山李道士抱琴來爲予作三曲請詩各爲之操 觀瀾','姚勉','宋','宋诗','song-poetry','','[]','若有人兮江之干，志在流水兮必觀其瀾。',42,'全唐诗/poet.song.224000.json','["若有人兮江之干，志在流水兮必觀其瀾。", "清風蕭蕭兮水聲潺潺。", "吁嗟乎，世道江河兮誰底其間。"]'),
('df369e3b-57ac-49e9-89bc-63c489d2a2d6','郡守勸駕樂語','姚勉','宋','宋诗','song-poetry','','[]','主人合作紫薇郎，引領羣仙覲玉皇。',64,'全唐诗/poet.song.224000.json','["主人合作紫薇郎，引領羣仙覲玉皇。", "滿袖風雲生羽翮，排空牛斗避光芒。", "錦江家讖聲名在，金榜巍科姓字香。", "典貢春官來歲事，芝香趣下瑞芝堂。"]'),
('8b515afa-c313-4a11-9c3d-952c79c09a43','新婚致語','姚勉','宋','宋诗','song-poetry','','[]','珠簾綉幕藹祥煙，合巹嘉盟締百年。',64,'全唐诗/poet.song.224000.json','["珠簾綉幕藹祥煙，合巹嘉盟締百年。", "律底春回寒谷暖，堂間夜會德星賢。", "綵軿牛女歡雲漢，華屋神仙艷洞天。", "玉潤冰清更奇絕，明年聯步璧池邊。"]'),
('a99aa93a-43b9-473b-92ff-1d704ad6de0c','對廳樂語','姚勉','宋','宋诗','song-poetry','','[]','洞房華褥綉芙蓉，惹得天香馥正濃。',64,'全唐诗/poet.song.224000.json','["洞房華褥綉芙蓉，惹得天香馥正濃。", "鳳觜續絃新跨鳳，龍頭有婿又乘龍。", "人間二月春光好，魁下三台瑞彩重。", "酬勸不須辭爛醉，詔書已下紫泥封。"]'),
('5deb8fd9-4f5d-48c5-ace2-c1eca7a73acb','女筵樂語','姚勉','宋','宋诗','song-poetry','','[]','馬前喝道狀元歸，舊婿重新此事奇。',64,'全唐诗/poet.song.224000.json','["馬前喝道狀元歸，舊婿重新此事奇。", "駕鶴驂鸞來錦水，烹龍炰鳳宴瑶池。", "滿斟蕉葉融春色，共指蟠桃祝壽期。", "後會相逢定何日，玉郎承詔入京時。"]'),
('cd454666-914b-4481-950c-58df31e3813d','禮席致語','姚勉','宋','宋诗','song-poetry','','[]','月姊當年付桂香，君家上第綠衣郎。',64,'全唐诗/poet.song.224000.json','["月姊當年付桂香，君家上第綠衣郎。", "祇今盛事追龍首，又此佳占叶鳳凰。", "暖律潛回燕谷冷，名花盡壓洛城芳。", "從今不把朱陳說，百世姚鄒話柄長。"]'),
('896e37d5-35e9-46dd-bec1-caa27910c19f','女筵樂語','姚勉','宋','宋诗','song-poetry','','[]','瑶姬來自狀元家，真是姚黄第一花。',64,'全唐诗/poet.song.224000.json','["瑶姬來自狀元家，真是姚黄第一花。", "玳席艷開春富貴，魚軒榮駐遠光華。", "梅梢欲動朱簷雪，竹葉微潮玉臉霞。", "正好留連長夜飲，未須催整七香車。"]'),
('bb01fa7c-24b8-4344-a16c-e73db0689719','郡守宴狀元樂語','姚勉','宋','宋诗','song-poetry','','[]','幾多文士踏槐黄，實出倫魁在瑞陽。',64,'全唐诗/poet.song.224000.json','["幾多文士踏槐黄，實出倫魁在瑞陽。", "千古河連留地讖，一聲臚唱破天荒。", "金釵笑擁龍頭客，寶篆濃薰燕寢香。", "方國薦賢蒙上賞，匪晨有詔下芝堂。"]'),
('e58cb444-7691-4bd8-92ce-bd5f56996bc0','送曾蒼山','姚勉','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','平生共飲西江水，今日相逢南浦雲。',32,'全唐诗/poet.song.224000.json','["平生共飲西江水，今日相逢南浦雲。", "玉潔日光湖上宰，與君有舊是斯文。"]'),
('9af33e26-e8f7-45b6-9aa5-56670f2fa66d','鬰孤臺九日','姚勉','宋','宋诗','song-poetry','','[]','天風吹上鬰孤臺，太守登高領客來。',64,'全唐诗/poet.song.224000.json','["天風吹上鬰孤臺，太守登高領客來。", "地近九霄星斗大，秋涵八景水雲開。", "吟成一徑黄花笑，召節歡傳紫詔催。", "琴鶴自隨千古事，興來且與盡餘盃。"]'),
('b9db9c1d-5f2d-490d-bf4f-e9d330261705','輓楊玉溪','姚勉','宋','宋诗','song-poetry','','[]','蜀道艱難又幾年，錦城斷礎带凄烟。',64,'全唐诗/poet.song.224000.json','["蜀道艱難又幾年，錦城斷礎带凄烟。", "從今井絡虧全勢，只恨坤輿失巨賢。", "山有蛾眉空積雪，國無峻柱可擎天。", "英魂楚楚能知否，應在青城作浪仙。"]'),
('fa3d14ac-667d-452b-ad9c-b9a70fd9d68c','秋夜','姚勉','宋','宋诗','song-poetry','','[]','明明月影带河流，雁在天邊鶴在洲。',64,'全唐诗/poet.song.224000.json','["明明月影带河流，雁在天邊鶴在洲。", "四壁蛩催幽夢覺，滿囊螢助讀書油。", "金莖露點三更冷，銀漢星移萬里秋。", "醉倚不堪回首處，雙清風月儘淹留。"]'),
('75154dc1-43de-4f21-b236-037d1d722d2e','示同學','姚勉','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','蠶絲義理苦追尋，方寸那容外物侵。',64,'全唐诗/poet.song.224000.json','["蠶絲義理苦追尋，方寸那容外物侵。", "伯樂未逢無識價，子期不遇少知音。", "泉源有本淵淵靜，學海無涯步步深。", "仰望泰山高北斗，何時許我一登臨。"]'),
('ab534366-17c3-4554-a04c-0151ed326350','戲叔納寵','姚勉','宋','宋诗','song-poetry','','[]','阿大中郎喜事宜，黄金不惜買蛾眉。',64,'全唐诗/poet.song.224000.json','["阿大中郎喜事宜，黄金不惜買蛾眉。", "春風带醉欺桃葉，暮雨凝絲滯柳枝。", "香閣鸞偕雙雁奠，妝臺鳳引兩皇來。", "從茲准協熊羆夢，多辦庫錢爲洗兒。"]'),
('e213318c-ffaf-4cff-8fdb-1ae9c12fcd6e','游曲江分韵得月字','姚勉','宋','宋诗','song-poetry','','[]','曲江磯頭山崒嵂，此景江南誇第一。',64,'全唐诗/poet.song.224000.json','["曲江磯頭山崒嵂，此景江南誇第一。", "漁舟晚弄烟波閒，市樓春映晴嵐出。", "擁輿長吟入畫圖，席地草飲成真率。", "更叩山房僧榻眠，卧聽松風待明月。"]'),
('79564430-6f81-4546-88ce-8bb72795cb63','句','黄德明','宋','宋诗','song-poetry','','[]','晚煙晴带濕，春霧暖生香。',12,'全唐诗/poet.song.224000.json','["晚煙晴带濕，春霧暖生香。"]'),
('ce75c49d-6a9b-42a0-8374-587331c5ad86','月代','許月卿','宋','宋诗','song-poetry','','[]','月代太陽，太陽代月。',120,'全唐诗/poet.song.224000.json','["月代太陽，太陽代月。", "君逸臣勞，職分無越。", "穆穆皇皇，明明在烈。", "光于四方，罔不秉哲。", "火明水清，坎離斯設。", "日月有明，容光靡闕。", "無非教也，教亦不屑。", "金取其清，分明之精。", "東有啟明，西有長庚。", "金清月白，助天日明。", "日明相續，萬物咸覩。", "匪今斯今，不瞽萬古。"]'),
('b51aa210-1e49-4eac-8df7-0ceffa0feb01','次韻春谷','許月卿','宋','宋诗','song-poetry','','[]','谷如三月間，屋向萬山安。',48,'全唐诗/poet.song.224000.json','["谷如三月間，屋向萬山安。", "春谷與山屋，別有天地寬。", "枯淡風月皎，富貴鶑花遶。", "大山表牡丹，此意殊未曉。"]'),
('59f95ec2-1849-4215-8cac-722504c40651','箕山','許月卿','宋','宋诗','song-poetry','','[]','箕山惟一瓢，襄邑亦四壁。',108,'全唐诗/poet.song.224000.json','["箕山惟一瓢，襄邑亦四壁。", "古今一許氏，傳家以清白。", "茶山與東萊，三詩映圭璧。", "後來二三賢，題品互紬繹。", "南軒推學授，晦翁要事實。", "亦有小東萊，經濟亦何切。", "極意深源流，敷殖久大業。", "臨川有二許，我來秋蕭瑟。", "撫卷三嘆起，寒花香的皪。"]'),
('11733193-cecb-4795-80d7-11bdbf826d0c','送碧梧入府','許月卿','宋','宋诗','song-poetry','','[]','人勸公入相，我勸公早歸。',264,'全唐诗/poet.song.224000.json','["人勸公入相，我勸公早歸。", "今以副樞入，好以元樞回。", "易爲六經宗，學易貴知時。", "時止則時行，時義大矣哉。", "故嘗論今日，兩語見稱奇。", "但且爲執政，宰相未可爲。", "若爲伴食相，何如酒一盃。", "曾以語裕翁，裕翁爲一咍。", "英雄見略同，明公試思之。", "文正爲清獻，何曾美鼎梅。", "史冊香萬古，日月名長在。", "時止時則行，宰相須時來。", "時來然後相，當傳忠定衣。", "官職難名節，願公玉無疵。", "壯節題初節，願公玉無灰。", "耐久老柱石，身佩國安危。", "五福一曰壽，壽國身之樞。", "請君看老子，寡慾身壽眉。", "心清萬里明，可杜倖時窺。", "寡慾善養心，軒鑑照魅魑。", "歲晚成二老，種蠡相塤箎。", "坐令四太平，太宗生光輝。"]'),
('f21478f5-12eb-48b9-8528-f24ab18cbed2','贈胡菊軒','許月卿','宋','宋诗','song-poetry','','[]','好物不雖多，自悟方悟他。',60,'全唐诗/poet.song.224000.json','["好物不雖多，自悟方悟他。", "心迷法華轉，心悟轉法華。", "願得無言經，盡度恒河沙。", "盡度一切已，依然無一物。", "籟鳴天河斜，清風共明月。"]'),
('1e250238-59d8-47bb-8032-661f3aa60d73','除月二十三日夜夢','許月卿','宋','宋诗','song-poetry','','[]','仙君重瞳衮衣明，紅雲一朶當殿楹。',128,'全唐诗/poet.song.224000.json','["仙君重瞳衮衣明，紅雲一朶當殿楹。", "千官拜舞環佩鳴，中有一人攝齊升。", "琅琅敷誦百辟驚，首云有臣許月卿。", "合在帝所式群英，煌煌召節來帝廷。", "膚使奕奕華弓旌，我時荷邊食芡菱。", "坐茅心渙儼不聽，從天飛下蒼葱珩。", "申傳帝命通叮嚀，親授秘訣餐長生。", "提耳言言帝旨令，夢回題詩香枕屏。"]'),
('46ddbf60-f4a0-4f72-9bd2-2dffda6d1e2b','次韻陳肇芳竿贈李相士','許月卿','宋','宋诗','song-poetry','','[]','相心然後相人形，試相何時可太平。',96,'全唐诗/poet.song.224000.json','["相心然後相人形，試相何時可太平。", "集思廣益真宰相，開誠布公肝膽傾。", "先相君子與小人，小人枉了君子贏。", "見吾善者笑局局，眼明黄山峰六六。", "何哉逆整干天誅，衰漢生靈已魚肉。", "安得重見無極翁，光風霽月黄山谷。"]'),
('bca5af7e-60b1-44e1-a378-21e52d92f23d','次韻謝君直贈李相士','許月卿','宋','宋诗','song-poetry','','[]','一年景讓秋光奇，山水秋來皆有姿。',96,'全唐诗/poet.song.224000.json','["一年景讓秋光奇，山水秋來皆有姿。", "君於何處相人物，誰爲盜跖誰伯夷。", "伯夷海濱待時清，秋空無雲正清時。", "相人不若相時好，相時而動談笑麾。", "笑殺馮道五季時，興亡不喜而不悲。", "相師試相馮道相，視國傳舍如弈棋。"]'),
('f9f532ec-d663-45d4-8f0f-60fb75c68d9e','京城看月','許月卿','宋','宋诗','song-poetry','','[]','幾千萬里碧琉璃，中有一圓光照之。',104,'全唐诗/poet.song.224000.json','["幾千萬里碧琉璃，中有一圓光照之。", "更無一物可與對，部勒星宿光陸離。", "憶昔看月大江頭，天地中間風吹衣。", "凡客無緣相賓主，獨携杯酒獨吟詩。", "祇今千門萬戶閉，良夜京華無人知，似我快活更有誰。", "故山今宵月更奇，明日懶人真箇歸。"]'),
('a8bd1153-deaa-4c61-8af2-fe4dcc1fae1c','故人','許月卿','宋','宋诗','song-poetry','','[]','故人歸作山中相，老我聊乘雪夜舟。',96,'全唐诗/poet.song.224000.json','["故人歸作山中相，老我聊乘雪夜舟。", "細君頗訝不入市，山中訪友將何求。", "扉屨資糧奪之去，毀車截鐙挽予留。", "一笑謂汝賢細君，無求我乃肯出游。", "宰相良解軒輊予，定難屈膝低我頭。", "同雲一色天欲雪，夜深雲散月明樓。"]'),
('81f7d0d4-c1df-4a45-82ad-8e2a48cc99b6','次韻胡溫升玉甫西野','許月卿','宋','宋诗','song-poetry','','["\u897f\u6e56"]','偶爲西湖萬山出，三省興中歌四勿。',128,'全唐诗/poet.song.224000.json','["偶爲西湖萬山出，三省興中歌四勿。", "中庸公子惠新詩，句裏韓筋猶柳骨。", "文章感慨須和平，能泣鬼神風雨驚。", "和聲似鳴國家盛，送東野序序文鳴。", "西野文鳴東野法，積中和順英華發。", "我詩不作郊島寒，曾誅莓苔隨意踏。", "誰道楊花本無才，天展湖山圖畫開。", "何須更問逋之覓，夜深明月半窗梅。"]'),
('b4d14e02-efa3-409e-9148-f761ee2145fd','次韻','許月卿','宋','宋诗','song-poetry','','[]','臨川老儒王半山，文章未肯班傳間。',160,'全唐诗/poet.song.224000.json','["臨川老儒王半山，文章未肯班傳間。", "亦有臨淄晏元獻，樂府一奏開天顔。", "我來此州嗟何晚，前哲風流挽不還。", "泉石黯淡山氣瘦，芙蓉飄零秋意闌。", "有客携詩來過我，議論磊落文波瀾。", "詩盟豈止尋宗派，理學猶規拜將壇。", "風雷凜凜三寸舌，招槌賢拂佐天慳。", "古來言行要相副，願言大德不踰閑。", "秋月皎皎鶴蹲蹲，春風洩洩禽關關。", "江岷山兮溪嶓塚，天根躡兮月窟攀。"]'),
('1a655c5f-96d4-470d-a3b7-3dfe6c9dc9f5','題明皇貴妃上馬圖','許月卿','宋','宋诗','song-poetry','','[]','開元天寶號太平，快活三郎偏縱情。',288,'全唐诗/poet.song.224000.json','["開元天寶號太平，快活三郎偏縱情。", "帝閑天驥雲雷駃，回首絕憐妃子醉。", "海棠酣春睡未足，扶上馬時頹山玉。", "二璫兩邊扶蹋𩍐，群姬爭扶不用命。", "萬花叢，玉山花，花朝王，醉牡丹。", "共立馬前黄幡綽，獻笑顔容似嘲謔。", "三郎勒馬頻回頭，兩手按膝雙凝眸。", "夾立兩旁御弓箭，带御器械如行殿。", "二璫相語儼相向，貴妃未至龍顔望。", "龍顔不怡吾曹憂，昵昵私語雙燕秋。", "御前兩驥立仗俟，御龍整暇聊緩轡。", "卷中何止數十人，十人眼只在一身。", "朕能墜馬替妃子，不忍花飛驚玉體。", "三郎但念妃子醉，豈知身醉誤國事。", "儻知敬是常惺惺，提主人翁教醉醒。", "醜醜婦斟薄薄酒，醜婦添翁多少壽。", "無鹽爲后能彊齊，夙夜警戒鷄鳴詩。", "花鈿安得紛委地，馬嵬安得有墜時。"]'),
('3406ad7e-b59f-4855-931f-a86506050cb8','涉世','許月卿','宋','宋诗','song-poetry','','[]','涉世如溪谷，只宜在淺處。',155,'全唐诗/poet.song.224000.json','["涉世如溪谷，只宜在淺處。", "一生如一日，未暮早歸去。", "君不見偉哉男子韓淮陰，往往正坐涉世深。", "功成身退豈不好，當時何事歸不早。", "人生少年須立事，生我不應負天地。", "了却君王事便休，去時莫待雨淋頭。", "如今版圖半烟霧，眼看流離無限子。", "取將舊物還君王，襁褓赤子寢之床。", "青天白日正亭午，歸去彈琴鶴對舞。", "靜與賢傳不□□，春風吹袂浴沂天。"]'),
('81b6d979-8164-40d1-bcc2-4b1e884ecf19','山近','許月卿','宋','宋诗','song-poetry','','[]','山近綠映日，山遠青带烟。',102,'全唐诗/poet.song.224000.json','["山近綠映日，山遠青带烟。", "平生有山癖，夢亦山水邊。", "山好水益媚，山老水連天。", "我家非洛中，亦非獨樂園。", "只在山屋上，下亦有流泉。", "俯仰頗樂之，妙處無昔賢。", "今日來別墅，水滿山四環。", "嗚呼何處無山水，有酒且飲明月在前山。"]'),
('41957839-29a7-4cc5-b9d7-f0da1fe45c63','新安','許月卿','宋','宋诗','song-poetry','','[]','新安別無奇，只有千萬山。',90,'全唐诗/poet.song.224000.json','["新安別無奇，只有千萬山。", "千山萬山中，其奇乃出焉。", "下者爲硯石，與世生雲烟。", "高者無繫累，飄然出神仙。", "忽生朱晦庵，追千萬世前。", "示千萬世後，如日月當天。", "嗚呼新安生若人，不知再生若人是何年。"]'),
('0864af55-660c-4425-a86f-cc3c52119a2d','木犀','許月卿','宋','宋诗','song-poetry','','[]','詩到黄初上，高標不肯唐。',48,'全唐诗/poet.song.224000.json','["詩到黄初上，高標不肯唐。", "分封在香國，筮仕得黄裳。", "錦晝纍金印，瑶英案玉皇。", "黄香天下士，誰得並清芳。"]'),
('67c7ff92-43e8-41de-9d0e-0087ae856f59','曉幄','許月卿','宋','宋诗','song-poetry','','[]','曉幄明初日，晨鐘遞北風。',48,'全唐诗/poet.song.224000.json','["曉幄明初日，晨鐘遞北風。", "人生行樂著，天道好還同。", "我友詩三昧，吾衰酒一中。", "萬間君雅志，突兀倚晴空。"]'),
('1a1a1fb2-120b-4f50-ac70-715e4dba9107','雲邊','許月卿','宋','宋诗','song-poetry','','[]','雲邊人種麥，天際我歸舟。',48,'全唐诗/poet.song.224000.json','["雲邊人種麥，天際我歸舟。", "月色輕寒夜，笛聲何處樓。", "久晴人渴雨，倦仕我思休。", "高士傳閑看，東籬花正幽。"]'),
('0e42b1bb-34f8-4ec2-9449-e1a9281bd4a0','明月','許月卿','宋','宋诗','song-poetry','','[]','明月天雙鑑，清湖地萬弓。',48,'全唐诗/poet.song.224000.json','["明月天雙鑑，清湖地萬弓。", "人行楊柳外，身在畫圖中。", "天闊雙眸快，樓高萬象融。", "故山應更好，楊柳映芙蓉。"]'),
('89864002-491a-4573-852b-1cab870dbe1a','甥館  其一','許月卿','宋','宋诗','song-poetry','','[]','月色真圖畫，風聲古瑟琴。',48,'全唐诗/poet.song.224000.json','["月色真圖畫，風聲古瑟琴。", "月風天地職，風月聖賢心。", "竹砌水如璧，梧岡朋盍簪。", "不須聯句得，天籟竹梧吟。"]'),
('308f184d-2442-4868-a9b1-8c7a495ea999','甥館  其二','許月卿','宋','宋诗','song-poetry','','[]','冬至思吾姪，樊川示阿宜。',48,'全唐诗/poet.song.224000.json','["冬至思吾姪，樊川示阿宜。", "驅羊官易取，觀象易難知。", "不遠復三字，大音聲一詩。", "屏山宗邵子，晦木不忘歸。"]'),
('3a5630aa-28ef-4ff5-865b-4f13a34c8a36','甥館  其三','許月卿','宋','宋诗','song-poetry','','[]','醉鄉真廣大，靜夜絕囂塵。',48,'全唐诗/poet.song.224000.json','["醉鄉真廣大，靜夜絕囂塵。", "月色明如晝，天涯總是春。", "鳥飛林不夜，蝶夢路無人。", "天地中間我，孤高誰與鄰。"]'),
('c71a111d-9912-45c2-8688-65445d927325','甥館  其四','許月卿','宋','宋诗','song-poetry','','[]','國士今爲鬼，有棺空斷腸。',48,'全唐诗/poet.song.224000.json','["國士今爲鬼，有棺空斷腸。", "綠衣長至節，丹旐短松岡。", "父乃哭其子，天乎殲此良。", "傷情臯某復，挽些謾巫陽。"]'),
('c1b50fc8-9c31-4ed0-8997-f3a191a748a2','甥館  其五','許月卿','宋','宋诗','song-poetry','','[]','國士報國士，後人哀後人。',48,'全唐诗/poet.song.224000.json','["國士報國士，後人哀後人。", "萬物邪勝正，一理屈終伸。", "秦暴二世滅，周仁八百春。", "紫雲樓上語，億載宋深仁。"]'),
('f4b7a93e-6374-4da6-9d62-780a4534860a','吊程貢元','許月卿','宋','宋诗','song-poetry','','[]','灑淚陳情表，何心貢澤宮。',48,'全唐诗/poet.song.224000.json','["灑淚陳情表，何心貢澤宮。", "波平看躍鯉，浪急不成龍。", "花誥榮孀母，藍袍付畫工。", "無人儔孝友，烟樹慘新封。"]'),
('81a68446-5c86-42aa-9439-5a2c9e06e613','代仍六弟吊程貢元  其一','許月卿','宋','宋诗','song-poetry','','[]','仁者竟不壽，世事空悠悠。',48,'全唐诗/poet.song.224000.json','["仁者竟不壽，世事空悠悠。", "霜滿人洪墓，月寒尊美樓。", "慈烏千載恨，薦鶚一生休。", "畫史成何事，青山烱照眸。"]'),
('6a8e3d3c-4c0c-4e5d-a8f2-b867c05581b5','代仍六弟吊程貢元  其二','許月卿','宋','宋诗','song-poetry','','[]','嚚訟漸成俗，如君今豈多。',48,'全唐诗/poet.song.224000.json','["嚚訟漸成俗，如君今豈多。", "仲尼仁者靜，下惠聖之和。", "夜月數聲笛，春風一再歌。", "紛紛當泚顙，視此石嵯峨。"]'),
('a6667412-4850-41fc-baf2-ec3abf3e3fff','代仍六弟吊程貢元  其三','許月卿','宋','宋诗','song-poetry','','[]','松下草不殖，豪家多不仁。',48,'全唐诗/poet.song.224000.json','["松下草不殖，豪家多不仁。", "惟君淡於水，與物靜爲春。", "多爲流涕者，應無切齒人。", "墓前有梧檟，那復見荆榛。"]'),
('6f00f2d5-e77a-433f-bd30-3272349ad507','挽番陽戴如曾貢士母金氏','許月卿','宋','宋诗','song-poetry','','[]','霜氣凜閨妹，嚴風老更癯。',48,'全唐诗/poet.song.224000.json','["霜氣凜閨妹，嚴風老更癯。", "詩書謂有子，門戶可無夫。", "鶵鳳橫秋鶚，孤鸞啼夜烏。", "長松有風雨，枯草但平蕪。"]'),
('f958940f-6f8e-43b1-803a-1809d7b8dd4f','次韻汪敬子','許月卿','宋','宋诗','song-poetry','','[]','好善芝蘭馨，惡惡鮑魚腥。',48,'全唐诗/poet.song.224000.json','["好善芝蘭馨，惡惡鮑魚腥。", "一心宰天地，萬世流風霆。", "六經如元氣，異端如氛埃。", "會往洙泗濱，傳取心印回。"]'),
('7737ec10-b657-46e5-a2f1-5328346817a0','挽汪士洪','許月卿','宋','宋诗','song-poetry','','[]','昔日杜小姪，中年馬少游。',48,'全唐诗/poet.song.224000.json','["昔日杜小姪，中年馬少游。", "不知身外事，祇覺鬢邊秋。", "有子三株柳，同公荒草邱。", "梅溪一夜雪，片片逐寒流。"]'),
('295a7213-ec0b-4963-b43f-2a4e4c59c23a','同滕推游朱緋堂二首  其一','許月卿','宋','宋诗','song-poetry','','[]','當日朱緋夢，荒烟化鶴城。',48,'全唐诗/poet.song.224000.json','["當日朱緋夢，荒烟化鶴城。", "斜陽邊草色，深樹裏禽聲。", "欲雨路微濕，出雲山半青。", "神游應故里，只欠愛翁亭。"]'),
('b0f0975c-abc6-4acc-b414-34ee54b6b957','同滕推游朱緋堂二首  其二','許月卿','宋','宋诗','song-poetry','','[]','此翁有山癖，曾此夢魂驚。',48,'全唐诗/poet.song.224000.json','["此翁有山癖，曾此夢魂驚。", "慷慨思逾淡，郊行酒易醒。", "石苔和夢濕，歸棹載詩輕。", "回首暮雲碧，兩賢沙磧行。"]'),
('6d90a364-78c6-40ac-a700-981762134780','挽外舅二首  其一','許月卿','宋','宋诗','song-poetry','','[]','人間三十二，名字幾千春。',48,'全唐诗/poet.song.224000.json','["人間三十二，名字幾千春。", "慷慨漢游俠，孝慈周吉人。", "視物猶視己，顧親寧顧身。", "山中當出相，嗣子世其仁。"]'),
('d593f856-ebfe-4cef-9a58-5f7a1dd77901','挽外舅二首  其二','許月卿','宋','宋诗','song-poetry','','[]','月卿方髻時，公欲東床之。',48,'全唐诗/poet.song.224000.json','["月卿方髻時，公欲東床之。", "我姑已黄土，公鬢正青絲。", "忽忽成今古，茫茫問孰誰。", "但能抱茂子，灑淚讀新碑。"]'),
('78b4477b-aa2e-469f-a80d-412958ec2258','有感','許月卿','宋','宋诗','song-poetry','','[]','一飲地黄酒，冤哉入九泉。',48,'全唐诗/poet.song.224000.json','["一飲地黄酒，冤哉入九泉。", "雲孤無葬地，雪霽有蒼天。", "今歲難張詠，他年高董宣。", "視吾匣中劍，光射斗牛邊。"]'),
('a0fe04bd-1909-43fd-ac8b-ed6d0f4c9438','住黛障','許月卿','宋','宋诗','song-poetry','','[]','黛障地眉展，綠波天畫開。',48,'全唐诗/poet.song.224000.json','["黛障地眉展，綠波天畫開。", "鴛鴦長不散，翡翠去還來。", "壇杏頹垣裏，隴梅荒草堆。", "山川渾似舊，不管曲聲哀。"]'),
('4249fc0a-3e73-48e3-a736-66163d8c92b9','夢中作','許月卿','宋','宋诗','song-poetry','','[]','我來烟水遠，漁艇夜鳴榔。',48,'全唐诗/poet.song.224000.json','["我來烟水遠，漁艇夜鳴榔。", "萬仞巫山聳，一宵秋夢長。", "金翹何婀娜，玉佩遽叮噹。", "月冷天鷄曉，空餘枕屏香。"]'),
('b41820af-edc3-4b04-bd03-c96310d04fa4','閒賦','許月卿','宋','宋诗','song-poetry','','[]','老大天諳練，殷勤月往還。',48,'全唐诗/poet.song.224000.json','["老大天諳練，殷勤月往還。", "岩巒有奇操，泉石亦清淡。", "隔浦飛秋葉，開窗看夕山。", "天心端正月，潭水夜深參。"]'),
('b8c94a4e-3daf-46ef-aab0-a77bc1956a5a','野人','許月卿','宋','宋诗','song-poetry','','[]','野人方蠖屈，天子正龍飛。',48,'全唐诗/poet.song.224000.json','["野人方蠖屈，天子正龍飛。", "東閣翹林騪，北山□□移。", "鵩來賈生去，熊兆太公歸。", "地主殷勤別，雲霄萬里期。"]'),
('f2d72f16-2ba3-4cf1-be3d-a48fb0f9a8b4','次韻鄭將士','許月卿','宋','宋诗','song-poetry','','[]','何曾離日用，千古到如今。',48,'全唐诗/poet.song.224000.json','["何曾離日用，千古到如今。", "菊蕊霜全節，梅花月印心。", "韓公蘄竹詠，蘇子楚山音。", "谷口微吾子，風流何處尋。"]'),
('c6e742c7-e0bc-4ad5-9cda-367a4005e301','霜日','許月卿','宋','宋诗','song-poetry','','[]','霜日步行遲，雲山履曆長。',48,'全唐诗/poet.song.224000.json','["霜日步行遲，雲山履曆長。", "蘆花相遜揖，松樹自宮商。", "竹動鳴珂里，桃成衣錦鄉。", "水邊籬落好，一夜玉爲堂。"]'),
('407c0f8b-1695-47ca-830e-3413bad0e260','得安道中','許月卿','宋','宋诗','song-poetry','','[]','洲渚但明月，人烟如曉星。',48,'全唐诗/poet.song.224000.json','["洲渚但明月，人烟如曉星。", "春泥纔故里，秋水又浮萍。", "衣破披簑冷，厨空煮草腥。", "抱兒含笑語，衣裏麥青青。"]'),
('5b192a3b-6f66-4965-997e-fed365f0b5ab','挽胡制機康侯','許月卿','宋','宋诗','song-poetry','','[]','鷺點青松白，鶑穿綠柳黄。',48,'全唐诗/poet.song.224000.json','["鷺點青松白，鶑穿綠柳黄。", "兒時工對偶，老去更文章。", "誅意平生學，爰咨去路忙。", "酒邊招隠操，我更憶山堂。"]'),
('8bcfa155-9b7e-4a28-b605-0091c7820a61','寄郭衢州','許月卿','宋','宋诗','song-poetry','','[]','渤海潢池盜，龔卿奉詔憂。',48,'全唐诗/poet.song.224000.json','["渤海潢池盜，龔卿奉詔憂。", "東軒繼芳躅，西府踵清流。", "同榜黄扉匹，中峰皂蓋儔。", "中齋同一笑，山屋好中秋。"]'),
('f4335bd1-b150-4fcc-9e4e-aecfbc2565c9','重寄郭衢州','許月卿','宋','宋诗','song-poetry','','[]','細數東京士，無如許郭優。',48,'全唐诗/poet.song.224000.json','["細數東京士，無如許郭優。", "山林異朝市，姓字欠書郵。", "久已巢由隠，難成李郭舟。", "三衢春有脚，山屋好中秋。"]'),
('c94eef91-a74c-4556-8c01-244ec3dfa5ff','寄留夢炎','許月卿','宋','宋诗','song-poetry','','[]','山屋好中秋，中齋炯在眸。',48,'全唐诗/poet.song.224000.json','["山屋好中秋，中齋炯在眸。", "中流誰砥柱，野水却孤舟。", "上意甘盤甚，來遲季子留。", "願毋淹獨樂，留相九重休。"]'),
('0b5a026c-27d8-401c-971a-6a31154595c5','重寄留夢炎','許月卿','宋','宋诗','song-poetry','','[]','安得肉生羽，從公出外游。',48,'全唐诗/poet.song.224000.json','["安得肉生羽，從公出外游。", "同年多契闊，新句孰賡酬。", "天玉梅花雪，人寒野水舟。", "中齋難醉白，山屋好中秋。"]'),
('a119f8cf-052c-447c-ad82-a9d2ffa89206','夜永','許月卿','宋','宋诗','song-poetry','','[]','夜永月清甚，雨餘風快哉。',48,'全唐诗/poet.song.224000.json','["夜永月清甚，雨餘風快哉。", "月將槐影出，風遣桂香來。", "風至地自掃，月來雲亦開。", "三千翰林手，光霽瑩靈臺。"]'),
('8b193166-9e58-48a7-85f5-8fc272fdcf10','客來','許月卿','宋','宋诗','song-poetry','','[]','客來商略詩，夜市正驚時。',48,'全唐诗/poet.song.224000.json','["客來商略詩，夜市正驚時。", "雲破天青眼，烟收月白眉。", "芙蓉天富貴，松竹月清奇。", "我醉欲眠去，携琴明日遲。"]'),
('331bc3d2-f80a-427d-b6a2-718a82d56274','咸淳','許月卿','宋','宋诗','song-poetry','','[]','咸淳風樂好，淳厚似咸平。',48,'全唐诗/poet.song.224000.json','["咸淳風樂好，淳厚似咸平。", "人意逢春樂，天心遇社晴。", "征僮催遠信，舞袖促新聲。", "今歲梅能耐，咸平詩可盟。"]'),
('a5c6dfa9-4724-4770-9860-6e9fd7d94802','送張平湖山遊','許月卿','宋','宋诗','song-poetry','','[]','殷勤來訪別，去作子長游。',48,'全唐诗/poet.song.224000.json','["殷勤來訪別，去作子長游。", "雪霽月清甚，天寒鴈過不。", "沙堤今相府，花苑古蘇州。", "歸路梅花好，還來問白鷗。"]'),
('5a780f24-4320-412b-86d7-a0b4a7ae83cc','次胡伯凱韻','許月卿','宋','宋诗','song-poetry','','[]','日日常三絕，時時酒一杯。',48,'全唐诗/poet.song.224000.json','["日日常三絕，時時酒一杯。", "西銘爐上雪，太極地中雷。", "屏破青山出，池成綠水來。", "飯餘三兩步，一樹木犀開。"]'),
('dfa227f2-4f35-47e0-a96a-6a9f5f71546b','題項橫父臨清亭時方生孫','許月卿','宋','宋诗','song-poetry','','[]','青梅如豆子，更可緩臨清。',48,'全唐诗/poet.song.224000.json','["青梅如豆子，更可緩臨清。", "倚杖閑花落，憑欄芳草生。", "逢人須說項，生子又添丁。", "千葉桃難實，山茶耐久盟。"]'),
('c6bf9c0b-a395-45fa-80c5-7926a923b8fe','捧硯姬空翠二首  其一','許月卿','宋','宋诗','song-poetry','','[]','捧硯姬空翠，隨琴鶴曉烟。',48,'全唐诗/poet.song.224000.json','["捧硯姬空翠，隨琴鶴曉烟。", "夕陽更山外，流水自樓前。", "芳草垂楊地，和風麗日天。", "戲游看處處，明媚自年年。"]'),
('0c2c9a19-cf4b-4be6-a1cd-82e01b07174f','捧硯姬空翠二首  其二','許月卿','宋','宋诗','song-poetry','','[]','看山車放慢，遇水馬爭先。',48,'全唐诗/poet.song.224000.json','["看山車放慢，遇水馬爭先。", "須信一年景，無如三月天。", "露花如此好，烟柳十分員。", "客醉不須去，竹床相對眠。"]'),
('43add65e-4c3e-46f5-bd46-8ad8790ca15e','獻歲','許月卿','宋','宋诗','song-poetry','','[]','獻歲歡聲沸，清晨寒氣侵。',48,'全唐诗/poet.song.224000.json','["獻歲歡聲沸，清晨寒氣侵。", "四時春是首，三日雨爲霖。", "綠展垂楊眼，青呈芳草心。", "日晴仍夜雨，擊壤費謳吟。"]'),
('d2f9195d-91c2-4b9b-ab95-496b48cfccde','梅叟','許月卿','宋','宋诗','song-poetry','','[]','梅叟真佳客，冰壺賢主人。',48,'全唐诗/poet.song.224000.json','["梅叟真佳客，冰壺賢主人。", "移樽隨月飲，顧典到更深。", "蠟炬精神耐，梅花氣象新。", "明朝山屋去，隠者詎能尋。"]'),
('2b2092bb-ca50-4e36-a2ac-1e37ff4a9d64','挽妹婿汪汻四首  其一','許月卿','宋','宋诗','song-poetry','','[]','奉禮徒員外，京師枉治中。',48,'全唐诗/poet.song.224000.json','["奉禮徒員外，京師枉治中。", "二郎槐不做，四老橘成空。", "三鳳壁岩子，雙龍寶劍雄。", "萬人真莫贖，愁絕老坡翁。"]'),
('9fceaadf-6d66-446f-b2d9-9406b12f87db','挽妹婿汪汻四首  其二','許月卿','宋','宋诗','song-poetry','','[]','郎罷當年語，深閨婉娩三。',48,'全唐诗/poet.song.224000.json','["郎罷當年語，深閨婉娩三。", "有齊之季女，必得有奇男。", "滿目呱呱泣，傷心切切彈。", "離鸞驚別鵠，何日淚痕乾。"]'),
('8cffafbd-2896-49d0-9d6c-761a8c88f5c5','挽妹婿汪汻四首  其三','許月卿','宋','宋诗','song-poetry','','[]','一疾那知死，三朝竟不醒。',48,'全唐诗/poet.song.224000.json','["一疾那知死，三朝竟不醒。", "遺羹真慘愴，分肉尚精明。", "玉樹衣難綵，壁岩氈枉青。", "英魂千古在，稚子讀書聲。"]'),
('ad6478ef-1bbc-4d97-9982-cd0bdc0b8d64','挽妹婿汪汻四首  其四','許月卿','宋','宋诗','song-poetry','','[]','亡恙壁岩日，媒云婦有依。',48,'全唐诗/poet.song.224000.json','["亡恙壁岩日，媒云婦有依。", "世科君六世，時事彼一時。", "寂寞吾州隔，諸孤我妹慈。", "九京逢桂老，東坦愧羲之。"]'),
('35ba5b59-e4d1-4039-a483-641e442fe7a8','燈火','許月卿','宋','宋诗','song-poetry','','[]','燈火掩柴門，疎蕪烟水昏。',48,'全唐诗/poet.song.224000.json','["燈火掩柴門，疎蕪烟水昏。", "鷄啼孤月曉，犬吠隔山村。", "桃葉翻新曲，梅花返舊魂。", "凄其何處笛，一笑卧空樽。"]'),
('77952a2e-1c75-42e6-b8a1-e33af8960114','月色','許月卿','宋','宋诗','song-poetry','','[]','明月亦清哉，清風絕點埃。',48,'全唐诗/poet.song.224000.json','["明月亦清哉，清風絕點埃。", "村童催睡去，野叟問禪來。", "樂事賞心夜，清風明月梅。", "夜深羣籟靜，猿鶴莫相猜。"]'),
('e449f82e-993f-406a-b2ee-ee006e28c540','帝學','許月卿','宋','宋诗','song-poetry','','[]','帝學須君入，天游輸我豪。',48,'全唐诗/poet.song.224000.json','["帝學須君入，天游輸我豪。", "君方註老子，我自讀離騷。", "湖上春風好，山中夜月高。", "山高君寄內，湖海我陶陶。"]'),
('e89cb3da-76d1-4241-a5de-3c2ad3960a77','次韻蜀人李施州芾端午  其一','許月卿','宋','宋诗','song-poetry','','[]','幾日愁無雨，夢回聞雨聲。',48,'全唐诗/poet.song.224000.json','["幾日愁無雨，夢回聞雨聲。", "恰逢端午至，不覺和詩成。", "慘淡疑天淚，滂沱吊屈生。", "邦人云此日，陰感助陰兵。"]'),
('c9a5e05a-98fa-413c-af2f-634247f120c6','次韻蜀人李施州芾端午  其二','許月卿','宋','宋诗','song-poetry','','[]','對時思故國，客裏厭南音。',48,'全唐诗/poet.song.224000.json','["對時思故國，客裏厭南音。", "同谷凄凉惡，三閭感慨心。", "賜衣聊杜句，要艾孰騷吟。", "莫說成都景，岷峨秋滿襟。"]'),
('2ac10cba-554c-4e8d-a8ec-2bd22c60a2f6','送撫倅林評事歸班','許月卿','宋','宋诗','song-poetry','','[]','分月年將滿，朝天早戒嚴。',48,'全唐诗/poet.song.224000.json','["分月年將滿，朝天早戒嚴。", "芝函新紫詔，棘寺舊青氈。", "梅雨商岩讖，槐花宰路占。", "應留待漏院，揮翰屬名賢。"]'),
('1aace6ab-fff4-47f4-aa53-c00699d68a51','天貺','許月卿','宋','宋诗','song-poetry','','[]','天貺逢佳節，地靈鍾異人。',48,'全唐诗/poet.song.224000.json','["天貺逢佳節，地靈鍾異人。", "今朝書上考，同日是生辰。", "部使星留次，臨川月半輪。", "明年當此日，五馬列朝紳。"]'),
('4bfeaa8b-23af-4ebb-9019-1b70f18a0090','飯了','許月卿','宋','宋诗','song-poetry','','[]','飯了庵中坐，高情等寂喧。',48,'全唐诗/poet.song.224000.json','["飯了庵中坐，高情等寂喧。", "井泉春戶口，篆火午香烟。", "句好堪呈佛，心空不問禪。", "一聲天外鴈，秋意滿徽絃。"]'),
('27cc6c61-8ba3-4d76-852e-4c58f6e6c618','大行皇帝挽詞五首  其一','許月卿','宋','宋诗','song-poetry','','[]','創始昌陵漢，中興高廟堯。',48,'全唐诗/poet.song.224000.json','["創始昌陵漢，中興高廟堯。", "登遐皆十月，揚烈擅三朝。", "再造煌煌業，參侔浩浩霄。", "中興兼創始，二帝侑逍遥。"]'),
('6e738959-3248-4d8a-9269-4afb70c0dbda','大行皇帝挽詞五首  其二','許月卿','宋','宋诗','song-poetry','','[]','享國昭陵似，龍飛四十春。',48,'全唐诗/poet.song.224000.json','["享國昭陵似，龍飛四十春。", "哀榮皆甲子，創守又庚申。", "刑措成康治，風移堯舜仁。", "瑶編再仁祖，萬葉道如新。"]'),
('f70daa68-1e1f-4064-8d85-982dc6cd2e65','大行皇帝挽詞五首  其三','許月卿','宋','宋诗','song-poetry','','[]','紫陽儒者侶，恨不與同時。',48,'全唐诗/poet.song.224000.json','["紫陽儒者侶，恨不與同時。", "指示四書要，躬親百世師。", "欽崇道兢業，懷保誥寬慈。", "玉殿凄凉處，瑶題尚啟敷。"]'),
('c31b6e92-cb26-4bbc-b71b-782edf175d15','大行皇帝挽詞五首  其四','許月卿','宋','宋诗','song-poetry','','[]','從諫如堯禹，聞言若舜文。',48,'全唐诗/poet.song.224000.json','["從諫如堯禹，聞言若舜文。", "五臣躋□□，三誥斥□君。", "聖度天同廣，忠謀日有聞。", "甲辰親策處，贛論玉顔欣。"]'),
('23106749-0f93-4a07-bd28-731d24615d46','大行皇帝挽詞五首  其五','許月卿','宋','宋诗','song-poetry','','[]','此日營陵處，當年毓聖鄉。',48,'全唐诗/poet.song.224000.json','["此日營陵處，當年毓聖鄉。", "幅員哀踽踽，羽衛道煌煌。", "有彗憂天墜，重輪麗日光。", "謳歌吾君子，千載聖情傷。"]'),
('5e895c21-eccf-4d96-b439-47db5dfd106d','贈快霖','許月卿','宋','宋诗','song-poetry','','[]','有客闖東籬，星翁身姓支。',48,'全唐诗/poet.song.224000.json','["有客闖東籬，星翁身姓支。", "快霖爲道號，直術不支籬。", "試與談災福，斷然無詭隨。", "小溪天下士，持此往參之。"]'),
('5194d944-2da2-4a92-b3ea-671d3a017743','神靜','許月卿','宋','宋诗','song-poetry','','[]','神靜何須卜，心閒即是仙。',48,'全唐诗/poet.song.224000.json','["神靜何須卜，心閒即是仙。", "芋煨牛糞火，瓢滴馬鬃泉。", "綠染春風柳，紅勻曉露蓮。", "明朝晴景好，一棹盡平川。"]'),
('3f3173a0-fd17-41c5-ae97-943c33637ec7','寄陳宰','許月卿','宋','宋诗','song-poetry','','[]','上國春多雨，西江蓮自香。',48,'全唐诗/poet.song.224000.json','["上國春多雨，西江蓮自香。", "恐人疑少室，惟我薄淮陽。", "南北東西命，君臣父子常。", "到官理詞訟，月色更風光。"]'),
('4b6804d3-d547-4d0f-8b25-b2c8d183508f','次韻李制幹贈行','許月卿','宋','宋诗','song-poetry','','[]','科舉有衣鉢，臨行問細君。',48,'全唐诗/poet.song.224000.json','["科舉有衣鉢，臨行問細君。", "梅花入征夢，楊葉礪功勳。", "儼對丹墀日，捷排閶闔雲。", "政須及邊事，毋惜齒牙論。"]'),
('667235e9-f2eb-4413-bbe4-3cbb27440de8','山川','許月卿','宋','宋诗','song-poetry','','[]','山川長不老，人意欲如何。',48,'全唐诗/poet.song.224000.json','["山川長不老，人意欲如何。", "霜後蒹葭健，秋來洲渚多。", "河汾周舊典，洙泗魯餘波。", "悽愴從陳蔡，令人涕滂沱。"]'),
('cd0659af-a6be-4b11-a9d5-2bf0e45363cf','天道','許月卿','宋','宋诗','song-poetry','','[]','天道尊高父道同，地親如母祀先農。',64,'全唐诗/poet.song.224000.json','["天道尊高父道同，地親如母祀先農。", "社翁不肯飲殘水，野老猶能存古風。", "簫鼓村田聊擊壤，雞豚社酒好治聾。", "滿庭芳曲還堪唱，一笑東坡鬢已翁。"]'),
('e1537e9e-fe47-4cce-a82a-f97e917dbf10','木犀','許月卿','宋','宋诗','song-poetry','','[]','桂犀明辨不雷同，長憶先師品藻公。',64,'全唐诗/poet.song.224000.json','["桂犀明辨不雷同，長憶先師品藻公。", "風到如開香積國，月明疑在廣寒宮。", "含香結佩風宜月，纍印懷香月稱風。", "酒裏典刑幸猶在，先師醖藉孔林叢。"]'),
('40a86f6c-ca00-48b6-b277-30a2c892f74e','次韻晉三姪招予及同年飲','許月卿','宋','宋诗','song-poetry','','[]','戀闕重陽不入都，菊英雖好不干渠。',64,'全唐诗/poet.song.224000.json','["戀闕重陽不入都，菊英雖好不干渠。", "樽前丞相方行酒，花外堯夫恰小車。", "羯末封胡延客醉，雷陳張范預期酤。", "他年三徑羊裘隠，君子應能范蠡圖。"]'),
('5195a82b-b67b-4d4f-b3d2-5dafdcde07f2','次韻雲岩','許月卿','宋','宋诗','song-poetry','','[]','權輿於我屋渠渠，久敬如君世莫如。',64,'全唐诗/poet.song.224000.json','["權輿於我屋渠渠，久敬如君世莫如。", "明月清風詩滿案，好天良夜酒連車。", "樽前遠韻輕盈菊，醉後分題爛慢書。", "凡此坐中人十九，鉤樞玉带客金魚。"]'),
('2967bf7c-77dd-4a3c-95b9-2e2f28058bf8','南堂','許月卿','宋','宋诗','song-poetry','','[]','南堂有客䅤秋旻，面面軒窗納曉雲。',64,'全唐诗/poet.song.224000.json','["南堂有客䅤秋旻，面面軒窗納曉雲。", "雲入書檠無俗氣，月來吟几有清芬。", "豈無綠竹詩淇澳，亦有蒼苔書篆文。", "閣上桂枝宜努力，難兄難弟總由人。"]'),
('90c00cbe-7ca9-40b8-9f2b-3efb15313037','使華','許月卿','宋','宋诗','song-poetry','','[]','使華館伴日宣勞，風雨連床夜作逃。',64,'全唐诗/poet.song.224000.json','["使華館伴日宣勞，風雨連床夜作逃。", "愛惜太癡如拱璧，棄遺勝讀若秋毫。", "雙清幽沼芳泉活，一碧長空皓月高。", "坐看睡魔三舍辟，金爐獸炭古離騷。"]'),
('b1234e35-79b6-405f-abbd-87c97b8a162a','允杰姪以詩來卒章和予生孫次韻一百首今存四  其一','許月卿','宋','宋诗','song-poetry','','[]','陳陳史傳勘玄幽，一笑誰能問慎由。',64,'全唐诗/poet.song.224000.json','["陳陳史傳勘玄幽，一笑誰能問慎由。", "往往東南旗運盛，亭亭西北蓋雲浮。", "瓊樓玉宇無身翼，弱水蓬萊有艾舟。", "聖主攘夷修政事，可能吊伐至枋頭。"]'),
('b5f0f949-ab1a-4ea1-8eb3-2fe48f8e42ba','允杰姪以詩來卒章和予生孫次韻一百首今存四  其二','許月卿','宋','宋诗','song-poetry','','[]','玉川破屋抱遺經，生子添丁意命名。',64,'全唐诗/poet.song.224000.json','["玉川破屋抱遺經，生子添丁意命名。", "門暗碧雲憂國志，窗明紅日愛君情。", "柳綠學徒勤左塾，花紅主婦饌前榮。", "他年誰註徵君傳，好把吟篇著眼評。"]'),
('ff091eff-ee80-4e62-aa3f-d7fba58886d6','允杰姪以詩來卒章和予生孫次韻一百首今存四  其三','許月卿','宋','宋诗','song-poetry','','[]','山已幽幽墅更幽，幽居別墅儘居由。',64,'全唐诗/poet.song.224000.json','["山已幽幽墅更幽，幽居別墅儘居由。", "數間屋想今岑寂，萬斛船忻正拍浮。", "採藥幽居憐閉戶，圍棋別墅夢歸舟。", "明朝菊徑歸來處，二阮黄花插滿頭。"]'),
('ee7702f9-bfc6-4cfa-be5e-22d61deb8db7','允杰姪以詩來卒章和予生孫次韻一百首今存四  其四','許月卿','宋','宋诗','song-poetry','','[]','孫枝遥喜道韋經，老手摩頭咳唾名。',64,'全唐诗/poet.song.224000.json','["孫枝遥喜道韋經，老手摩頭咳唾名。", "豚犬吾兒夷□姪，虎龍孫祖退之情。", "洗兒湯餠吾方拙，教子鹽梅汝更榮。", "許氏一門忠孝盛，夔臯熊虎□延評。"]'),
('46014bd0-281e-49ae-9037-f8f100ac34de','用韻簡如晦','許月卿','宋','宋诗','song-poetry','','[]','龍溪毓秀自平陽，千載詩葩分外香。',64,'全唐诗/poet.song.224000.json','["龍溪毓秀自平陽，千載詩葩分外香。", "錦里篤生天下士，玉堂曾看甲科郎。", "龍溪季子代無乏，鶚薦明年定破荒。", "桂樹黄堂秋色裏，何妨演習鹿鳴章。"]'),
('0f251d4b-07f2-4838-89d9-47cce9627ff7','用韻自述','許月卿','宋','宋诗','song-poetry','','[]','菊花開處即重陽，月桂中秋夜夜香。',64,'全唐诗/poet.song.224000.json','["菊花開處即重陽，月桂中秋夜夜香。", "紫綬象環如魯叟，綸巾羽扇亦周郎。", "不憂鴻鴈稻粱少，但恐鶴猿松菊荒。", "宰相山中書幾考，清風明月老平章。"]'),
('7f0b2003-abab-46dd-bf2f-c3d0e87e97b7','八角','許月卿','宋','宋诗','song-poetry','','[]','八角亭中天似水，七言城裏夜未央。',64,'全唐诗/poet.song.224000.json','["八角亭中天似水，七言城裏夜未央。", "主人解榻賢材館，門客避堂上下床。", "籟寂寂時星歷歷，泉涓涓處山蒼蒼。", "主人門客皆觴詠，羽扇綸巾獨篆香。"]'),
('42ebd34d-6875-4abd-a02c-928cc387f379','歸塗','許月卿','宋','宋诗','song-poetry','','[]','望外雲頭日高掛，竹間亭子雪猶存。',64,'全唐诗/poet.song.224000.json','["望外雲頭日高掛，竹間亭子雪猶存。", "啣蘆鴈起瀟湘暮，賣炭人行烟火村。", "綺疎月照窗如晝，寶鼎香銷帳似雲。", "欲轉冰壺渾未暇，党家習氣彼羶葷。"]'),
('8aeb1513-5dec-4b66-81f8-316221007210','次韻程愿二首  其一','許月卿','宋','宋诗','song-poetry','','[]','我家張許同生歲，果者堯時值聖明。',64,'全唐诗/poet.song.224000.json','["我家張許同生歲，果者堯時值聖明。", "丙子與君無貴者，甲辰惟我亦同庚。", "閑雲萬嶺林泉興，明月一溪邱壑情。", "同歲同心有如此，相期歲晚李歌行。"]'),
('8b949a47-f232-46cc-9fee-e3bd9143a159','次韻程愿二首  其二','許月卿','宋','宋诗','song-poetry','','[]','二李歌行醉裏歌，君溪兩棹我烟簑。',64,'全唐诗/poet.song.224000.json','["二李歌行醉裏歌，君溪兩棹我烟簑。", "鳳凰臺上我山墅，虹馬軒高君月坡。", "曉徑焰間追李杜，夜窗灰裏撥陰何。", "長哦歲晚成二老，詩社往來君肯麽。"]'),
('801f9aa3-45eb-4974-ab3a-b989d9769cc2','寄顧次岳五首  其一','許月卿','宋','宋诗','song-poetry','','[]','柳塘醉我無邊酒，得隴癡生望蜀心。',64,'全唐诗/poet.song.224000.json','["柳塘醉我無邊酒，得隴癡生望蜀心。", "亦有白衣雙白玉，不孤黄菊萬黄金。", "寶婺古來金綉水，銀蟾後夜玉青岑。", "韋齋井畔通宵月，應照空樽印渴襟。"]'),
('69e46e4c-05bd-438f-b1d7-5e360e49aa3a','寄顧次岳五首  其二','許月卿','宋','宋诗','song-poetry','','[]','韋齋井畔通宵月，流出文公闕里心。',64,'全唐诗/poet.song.224000.json','["韋齋井畔通宵月，流出文公闕里心。", "半夜起來湖瑩玉，明朝應有柳摇金。", "萬壑正看天地肅，一樓坐斷水雲岑。", "鏡湖樓扁知無恙，二十年前醉解襟。"]'),
('ea8df731-a186-4e9f-85eb-0d37e7a867a4','寄顧次岳五首  其三','許月卿','宋','宋诗','song-poetry','','[]','鏡湖扁字無今古，無古無今只此心。',64,'全唐诗/poet.song.224000.json','["鏡湖扁字無今古，無古無今只此心。", "雲入枕邊堂署玉，月窮天外日鎔金。", "樓臺髣髴水墨畫，烟霧空濛岩壑岑。", "須信尚書最難讀，人間無許大胸襟。"]'),
('9ff2fa8b-b619-4d69-96d2-3c1bdcb08b81','寄顧次岳五首  其四','許月卿','宋','宋诗','song-poetry','','[]','運千可際休明運，心一堪傳賢聖心。',64,'全唐诗/poet.song.224000.json','["運千可際休明運，心一堪傳賢聖心。", "不一此心非自玉，半千之運或如金。", "道源天出三清境，遠目明雙寸碧岑。", "胸次須令天樣闊，五湖爲带三江襟。"]'),
('2592e310-d721-4a50-a041-d9fd7072cfe1','寄顧次岳五首  其五','許月卿','宋','宋诗','song-poetry','','[]','半夜開窗凭闌坐，無心雲起鏡湖心。',64,'全唐诗/poet.song.224000.json','["半夜開窗凭闌坐，無心雲起鏡湖心。", "鋪茵煙草漫天幄，璞玉樓臺渾色金。", "訪古寂寥秋漠漠，懷人感慨碧岑岑。", "未知何日韋齋井，明月清風煩暑襟。"]'),
('c2b5b9cb-265b-4cb0-ab70-11c3b7344c6b','鹿鳴用趙資相韻','許月卿','宋','宋诗','song-poetry','','[]','宗主人才郭子儀，門多將相蔚相輝。',64,'全唐诗/poet.song.224000.json','["宗主人才郭子儀，門多將相蔚相輝。", "托根小草秋榆宦，食葉長廊春棘闈。", "報國自憐心事壯，憂時不覺夢魂飛。", "平生此志非溫飽，勳業從公問指歸。"]'),
('a39abbda-c4ac-4b47-84b1-d175e14196b3','入邑問炊中雲招王希聖起龍三首  其一','許月卿','宋','宋诗','song-poetry','','[]','希聖平生詩酒豪，居然閉戶學孤高。',64,'全唐诗/poet.song.224000.json','["希聖平生詩酒豪，居然閉戶學孤高。", "不知昨夜秋風柳，得似當時春日桃。", "別去半年猶旦暮，胸中百癢欠爬搔。", "虎溪破戒君須解，已辦清詩與濁醪。"]'),
('fbada1ab-9dea-4ed6-86ac-08e40bb0bfbb','入邑問炊中雲招王希聖起龍三首  其二','許月卿','宋','宋诗','song-poetry','','[]','移文招子氣添豪，畢竟牢關計未高。',64,'全唐诗/poet.song.224000.json','["移文招子氣添豪，畢竟牢關計未高。", "留得商霖活秋稼，未應禹浪怨春桃。", "半窗明月詩誰和，一劍空燈手自搔。", "來此共君思昨夢，秋風江上幾投醪。"]'),
('a7777edd-6de3-40db-890a-bcad773e80c0','入邑問炊中雲招王希聖起龍三首  其三','許月卿','宋','宋诗','song-poetry','','[]','簞瓢不改乃真豪，之子胸中志自高。',64,'全唐诗/poet.song.224000.json','["簞瓢不改乃真豪，之子胸中志自高。", "本自無官彭澤柳，不知何世武陵桃。", "窗前草色勤鑽仰，堂上萱叢敬抑搔。", "好向中庸看未發，養成和氣盎春醪。"]'),
('fff9b97b-08ff-4bfd-9dab-22b9687dc0d9','遇黄先生','許月卿','宋','宋诗','song-poetry','','[]','策馬沙頭值此翁，恐成鴻燕嗇相逢。',64,'全唐诗/poet.song.224000.json','["策馬沙頭值此翁，恐成鴻燕嗇相逢。", "歸鞭亟指遠峰碧，握手頻看笑臉紅。", "淡月一簾清坐處，高風千載慨歌中。", "淵源自昔崇師友，吳下應憐舊阿蒙。"]'),
('dd451af6-3b09-4802-b597-85e8325430c4','和趙資相','許月卿','宋','宋诗','song-poetry','','[]','手托東南半壁天，向天捧詔下搜賢。',64,'全唐诗/poet.song.224000.json','["手托東南半壁天，向天捧詔下搜賢。", "塵沙騎鶴征鴻倦，衢道乘鸞病驥先。", "玉陛九重將玉立，珠簾十里看珠聯。", "狀元宰相平生事，雅意中原願執鞭。"]'),
('c35b1d05-9ba7-4f2b-974e-1196836a68f3','追賦暮游','許月卿','宋','宋诗','song-poetry','','[]','錫山舟泊似荒村，微服南禪古跡存。',64,'全唐诗/poet.song.224000.json','["錫山舟泊似荒村，微服南禪古跡存。", "壁上姓名今已遠，碑陰人物了能言。", "薄游草草山侵袖，遠思悠悠風滿軒。", "携手出門烟樹密，數僧離立語黄昏。"]'),
('97202817-00f8-48c1-b658-980c6debac36','次韻葉司戶','許月卿','宋','宋诗','song-poetry','','[]','舟自摇摇釣瀨濱，睦州司戶得詩人。',64,'全唐诗/poet.song.224000.json','["舟自摇摇釣瀨濱，睦州司戶得詩人。", "對床夜雨如蘇子，滿座春風似伯淳。", "文武略窺瑶殿射，婺衢爭耀錦鄉春。", "金華葉相垂青史，青出於藍局局新。"]'),
('adff86d7-a4ff-406c-a6fc-9eb1014c60b9','次韻黄玉如大章携先集來訪二首  其一','許月卿','宋','宋诗','song-poetry','','[]','夜宿槎溪碧草幽，草窗招隠勸巢由。',64,'全唐诗/poet.song.224000.json','["夜宿槎溪碧草幽，草窗招隠勸巢由。", "朝來忽得新詩好，客裏俄驚喜氣浮。", "秋老空山唳清鶴，天寒野水卧孤舟。", "細吟天下黄香句，曉霧輕烟古渡頭。"]'),
('69499720-9cfb-43a4-b6eb-0524feaca637','次韻黄玉如大章携先集來訪二首  其二','許月卿','宋','宋诗','song-poetry','','[]','橋梓風流滿腹經，桂花香裏識魁名。',64,'全唐诗/poet.song.224000.json','["橋梓風流滿腹經，桂花香裏識魁名。", "翻成宵夢古今事，何况人間父子情。", "先集一編詩橐富，家傳萬卷子金榮。", "挂名敘跋流芳遠，曉起吟窗仔細評。"]'),
('a7794223-f8fc-4b89-8f8c-2c299ba7259a','再和題黄免耕吟藁  其一','許月卿','宋','宋诗','song-poetry','','[]','免耕遺藁九京幽，宿諾吾方負仲由。',64,'全唐诗/poet.song.224000.json','["免耕遺藁九京幽，宿諾吾方負仲由。", "宿諾斜陽悲宿草，沉思一旦落沉浮。", "池生春草虛堂夢，楓落吳江何處舟。", "有子九京如不死，一輪明月墓山頭。"]'),
('0b71182c-d171-41e5-9479-71a37ad7f2ca','再和題黄免耕吟藁  其二','許月卿','宋','宋诗','song-poetry','','[]','優游一辟難贊經，仲舒師友盡時名。',64,'全唐诗/poet.song.224000.json','["優游一辟難贊經，仲舒師友盡時名。", "已登鄉國一經薦，未究天人三策情。", "文定浚源雖瑩徹，牧堂奕葉必敷榮。", "紫陽風水深留意，磨石佳城後世評。"]'),
('f41f2db4-0954-4e5c-b22d-179a0b5248f5','代仍六弟吊程貢元','許月卿','宋','宋诗','song-poetry','','[]','少從諸父與君游，到眼銘章淚莫收。',64,'全唐诗/poet.song.224000.json','["少從諸父與君游，到眼銘章淚莫收。", "水闊騎鯨霜葉落，波寒躍鯉雪蘋秋。", "當時折桂浮雲夢，今日叢萱暮靄愁。", "惆悵人洪暗煙月，淡凝碑字濕松楸。"]'),
('ea1affc8-54e5-4cae-9091-6e63c9d2869b','寄題岩經樓','許月卿','宋','宋诗','song-poetry','','[]','樓中圖史澹爐墨，中有成都較藝文。',64,'全唐诗/poet.song.224000.json','["樓中圖史澹爐墨，中有成都較藝文。", "手澤存焉生舊感，心傳妙處長新聞。", "世科事業無如子，經學源流可致君。", "祇恐校讎天祿閣，猿啼樓外滿溪雲。"]'),
('6b9b1ac6-0fa0-475e-a1ee-a733df6c3cd5','次韻仲成叔賀雙桂橋','許月卿','宋','宋诗','song-poetry','','[]','展墓歸來春水浮，橋頭望月正如鈎。',64,'全唐诗/poet.song.224000.json','["展墓歸來春水浮，橋頭望月正如鈎。", "橋成未用問誰住，意遠應同逐水流。", "天外鴈鳧何足許，人間鹿豕可仝游。", "須知□□□□□，莫說存耕知有秋。"]'),
('1c9eca0c-ad67-41f2-b0dc-58b8b4916921','滿城風雨近重陽','許月卿','宋','宋诗','song-poetry','','[]','滿城風雨近重陽，一舸烟波入醉鄉。',64,'全唐诗/poet.song.224000.json','["滿城風雨近重陽，一舸烟波入醉鄉。", "心事已同鷗鳥白，眼界空有雲山蒼。", "酒安能管興亡事，菊亦頗復時世粧。", "何似長歌明月裏，月明天闊地更長。"]'),
('8c7f3f98-d0c5-46ea-887b-c413e91abb46','挽座主吳倅','許月卿','宋','宋诗','song-poetry','','[]','菊翁去後菊園荒，壽不如花儘自香。',64,'全唐诗/poet.song.224000.json','["菊翁去後菊園荒，壽不如花儘自香。", "進學解成誰貝錦，題輿字濕已黄粱。", "衆流出壑三秋暮，明月照松千仞岡。", "冷落僧爐數間屋，但留名節付賢郎。"]'),
('118e7426-8bad-4a46-a888-8d7d8ae01a1b','登慈恩絕頂有感','許月卿','宋','宋诗','song-poetry','','[]','爲學平生不究源，未妨絕頂上慈恩。',64,'全唐诗/poet.song.224000.json','["爲學平生不究源，未妨絕頂上慈恩。", "塔高俯視群山小，江闊能容巨浪喧。", "人每中登難脚力，誰於高處領天根。", "須信平生爲基址，基址牢時德業尊。"]'),
('829e5bc3-4fa8-4c5f-a442-ccd4dd37ab33','挽陳節使','許月卿','宋','宋诗','song-poetry','','[]','凜凜如公一寸丹，荒城夜月徹清寒。',64,'全唐诗/poet.song.224000.json','["凜凜如公一寸丹，荒城夜月徹清寒。", "向時尚已死諸葛，今日難貪老阿瞞。", "素志平生兆馬革，黎民一郡博彈冠。", "隻雞斗酒群群讖，吾力猶能滅賀蘭。"]'),
('18fc6e60-e2cb-4bf8-a1ce-e5935f95415b','挽李左藏','許月卿','宋','宋诗','song-poetry','','[]','少年謂子氣橫秋，壯已邊城汗漫游。',64,'全唐诗/poet.song.224000.json','["少年謂子氣橫秋，壯已邊城汗漫游。", "筮仕弗如歸亦好，讀書未了死方休。", "半生懶意琴三疊，千古詩情土一邱。", "月落錫林烟露冷，松風無籟自颼颼。"]'),
('0af7c9fd-51ed-48e9-ac4d-53c2e5c2ab1a','挽清湘令董介軒','許月卿','宋','宋诗','song-poetry','','[]','偏得人間謗與名，蓋棺方定伯夷清。',64,'全唐诗/poet.song.224000.json','["偏得人間謗與名，蓋棺方定伯夷清。", "五經笥滿風雲壯，百尺樓高星斗橫。", "明月照庭香不斷，狂飈吹雪意如生。", "河汾回首成今古，禮樂猶將致太平。"]'),
('e4a4e664-cf69-4e91-8d2a-ff984ead44ab','挽馬樞密母段氏','許月卿','宋','宋诗','song-poetry','','[]','松岡新植瀧豐碑，千古哀榮誰似之。',64,'全唐诗/poet.song.224000.json','["松岡新植瀧豐碑，千古哀榮誰似之。", "訓子斷機霜雪冷，退朝猶績月星垂。", "綠衣西府梅花落，素幄北堂萱草萎。", "何惜沙堤明日路，潘輿無復再來時。"]'),
('f14a010a-9d44-49ed-8e3f-0debdec64deb','次韻朱塘三首  其一','許月卿','宋','宋诗','song-poetry','','[]','杏壇黄葉滿霜林，何幸朱塘兀古枌。',64,'全唐诗/poet.song.224000.json','["杏壇黄葉滿霜林，何幸朱塘兀古枌。", "試上月臺因問月，知涵雲谷幾多雲。", "夢游當日成何事，嗜學于今喜舊聞。", "我意昨游春水滿，重來秋意見涯垠。"]'),
('ace22924-c08b-498e-8ee2-f336b70c88f9','次韻朱塘三首  其二','許月卿','宋','宋诗','song-poetry','','[]','游子從來悲故鄉，歸來襟袖芷蘭芳。',64,'全唐诗/poet.song.224000.json','["游子從來悲故鄉，歸來襟袖芷蘭芳。", "夢魂飛去雲濤遠，杖策閑行秋水光。", "可是夢中曾到此，安知身後却餘香。", "紫陽弟子有賢子，卜築新亭真肯堂。"]'),
('35f6e0e9-f766-49e0-a0e3-446877ab16dc','次韻朱塘三首  其三','許月卿','宋','宋诗','song-poetry','','[]','謾着新亭俯碧漪，高低草樹任差池。',64,'全唐诗/poet.song.224000.json','["謾着新亭俯碧漪，高低草樹任差池。", "須知亭扁須時彥，不是谿齋不勇爲。", "水靜山深悉天趣，風光月霽足吾師。", "未妨賦誦銘顔樂，正學於戲無已時。"]'),
('6352ad74-e035-414c-9fe3-bdf7297de9de','與陳宰','許月卿','宋','宋诗','song-poetry','','[]','到處逢人說大蘇，一門兄弟古今無。',64,'全唐诗/poet.song.224000.json','["到處逢人說大蘇，一門兄弟古今無。", "吹塤林五黟山馬，鼓瑟陳雙婺水鳬。", "定分有殊自鵬鷃，閑情無限儘龍豬。", "歸來坐倚蓬窗下，少挹春風過里閭。"]'),
('c6204dbf-780c-4616-94c9-7bc471e3b07b','迎謁劉朔齋□提舉行部','許月卿','宋','宋诗','song-poetry','','[]','百城奔走候車塵，庾節光華婺水濱。',64,'全唐诗/poet.song.224000.json','["百城奔走候車塵，庾節光華婺水濱。", "人望朔齋春有脚，家傳元祐水無心。", "天低日近霜華曉，地僻臘殘梅蕊春。", "願得劉家再忠肅，前爲伊鼎後商霖。"]'),
('a9e8c485-d72f-4909-87b5-e0cc1ae2cbc0','贈黄藻二章  其一','許月卿','宋','宋诗','song-poetry','','[]','參軍一夢到詞場，難弟想應瞻聖皇。',64,'全唐诗/poet.song.224000.json','["參軍一夢到詞場，難弟想應瞻聖皇。", "此去捷音來鼎鼎，向來諸老去堂堂。", "馬頭雪絮天街玉，人跡板橋茅店霜。", "君去世科傳伯氏，釣舟留我住嚴光。"]'),
('26dce3b3-f262-4a13-b60d-c087b60701f0','贈黄藻二章  其二','許月卿','宋','宋诗','song-poetry','','[]','星邑唐詩韻一天，參軍生死別經年。',64,'全唐诗/poet.song.224000.json','["星邑唐詩韻一天，參軍生死別經年。", "君來佳句賓朋誦，我願世科昆弟傳。", "別語明晨繞朝策，秋風來歲祖生鞭。", "難兄難弟誇京邑，莫負當年夢惠連。"]'),
('4c52eb07-9a2f-409e-8c1f-efd936d12f8c','贈程惠子','許月卿','宋','宋诗','song-poetry','','[]','我朝詩道愧唐人，魏晉風流更勿論。',64,'全唐诗/poet.song.224000.json','["我朝詩道愧唐人，魏晉風流更勿論。", "莊子于今逢惠子，孔門自昔契程門。", "君宜鶑出雲霄路，我亦猿吟烟水村。", "趁取山人來離谷，梅花湖上返詩魂。"]'),
('bc43ebe1-a83b-4894-8d6c-d2ca236b599d','辭賈徽州二首  其一','許月卿','宋','宋诗','song-poetry','','[]','束書歸去饗梅花，底事霏英故故斜。',64,'全唐诗/poet.song.224000.json','["束書歸去饗梅花，底事霏英故故斜。", "約住忙中千里鶴，羨渠如意兩歸鴉。", "家中見雪念爲客，客裏觀梅不似家。", "園樹暫時相鬭白，明朝休向我儂誇。"]'),
('e8e65049-dfdc-45e2-9ba8-f23a98bb8909','辭賈徽州二首  其二','許月卿','宋','宋诗','song-poetry','','[]','岫雲休怪此行徐，出處家風本俗如。',64,'全唐诗/poet.song.224000.json','["岫雲休怪此行徐，出處家風本俗如。", "當任宣尼無俟駕，肯辭孟子範馳驅。", "如金歲月人奔競，似玉行藏我卷舒。", "極目冥鴻揮綠綺，忘情魚鳥盡江湖。"]'),
('218e9d94-6493-4a1d-83da-781145933d93','三月','許月卿','宋','宋诗','song-poetry','','[]','三月春如少年時，了知造化最兒嬉。',64,'全唐诗/poet.song.224000.json','["三月春如少年時，了知造化最兒嬉。", "智行無事柳飛絮，道法自然花滿枝。", "錦綉園林天富貴，神仙院落月清奇。", "老天長似春三月，游嬉人間不皺眉。"]'),
('d4aaddea-43c0-47f4-a6ee-eb46d5b99b8c','題趙尉洞源泉','許月卿','宋','宋诗','song-poetry','','[]','歸去來詞書印曆，高風千載汝南評。',64,'全唐诗/poet.song.224000.json','["歸去來詞書印曆，高風千載汝南評。", "松間風影有地籟，林下炎天無水聲。", "行客詩魂同石瘦，主人心事共泉清。", "明朝遮日長安去，君亦曹裝趣上京。"]'),
('c77befe7-98ac-4724-bb7e-137643004326','贈墨士程雲翁','許月卿','宋','宋诗','song-poetry','','[]','滿地干戈正擾攘，君家猶自搗龍香。',64,'全唐诗/poet.song.224000.json','["滿地干戈正擾攘，君家猶自搗龍香。", "輕清披就烟雲質，堅勁磨來金玉相。", "倚馬喜資揮露布，飛鸞端藉發天章。", "山屋莫道渾無用，留寫樵歌入錦囊。"]'),
('e287baa5-abfe-40f2-96f1-2eccdaab771d','春日閑賦','許月卿','宋','宋诗','song-poetry','','[]','數行竹樹鳴春雨，一簇人家带曉烟。',64,'全唐诗/poet.song.224000.json','["數行竹樹鳴春雨，一簇人家带曉烟。", "省事山丹自籬落，親人海燕並庭簷。", "樓高思遠天無極，酒罷歌闌月正圓。", "新茗一甌香一篆，與君清坐看風簾。"]'),
('b0456d3f-2f8a-4f03-966e-10cc35c1a8a9','題汪端翁廟','許月卿','宋','宋诗','song-poetry','','[]','端公碑石蔓蘿捫，嘆息雙杉拔本根。',64,'全唐诗/poet.song.224000.json','["端公碑石蔓蘿捫，嘆息雙杉拔本根。", "將略傳家自忠顯，侍兒梟首亦平原。", "乘風飛去乾坤窄，踏月歸來烟水昏。", "往事不堪重回首，青燈黄卷照芳樽。"]'),
('7f7481c5-9a07-48e0-995b-b36bbdd72a4b','寄題張宗玉窗下廬山','許月卿','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山移到龍溪東，兩壁生雲無數峰。',64,'全唐诗/poet.song.224000.json','["廬山移到龍溪東，兩壁生雲無數峰。", "夢與文淵三峽水，共參金露九秋風。", "萬山恍對凝塵榻，五老仝携入室筇。", "更問濂溪風共月，又移窗下到腦中。"]'),
('1a3207bf-f005-4cbc-ae89-39599ce5fda1','賦新花竹','許月卿','宋','宋诗','song-poetry','','[]','花紅竹綠兩相當，綠竹紅花在道傍。',64,'全唐诗/poet.song.224000.json','["花紅竹綠兩相當，綠竹紅花在道傍。", "竹引花風心浪動，花含竹露面芬芳。", "須知竹戀花蝴蝶，喜見花貪竹鳳凰。", "彼此莫嫌花共竹，他年花老竹蒼蒼。"]'),
('4138790b-5647-4874-9b74-d973236296ab','贈王竹窗','許月卿','宋','宋诗','song-poetry','','[]','若欲相尋向竹邊，開窗着屐更誰先。',64,'全唐诗/poet.song.224000.json','["若欲相尋向竹邊，開窗着屐更誰先。", "定有一輪穿密密，可無數點洗涓涓。", "茂林從昔於儂好，太極遥憐似我圓。", "釣竿莫惜分新綠，更割半窗瀟灑天。"]'),
('e97f6ac5-5f44-433a-bbab-f1792206d69f','中秋謝施婺源爰','許月卿','宋','宋诗','song-poetry','','[]','高情古意滿溪樓，靜拍欄干儘兩眸。',64,'全唐诗/poet.song.224000.json','["高情古意滿溪樓，靜拍欄干儘兩眸。", "月不露圭天有道，風能□谷水無愁。", "從吾所好萬青壑，捨我其誰雙白鷗。", "別樣主人情重處，不將紅妓涴中秋。"]'),
('09102b4d-e49f-41f1-a488-a4e32522ebb3','和子思弟韻壽母','許月卿','宋','宋诗','song-poetry','','[]','劣相誰知此老天，瑶池專遣雪當筵。',64,'全唐诗/poet.song.224000.json','["劣相誰知此老天，瑶池專遣雪當筵。", "開花敬上夫人壽，列樹無非西子妍。", "松學妙齡施粉點，鶴迷歸路認蓮船。", "水晶世界瓊梅閣，肯道人間不是仙。"]'),
('9b01a13e-2aae-444f-a4a5-5b2093112be0','次韻黄玉如求記','許月卿','宋','宋诗','song-poetry','','[]','先子北山書劍留，山川還自舊相繆。',64,'全唐诗/poet.song.224000.json','["先子北山書劍留，山川還自舊相繆。", "與君去歲銜盃處，遣我長歌陟岵游。", "瘦鶴風輕霜檜舞，歸鴉烟重晚林投。", "中齋孟氏仙官府，同號同庚成佛不。"]'),
('e592213e-fa10-4260-b982-0c498452a57b','川原','許月卿','宋','宋诗','song-poetry','','[]','川原紅紫一時新，暮雨朝雲更可人。',64,'全唐诗/poet.song.224000.json','["川原紅紫一時新，暮雨朝雲更可人。", "燦若中興紅藥相，嫣然何慮海棠嗔。", "天將好景煩吟筆，我自清時作幸民。", "書冊埋頭無了日，不如拋却去尋春。"]'),
('c45e2958-3c67-4744-981b-c33a306de39f','次允杰五首  其一','許月卿','宋','宋诗','song-poetry','','[]','魏公間氣孰能儔，纖若登梯量自優。',64,'全唐诗/poet.song.225000.json','["魏公間氣孰能儔，纖若登梯量自優。", "父母床無烹子刃，相公腹有濟川舟。", "江山之外雲端鶴，天地中間海上鷗。", "學進識明涵受闊，連天遠水月明樓。"]'),
('484507b0-5567-4231-8989-ac1f8c1ca131','次允杰五首  其二','許月卿','宋','宋诗','song-poetry','','[]','斯人非與更誰儔，咸以無心感最優。',64,'全唐诗/poet.song.225000.json','["斯人非與更誰儔，咸以無心感最優。", "上下天光萬頃碧，乾坤中處一虛舟。", "相從相語何妨鶴，纔有機心不下鷗。", "平地人間無限闊，元龍何必卧危樓。"]'),
('c0271cdc-1b34-410f-96af-b7d34cf2dd5d','次允杰五首  其三','許月卿','宋','宋诗','song-poetry','','[]','相鶴先經古罕儔，一詩檃括爾才優。',64,'全唐诗/poet.song.225000.json','["相鶴先經古罕儔，一詩檃括爾才優。", "雲天杳杳仙騏騪，蓬海茫茫我楫舟。", "赴隴光榮空似鳳，乘軒浩蕩不如鷗。", "淵材多事添煩惱，一夜胎仙頻倚樓。"]'),
('74f3d67d-ab18-4c79-b5cd-12b3620c36a5','次允杰五首  其四','許月卿','宋','宋诗','song-poetry','','[]','老鶴吾慚鶑谷儔，揚州草檄類俳優。',64,'全唐诗/poet.song.225000.json','["老鶴吾慚鶑谷儔，揚州草檄類俳優。", "千年橘井雉城字，萬斛桃花鶴料舟。", "爲文待漏書丹鳳，如此有盟寒白鷗。", "歌吹竹西驚昨夢，眼中騎鶴有高樓。"]'),
('def7fc9d-360a-4881-987b-4f8b2da23402','次允杰五首  其五','許月卿','宋','宋诗','song-poetry','','[]','瓣香曾侍鶴山儔，蜀有鶴林殊匪優。',64,'全唐诗/poet.song.225000.json','["瓣香曾侍鶴山儔，蜀有鶴林殊匪優。", "蛻作嬰兒生我室，化爲道士掠予舟。", "相同龜壽□鵬鷃，自混雞群狎鷺鷗。", "仙子已騎黄鶴去，此地空餘黄鶴樓。"]'),
('df2d6505-8a7c-4ed1-9372-17f99196b26c','六月雨十一首  其一','許月卿','宋','宋诗','song-poetry','','[]','麟筆大書六月雨，蟬聲靜掃一天秋。',64,'全唐诗/poet.song.225000.json','["麟筆大書六月雨，蟬聲靜掃一天秋。", "天河倒挽甲兵洗，地寶咸歸秔稻疇。", "雨餘欹枕軒窗月，天際歸帆蘋蓼洲。", "一飽了知天賜履，漉巾洗盞辦新篘。"]'),
('9f63c47e-ffdc-473d-9622-7450096543be','六月雨十一首  其二','許月卿','宋','宋诗','song-poetry','','[]','岫雲已喜能成雨，不卜先知今有秋。',64,'全唐诗/poet.song.225000.json','["岫雲已喜能成雨，不卜先知今有秋。", "作楫作霖三說命，時暘時雨九箕疇。", "數行竹樹清風夜，萬頃烟波明月洲。", "二客從予遊赤壁，歸謀正值酒堪篘。"]'),
('12f9af5d-d472-445c-a2b7-c87602486c0b','六月雨十一首  其三','許月卿','宋','宋诗','song-poetry','','[]','先集流傳妙詩句，芃芃禾黍舞凉秋。',64,'全唐诗/poet.song.225000.json','["先集流傳妙詩句，芃芃禾黍舞凉秋。", "九秋寶麗從天落，一雨賦興矧若疇。", "月更風流寫松竹，雨餘凉意滿汀洲。", "客來且貰鄰壚酒，家釀明朝儘可篘。"]'),
('729b18e4-54cd-4efc-a8ee-ab9a7228638a','六月雨十一首  其四','許月卿','宋','宋诗','song-poetry','','[]','雨餘目極乾坤月，雪外天連䆉稏秋。',64,'全唐诗/poet.song.225000.json','["雨餘目極乾坤月，雪外天連䆉稏秋。", "舜殿風薰殊未玉，堯天雨施自君疇。", "層波渝我蒹葭渚，列宿嗤人杜若洲。", "珍重菊莊來顧我，床頭爲子出春篘。"]'),
('8f36764b-63c8-4897-a605-b3f66a8beb0d','六月雨十一首  其五','許月卿','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','都忘甲子不知老，三十六峰無限秋。',64,'全唐诗/poet.song.225000.json','["都忘甲子不知老，三十六峰無限秋。", "江水清兮鱗百丈，廬山高處稻盈疇。", "堯時丙子壽星數，坡句許家仙島洲。", "自分吾生老耕釣，花瓢趁取日先篘。"]'),
('c105479f-29e2-4060-b4fd-f58d89f48100','六月雨十一首  其六','許月卿','宋','宋诗','song-poetry','','[]','五更殊覺洗空憂，一雨端能接引秋。',64,'全唐诗/poet.song.225000.json','["五更殊覺洗空憂，一雨端能接引秋。", "陋室了知饒鶴料，高田無復拆龜疇。", "蒲葵扇老堪藏篋，楊柳梢存不見洲。", "混混濁流聊濯足，玉泉金井酒宜篘。"]'),
('32308f09-0e21-44e6-b379-c088004a837a','六月雨十一首  其七','許月卿','宋','宋诗','song-poetry','','[]','雙星今夜話綢繆，頗語人間一夜秋。',64,'全唐诗/poet.song.225000.json','["雙星今夜話綢繆，頗語人間一夜秋。", "萬事悠悠何預我，四方蹙蹙屬之疇。", "萬家旁置傷心地，四水宗朝極目洲。", "坐看白雲棲斷處，支郎酒老臘前篘。"]'),
('31fe28fc-8df6-46db-b922-0e63303d1275','六月雨十一首  其八','許月卿','宋','宋诗','song-poetry','','[]','行晴坐雨荷天休，天地中間獨享秋。',64,'全唐诗/poet.song.225000.json','["行晴坐雨荷天休，天地中間獨享秋。", "淡日凉風滿衣屨，甘霖薄暮悅田疇。", "晴天歷歷供峰嶼，烟雨濛濛護島洲。", "蹙蹙四方瞻靡騁，愁心如醉嬾新篘。"]'),
('6f203855-a267-4dbe-ae26-af38e0fd0188','六月雨十一首  其九','許月卿','宋','宋诗','song-poetry','','[]','彭城夜雨悲翁季，手植堂前雙桂秋。',64,'全唐诗/poet.song.225000.json','["彭城夜雨悲翁季，手植堂前雙桂秋。", "竹馬吾何計東閣，巾車何自樂田疇。", "棣華頗失椿萱樹，雁影平沉橘柚洲。", "更憶北山移植處，釣魚竿底玉醪篘。"]'),
('057d7e85-a1ab-40d7-8ff2-7aad981c75e4','六月雨十一首  其一○','許月卿','宋','宋诗','song-poetry','','[]','一月春風洛水幽，凜然惟有壑專秋。',64,'全唐诗/poet.song.225000.json','["一月春風洛水幽，凜然惟有壑專秋。", "十室九空鴻鴈渚，千村萬落杞荆疇。", "烏鳥有情瞻岵屺，黄龍無底羽淵洲。", "思昔朝廷天廣大，何時醢賜伴醪篘。"]'),
('d096d669-0096-4f82-8d0c-5637c65f7f3e','六月雨十一首  其一一','許月卿','宋','宋诗','song-poetry','','[]','今歲無時不禦寇，每年此際去防秋。',64,'全唐诗/poet.song.225000.json','["今歲無時不禦寇，每年此際去防秋。", "琴散廣陵今叔夜，笳聲出室古劉疇。", "啟沃欣承霖雨楫，流離安樂鴈鴻洲。", "我自清時幸民着，茅柴薄晚婦能篘。"]'),
('5540bf25-7c51-41a9-8e04-14327bdeb106','臨川家史君坤翁喜雨','許月卿','宋','宋诗','song-poetry','','[]','臨川鼓舞誦賢侯，閔雨皇皇祈有秋。',64,'全唐诗/poet.song.225000.json','["臨川鼓舞誦賢侯，閔雨皇皇祈有秋。", "昨夜琅函奏霄漢，今朝玉粒雨平疇。", "名亭應有東坡記，積粟可寬西顧憂。", "我得順流南浦去，商霖又是濟川舟。"]'),
('18b1c840-9bbe-4fea-a615-47759a421cf0','浴罷','許月卿','宋','宋诗','song-poetry','','[]','浴罷披襟竹影斜，客中殘暑散空花。',64,'全唐诗/poet.song.225000.json','["浴罷披襟竹影斜，客中殘暑散空花。", "人行窗外雲無脚，月起林間燈映紗。", "舉酒聞鐘知近寺，談詩食李却忘家。", "明朝又浴還來此，何必開樽只煮茶。"]'),
('bb327448-ecde-4107-982f-a2aa199c0c6c','次績溪趙簿孟英見投韻','許月卿','宋','宋诗','song-poetry','','[]','碧澗仙人亦愛樓，星溪樓上豁雙眸。',64,'全唐诗/poet.song.225000.json','["碧澗仙人亦愛樓，星溪樓上豁雙眸。", "吟邊興落千峰外，醉裏眉攢萬國愁。", "傳舍官途輕似燕，禪心世事狎於鷗。", "詩人將半南唐帝，碧澗雲烟六月秋。"]'),
('626bdf2e-458b-4c0a-b484-364d0abe034e','次胡伯凱韻','許月卿','宋','宋诗','song-poetry','','[]','作詩直欲到天慳，於蒍應如元魯山。',64,'全唐诗/poet.song.225000.json','["作詩直欲到天慳，於蒍應如元魯山。", "我隠自便甘曲渚，子來相與釣清灣。", "閑中日月詩書府，地上神仙人世間。", "尋柳問花千古意，窗前幽草不須芟。"]'),
('236debb8-954b-4649-9515-f677ddecba1b','贈李企','許月卿','宋','宋诗','song-poetry','','[]','雁湖曾是謫臨川，誰道風流愧昔賢。',64,'全唐诗/poet.song.225000.json','["雁湖曾是謫臨川，誰道風流愧昔賢。", "共覺共兜亂堯世，何須虞芮質周田。", "三年遷客僅數舍，一日恩書落九天。", "歸去來荒松菊徑，勉旃忠節振家傳。"]'),
('2ed357a7-0fbd-43f6-ba75-4aa3295e31d8','寄東宮官','許月卿','宋','宋诗','song-poetry','','[]','瀛洲有詔翊儲宮，妙選歡傳有古風。',64,'全唐诗/poet.song.225000.json','["瀛洲有詔翊儲宮，妙選歡傳有古風。", "鶴禁共看周八士，狐裘記取國三公。", "年華春早雞聲裏，博望秋嚴霜氣中。", "入侍緝熙傳聖學，四書雋永事何窮。"]'),
('e1302b9a-e920-4a75-b59a-83a23b758456','題俞時琰杏山堂醫','許月卿','宋','宋诗','song-poetry','','[]','妖冶來奔夜色昏，毅然絕谷有神明。',64,'全唐诗/poet.song.225000.json','["妖冶來奔夜色昏，毅然絕谷有神明。", "春融庭畔一簾柳，秋滿湖邊萬頃雲。", "蕩滌胃腸無穢濁，洞明空色有真清。", "陳樓相問胡盧處，本事方書世並行。"]'),
('134af595-f86b-4963-9053-4246ed7ed495','曆日','許月卿','宋','宋诗','song-poetry','','[]','曆日從頭又一新，直饒燕雀喜新晴。',64,'全唐诗/poet.song.225000.json','["曆日從頭又一新，直饒燕雀喜新晴。", "梅花獻歲無邊景，喜鵲今朝第一聲。", "柳眼知時王幕綠，草心報國漢朝青。", "日晴夜雨豐年兆，雨過雲開月滿庭。"]'),
('cb027556-b85c-48a5-82c1-affe506fba52','香潭八首  其一','許月卿','宋','宋诗','song-poetry','','[]','平生不作明河篇，一笑童心尚隠然。',64,'全唐诗/poet.song.225000.json','["平生不作明河篇，一笑童心尚隠然。", "後日視今哀後日，同年而語不同年。", "瑩清川澤玻璃地，濃淡烟雲水墨天。", "儘向癡人前說夢，何妨句裏有嬋娟。"]'),
('4fc86282-d83a-4ac0-953c-9f178063f6af','香潭八首  其二','許月卿','宋','宋诗','song-poetry','','[]','瓊林宴坐賜詩篇，先帝恩光故燁然。',64,'全唐诗/poet.song.225000.json','["瓊林宴坐賜詩篇，先帝恩光故燁然。", "紫陌尋春思是日，紅牋通刺戒同年。", "浮花浪蕊陽和地，疎影暗香霜雪天。", "松柏歲寒吾共子，春風永巷閉連娟。"]'),
('e9a47ea3-6ec5-4b92-aff2-6f292542cbf0','香潭八首  其三','許月卿','宋','宋诗','song-poetry','','[]','殷勤教我琵琶篇，年友胸中炯炯然。',64,'全唐诗/poet.song.225000.json','["殷勤教我琵琶篇，年友胸中炯炯然。", "公瑾風流酹江月，孔明禮樂中興年。", "君臣可謂逢千載，南北須教總一天。", "水調歌中休惜別，月明千里共嬋娟。"]'),
('ac1a6ce2-db2f-4e22-80ba-b38725e3d177','香潭八首  其四','許月卿','宋','宋诗','song-poetry','','[]','我歌亂以歸來篇，君笑騎馿孟浩然。',64,'全唐诗/poet.song.225000.json','["我歌亂以歸來篇，君笑騎馿孟浩然。", "君有風雲須得地，我無曆日不知年。", "君貪觴咏盟泉石，我願朝廷泰地天。", "君去登畿春浩浩，我歸受幣女娟娟。"]'),
('e527f34d-78ef-4743-ad32-42f9a887c80c','香潭八首  其五','許月卿','宋','宋诗','song-poetry','','[]','信筆篇篇又一篇，東坡父子故依然。',64,'全唐诗/poet.song.225000.json','["信筆篇篇又一篇，東坡父子故依然。", "鳳凰鳴處知何日，龍虎榜中今幾年。", "殘歲寄寒難避地，顛風急雪更無天。", "六宮粉黛無顔色，誰道人間少靜娟。"]'),
('9c7810ec-4c8e-457b-b19d-16d7b655a822','香潭八首  其六','許月卿','宋','宋诗','song-poetry','','[]','斗酒從來詩百篇，世間莊語便譁然。',64,'全唐诗/poet.song.225000.json','["斗酒從來詩百篇，世間莊語便譁然。", "蕙蘭得志應無日，稊稗逢時却有年。", "何必怨尤難捨我，欲教平治直須天。", "生來不被蛾眉誤，人謗人間無麗娟。"]'),
('50ef9b9e-be78-4767-850c-619f27faeca7','香潭八首  其七','許月卿','宋','宋诗','song-poetry','','[]','老師當日啟靈篇，親手傳承豈偶然。',64,'全唐诗/poet.song.225000.json','["老師當日啟靈篇，親手傳承豈偶然。", "殘月曉風空夜夜，垂楊芳草自年年。", "報恩男子那無地，未喪斯文决有天。", "月在香潭照心曲，更饒一雨洗娟娟。"]'),
('12feca57-6a3b-4b16-9bb4-afea637db25f','香潭八首  其八','許月卿','宋','宋诗','song-poetry','','[]','政須洗耳聽新篇，業已扁舟學計然。',64,'全唐诗/poet.song.225000.json','["政須洗耳聽新篇，業已扁舟學計然。", "潔己庶幾堪諫主，力田未必愧逢年。", "菑畬之業平心地，金石之交只在天。", "舞殿歌臺從冷暖，此心如月一嬋娟。"]'),
('1e006565-86ba-463a-8b62-7c3384b9d154','仲春初五日報謁','許月卿','宋','宋诗','song-poetry','','[]','玉磬蒲團出定音，謁酬與世費浮沉。',64,'全唐诗/poet.song.225000.json','["玉磬蒲團出定音，謁酬與世費浮沉。", "徑松參漢周官肅，塢竹藏雲商易深。", "暮色溪山皆有道，春風花草本無心。", "年來年去頭成白，斗酒樓前明月斟。"]'),
('2ac7f055-5648-4201-a21f-03bc7f7dfce4','多謝','許月卿','宋','宋诗','song-poetry','','[]','多謝東皇着意晴，海棠勻趁笑相迎。',64,'全唐诗/poet.song.225000.json','["多謝東皇着意晴，海棠勻趁笑相迎。", "園林富貴何千萬，花柳功勳已十成。", "曉雨有情於芍藥，春風無處不流鶑。", "扁舟水長一篙許，茶竈筆床聊意行。"]'),
('c0d7c3c8-4c79-4b8a-a183-43ada43d3d5c','早起','許月卿','宋','宋诗','song-poetry','','[]','早起輕寒尚裌衣，飯餘春雨滿行旂。',64,'全唐诗/poet.song.225000.json','["早起輕寒尚裌衣，飯餘春雨滿行旂。", "春波綠處春草碧，曉露濃時曉日晞。", "桃李年年春富貴，桑麻事事道精微。", "詩情不在火爐畔，風雪灞橋烟景歸。"]'),
('88b9e753-2630-42db-b643-993d028e2bec','厭厭','許月卿','宋','宋诗','song-poetry','','[]','厭厭夜飲忘更深，客不來辭主有情。',64,'全唐诗/poet.song.225000.json','["厭厭夜飲忘更深，客不來辭主有情。", "僮僕觸屏成蝶夢，姬姜壓笛作蟬聲。", "月如有待行行慢，風不生嗔細細清。", "萍散人生何可料，嬋娟千里共交盟。"]'),
('3c79eab1-4b33-4c4b-9133-907fd7b07f13','項似道眉子硯','許月卿','宋','宋诗','song-poetry','','[]','新安硯石舊多奇，硯入黄扉得所歸。',64,'全唐诗/poet.song.225000.json','["新安硯石舊多奇，硯入黄扉得所歸。", "呵水浮雲尤物視，傳衣半夜偉人知。", "坡仙爲欠十眉詠，李及何妨一硯持。", "堪笑泉田老居士，無端渾沌盡新眉。"]'),
('916f2937-b13f-4565-8694-8e7f97b5823b','憶胡同年','許月卿','宋','宋诗','song-poetry','','[]','同年情誼弟兄侔，姓不同兮馬范儔。',64,'全唐诗/poet.song.225000.json','["同年情誼弟兄侔，姓不同兮馬范儔。", "吾榜得人今古盛，使君與我腹心投。", "斜陽遮斷離愁路，野渡撐開別恨舟。", "水調聲中多少事，暮烟林壑月明樓。"]'),
('a0fbfbac-7249-4a47-a8fb-f12f4b3f9fe4','賦廷玉菊存堂','許月卿','宋','宋诗','song-poetry','','[]','祖菊園翁孫菊存，君家菊譜傲蘭孫。',64,'全唐诗/poet.song.225000.json','["祖菊園翁孫菊存，君家菊譜傲蘭孫。", "天隨天問非他族，秋意秋懷自一門。", "白送遶籬從谷谷，黄飄流地彼村村。", "花應自賀三生遇，親見淵明無此孫。"]'),
('7f901996-d2ac-41fa-a5aa-c8590cf17d7a','賦吳廷圭篔西亭','許月卿','宋','宋诗','song-poetry','','[]','竹西歌吹古揚州，分與延陵第一流。',64,'全唐诗/poet.song.225000.json','["竹西歌吹古揚州，分與延陵第一流。", "直節雪霜霜曉檻，虛心風月月明樓。", "東南直道輝青史，朔北虛懷動玉旒。", "立盡斜陽更新月，纏腰騎鶴此君游。"]'),
('1fd29bcf-c85a-4b0b-9e8d-267d529d17f9','題德新堂','許月卿','宋','宋诗','song-poetry','','[]','同年吾憶鄭盤翁，獨向盤銘緊用工。',64,'全唐诗/poet.song.225000.json','["同年吾憶鄭盤翁，獨向盤銘緊用工。", "似玉躬行勤淬礪，如棋世事極磨礲。", "初年晚節渾無斁，昨日今朝便不同。", "遺子貽孫新未已，盤銘須信有奇功。"]'),
('b77212a8-e960-4f91-82bd-a30adafb649c','起來','許月卿','宋','宋诗','song-poetry','','[]','起來霜月冷颼颼，清興催人不自由。',64,'全唐诗/poet.song.225000.json','["起來霜月冷颼颼，清興催人不自由。", "萬戶千門胡蝶夢，五更三點黑貂裘。", "旦公待旦霜如雪，時夜如時月似鈎。", "明日人來問寄字，一天霜月倚西樓。"]'),
('aff96890-e494-47e8-a811-a87a099d1650','露','許月卿','宋','宋诗','song-poetry','','[]','輕烟薄霧結凄迷，顆顆勻圓訝許齊。',64,'全唐诗/poet.song.225000.json','["輕烟薄霧結凄迷，顆顆勻圓訝許齊。", "無雨無風聞葉響，如珠如粟壓花低。", "飛來蓮葉仙猶濕，吟過林稍蟬不饑。", "散洒劉郎金露掌，不垣不戶總京低。"]'),
('09f48ff5-a25c-41db-9efc-4f339097586e','臨川','許月卿','宋','宋诗','song-poetry','','[]','臨川攝守得仁侯，閔兩精誠貫顯幽。',64,'全唐诗/poet.song.225000.json','["臨川攝守得仁侯，閔兩精誠貫顯幽。", "五日不將京兆看，豐年惟切杜陵憂。", "先欣霢霂滋青稻，佇見滂沱漲碧流。", "物外閑人歡喜處，炎天亭受一亭秋。"]'),
('9260ed69-21b0-4963-a29e-59654e32a5e0','送孫山長謁皮參政','許月卿','宋','宋诗','song-poetry','','[]','授鉞天教錦故鄉，公心泉石不旂常。',64,'全唐诗/poet.song.225000.json','["授鉞天教錦故鄉，公心泉石不旂常。", "沙堤正自恐不免，野渡安能久退藏。", "羨子白劉從綠野，顧予雞犬愧旌陽。", "衮衣會趁春風入，野服猶堪謁道傍。"]'),
('9516c468-cc85-43ae-a66d-879e9b7246d4','代弟二首  其一','許月卿','宋','宋诗','song-poetry','','[]','少年卜式謾輸邊，畢竟鄉人合薦賢。',64,'全唐诗/poet.song.225000.json','["少年卜式謾輸邊，畢竟鄉人合薦賢。", "純□□□忘寢食，浮名過眼謝騰騫。", "聖恩雨露榮親日，春酒光風介壽天。", "世事到頭都是夢，青衫贏得畫圖傳。"]'),
('95f543e9-a416-4a11-af76-bf5673c3747d','代弟二首  其二','許月卿','宋','宋诗','song-poetry','','[]','渭陽夢斷幾經年，幸甚東床再有緣。',64,'全唐诗/poet.song.225000.json','["渭陽夢斷幾經年，幸甚東床再有緣。", "躍鯉庭中看鑄鼎，乘龍門外待揚鞭。", "墓碑不載韓翺字，文集應傳李漢編。", "愁滿重慈鬢邊雪，夜來風雨暗前川。"]'),
('163dcdf2-3b74-4b8c-8d9b-c60b24c83a5f','挽張丞泳','許月卿','宋','宋诗','song-poetry','','[]','異時兩舉遂登科，人謂功名當若何。',64,'全唐诗/poet.song.225000.json','["異時兩舉遂登科，人謂功名當若何。", "三十餘年空屈曲，七咨脫選竟蹉跎。", "爲丞再出簿尉下，斯世渾如夢覺過。", "同里同年老御史，諒難如此不悲歌。"]'),
('aaeb4f38-e6a2-4248-9a0c-325b8c4a9406','送周徽州赴建州','許月卿','宋','宋诗','song-poetry','','[]','作牧文公父母州，考亭今又借邦侯。',64,'全唐诗/poet.song.225000.json','["作牧文公父母州，考亭今又借邦侯。", "來莫建山同仰止，去思歙水共長流。", "貢茗莫淹千里守，和羹須是百花頭。", "暇日摩挲廳壁記，昔梁叔子後身周。"]'),
('36accee9-f382-40f3-84b8-09d7a2e6821b','次周尚書八首  其一','許月卿','宋','宋诗','song-poetry','','[]','卜隠偏宜大好州，浮雲夢不到王侯。',64,'全唐诗/poet.song.225000.json','["卜隠偏宜大好州，浮雲夢不到王侯。", "細評月露蒼山峙，靜止花闌綠水流。", "泉□□□□□□，□簑無雨可淋頭。", "西江賓幕相須久，贏得閑吟謁道周。"]'),
('e835c726-0e49-4de8-a839-cc8c18dd044b','次周尚書八首  其二','許月卿','宋','宋诗','song-poetry','','[]','溫州今似古青州，溫飽能輕百戶侯。',64,'全唐诗/poet.song.225000.json','["溫州今似古青州，溫飽能輕百戶侯。", "沃力泉源那擇地，歲寒砥柱屹中流。", "要知蟬□三公府，便是黄扉四狀頭。", "萬事世間唐土爾，辦將勳業到伊周。"]'),
('c324a40a-3105-433e-92a1-c4877c572d45','次周尚書八首  其三','許月卿','宋','宋诗','song-poetry','','[]','公與梅溪生共州，一編默受似留侯。',64,'全唐诗/poet.song.225000.json','["公與梅溪生共州，一編默受似留侯。", "冰霜歲晚仝清節，涇渭胸中肯混流。", "皎日當空峨豸角，支天一柱屬龍頭。", "時清儘可巢由我，身健猶看師宰周。"]'),
('17d387ac-9a0d-4240-a795-e68c61e9bae6','次周尚書八首  其四','許月卿','宋','宋诗','song-poetry','','[]','曾共芙蓉下視州，舊衝仍是醉鄉侯。',64,'全唐诗/poet.song.225000.json','["曾共芙蓉下視州，舊衝仍是醉鄉侯。", "半山相俟歸投老，若水公兮急退流。", "世事每觀强努力，人生何似大刀頭。", "摛文儘自染燕許，閑夢何妨我蝶周。"]'),
('e3368b1f-bdfb-4580-a023-c05ac110d761','次周尚書八首  其五','許月卿','宋','宋诗','song-poetry','','[]','老氣軒昂蓋四州，文場真將屬條侯。',64,'全唐诗/poet.song.225000.json','["老氣軒昂蓋四州，文場真將屬條侯。", "君扶黄道青如許，我住花屏翠欲流。", "禁路促歸一夔足，詞場飛跨六鰲頭。", "隠箕山上泉瓢許，歌大江東羽扇周。"]'),
('f5994b03-680a-4d42-8780-e854d6969d77','次周尚書八首  其六','許月卿','宋','宋诗','song-poetry','','[]','后山着意送荆州，相伴兒童餞細侯。',67,'全唐诗/poet.song.225000.json','["后山着意送荆州，相伴兒童餞細侯。", "風月夜深獨先覺，乾坤秋老不同流。", "江閩凱悌地聯脈，關陝規恢天盡頭。", "聞說齊{月畺}婦唾手，世如用孔作東周。"]'),
('4034734e-c136-4c1b-b5d2-65cd47da8b1f','次周尚書八首  其七','許月卿','宋','宋诗','song-poetry','','[]','詩律無寒□鄴州，家風洗耳□□侯。',64,'全唐诗/poet.song.225000.json','["詩律無寒□鄴州，家風洗耳□□侯。", "□傳以酒爲真印，萬法惟梅不共流。", "幸免五經嘲笥腹，可無百尺進竿頭。", "從來此道飄零甚，戎索惟憑疆以周。"]'),
('a9875bc2-9afe-441d-b8e0-f7beaec4866f','次周尚書八首  其八','許月卿','宋','宋诗','song-poetry','','[]','平原平等視青州，不佛不仙仍不侯。',64,'全唐诗/poet.song.225000.json','["平原平等視青州，不佛不仙仍不侯。", "滿樹絲蘿天富貴，半窗水墨月風流。", "皆云臨濟具雙眼，且放東坡出一頭。", "劈畫尚能千百歲，須臾一笑跨商周。"]'),
('646eb1ad-2dd1-4174-adc7-459d4bd84360','暮春聯句九首  其一','許月卿','宋','宋诗','song-poetry','','[]','清廟朱絃瑟，羔羊素緎風。',132,'全唐诗/poet.song.225000.json','["清廟朱絃瑟，羔羊素緎風。", "釣竿漁艇小，園徑李蹊通。", "白酒渾忘送，皇天似不公。", "風簷開秀色，雪嶺現酥胸。", "王化殊無外，聖賢時復中。", "人稱君子子，卿自密翁翁。", "從喚酒經癖，聊紓花史忠。", "前知安用卜，定見不訪訌。", "橘僕使令熟，竹君家計豐。", "六年無不可，三語將無同。", "柳子慣乞巧，韓公不送窮。"]'),
('6e14782a-c11e-4f84-96a6-462b1911b56f','暮春聯句九首  其二','許月卿','宋','宋诗','song-poetry','','[]','畏愛盾衰日，清和夷惠風。',132,'全唐诗/poet.song.225000.json','["畏愛盾衰日，清和夷惠風。", "仁何如管仲，恩罔極王通。", "王必三微謹，天爲一大公。", "五行應過眼，萬字佛頭胸。", "治國運掌上，經書滿腹中。", "憑欄心尚壯，引鏡鬢俄翁。", "錫屈天生德，教咸黄覽忠。", "齊夷靡瞻騁，內外詛萬訌。", "一酌泉流濁，四知囊匱豐。", "詠觴聊暢敘，羹水辨和同。", "不當陳三價，難逃黄九窮。"]'),
('8c316f93-f728-4da6-818b-17702dafd9d8','暮春聯句九首  其三','許月卿','宋','宋诗','song-poetry','','[]','祥雲仍瑞日，霽月更光風。',132,'全唐诗/poet.song.225000.json','["祥雲仍瑞日，霽月更光風。", "虹夜書舡滿，鷄林詩賈通。", "十行寬四海，一國詠三公。", "經史遮眵目，古今澆渴胸。", "太玄難準易，皇極辯非中。", "清夜談玄處，盛時無極翁。", "乾坤涵奧學，日月照孤忠。", "自信區區者，遥憐處處訌。", "天無厭周德，年侯克商豐。", "群后集班瑞，宗人宅受同。", "太平無以報，真意渺何窮。"]'),
('43cac595-787a-434b-8fe5-8d2d565996ea','暮春聯句九首  其四','許月卿','宋','宋诗','song-poetry','','[]','沃心裨帝學，古道暢皇風。',132,'全唐诗/poet.song.225000.json','["沃心裨帝學，古道暢皇風。", "天下真無敵，君前置一通。", "將拚龍尾硯，去作魚頭公。", "筆底瀾翻舌，談間磊塊胸。", "通明雲殿上，清切玉堂中。", "發軔同安簿，深衣獨樂翁。", "孝經題幼志，沼鑑見精忠。", "元祐龍蛇雜，開禧蟊賊訌。", "隆冬老儒立，奸黨一碑豐。", "三晉春秋在，千年綱目同。", "長天炤孤憤，清夜好研窮。"]'),
('eae28e29-8d98-41c5-98e5-66b880912359','暮春聯句九首  其五','許月卿','宋','宋诗','song-poetry','','[]','我似濂溪拙，人嗤凝式風。',132,'全唐诗/poet.song.225000.json','["我似濂溪拙，人嗤凝式風。", "天連千障合，水可四溟通。", "我友二三子，他年十八公。", "逍遥吟弄趣，灑落霽光胸。", "傲睨芸香裏，醉眠花影中。", "文章解遷史，詩律更涪翁。", "與酒交逾密，爲花謀必忠。", "鶴琴清夜警，鶑燕暮春訌。", "冰釋契杜預，露晞詢鞏豐。", "幾能知至至，學貴不同同。", "山水清音有，園林勝事窮。"]'),
('f9ce64ae-d3cb-431b-86e5-9ba20209a997','暮春聯句九首  其六','許月卿','宋','宋诗','song-poetry','','[]','徐字不晉帖，楚詩無國風。',132,'全唐诗/poet.song.225000.json','["徐字不晉帖，楚詩無國風。", "天邊長劍倚，花外小車通。", "不肯吏文叔，誰能書子公。", "二三豪俊骨，數萬甲兵胸。", "柳暗琴三疊，梅殘酒一中。", "羨君屠龍技，笑我祝雞翁。", "擊甕浮兒志，編橋度蟻忠。", "行春奉寬詔，佩犢弭兵訌。", "天闊吟邊遠，月明詩檐豐。", "秋光宦情薄，鸞鶴嘯聲同。", "清澗耳堪洗，深山目更窮。"]'),
('d6eb384c-a2b1-4b77-a405-c46db97c953a','暮春聯句九首  其七','許月卿','宋','宋诗','song-poetry','','[]','寸心元有雨，八面更當風。',132,'全唐诗/poet.song.225000.json','["寸心元有雨，八面更當風。", "精衛海能涸，杜鵑天可通。", "君臣知有義，褒貶豈無公。", "一展霹靂手，九吞雲夢胸。", "狂瀾障川外，砥柱橫流中。", "曷不身伊尹，空教口晦翁。", "主憂臣不辱，世亂孰爲忠。", "白日青天共，潢池渤海訌。", "居家移官理，憂國願年豐。", "今古心符節，乾坤理勘同。", "普能知道大，院不慮途窮。"]'),
('6015c736-4d77-4756-8874-c9db2d66a3ea','暮春聯句九首  其八','許月卿','宋','宋诗','song-poetry','','[]','燮調能十雨，具訓微三風。',132,'全唐诗/poet.song.225000.json','["燮調能十雨，具訓微三風。", "希聖如顔子，何時笑叔通。", "明經徒爲利，穢史不能公。", "落落經綸腹，悠悠錦繡胸。", "茶烟禪榻上，花蕊酒盃中。", "皇覽方佳少，青衫已禿翁。", "凄凉語棐話，寂寞教咸忠。", "青嶂鶴仙返，白楊鴉夜訌。", "庭前雙桂樹，堂上六經豐。", "皇帝春秋盛，車書夷夏同。", "移忠聊士諾，獨善未妨窮。"]'),
('74be28e5-1b96-4115-9dee-f7346a2003e0','暮春聯句九首  其九','許月卿','宋','宋诗','song-poetry','','[]','賀公雅吳語，文靖詠唐風。',132,'全唐诗/poet.song.225000.json','["賀公雅吳語，文靖詠唐風。", "我自儒多誤，心慙佛六通。", "將焉用彼相，不肯爲渠公。", "明月夜滿目，晴雲曉盪胸。", "馬更騎東下，騮更入花中。", "無慮殊難老，有頭能自翁。", "徜徉生計拙，瀟散自謀忠。", "白酒盃中滿，紅塵門外訌。", "漢輪謾牧叟，魯質不周豐。", "自詭冰堅渡，如新火浣同。", "青山青未了，綠水綠無窮。"]'),
('92a9fb9f-ef8b-4c47-811a-39815e84c4ce','途中賡禁體雪韻','許月卿','宋','宋诗','song-poetry','','[]','野店衝寒出曉芭，渾如踏月過溪沙。',64,'全唐诗/poet.song.225000.json','["野店衝寒出曉芭，渾如踏月過溪沙。", "五漿先具簷頭蕊，六博爭雄屐齒花。", "狐白裘成天不管，玉清境浄地無瑕。", "素光自是漁人物，披得一簑來酒家。"]'),
('e4d6dfd4-4380-4ec9-88b1-63dbb8137af8','十二辰','許月卿','宋','宋诗','song-poetry','','[]','饑鼠簷行驕捷疾，蝸牛角立爭奇崛。',96,'全唐诗/poet.song.225000.json','["饑鼠簷行驕捷疾，蝸牛角立爭奇崛。", "似聞猛虎今陸游，從以卧兔未飄忽。", "先生龍卧未風雲，春蚓秋蛇供醉筆。", "蕭蕭馬鳴旆悠悠，牧民如羊良率易。", "人言唐土愧二猴，漢使碧鷄真浪出。", "屠狗師還戒勿用，驅豬試問問王弼。"]'),
('8c8dc2de-46be-4eb6-87df-034f0396dd9b','題清足堂','許月卿','宋','宋诗','song-poetry','','[]','秀翁今又以光名，窗外琅玕不欠清。',64,'全唐诗/poet.song.225000.json','["秀翁今又以光名，窗外琅玕不欠清。", "十八公松曾入夢，兩三竿竹豈無情。", "紅塵不近春風瑟，翠色能添夜雪燈。", "我欲釣竿簑笠去，斸分烟雨子還能。"]'),
('ff034078-69f0-47b7-95a4-d7a029865d27','次韻曉行','許月卿','宋','宋诗','song-poetry','','[]','主人別客屢挑燈，客喜乘凉月下行。',64,'全唐诗/poet.song.225000.json','["主人別客屢挑燈，客喜乘凉月下行。", "暗露濕螢仍濕草，曉風殘月更殘更。", "柔情燕燕椒房夜，雅韻鶑鶑桂魄晶。", "朝往長沙成夜醉，宵征肅肅醉翁亭。"]'),
('ef77025b-7815-46bd-853c-329389acc016','用名世弟韻','許月卿','宋','宋诗','song-poetry','','[]','大圭白璧男兒事，小酌青燈兄弟情。',64,'全唐诗/poet.song.225000.json','["大圭白璧男兒事，小酌青燈兄弟情。", "倚閣烟雲生別浦，高林風月滿疎櫺。", "人生功業何損益，外物本心須重輕。", "志節始終非易事，退之猶自怵天刑。"]'),
('79c850f4-a46e-4096-8725-fd9d1338eb22','悶來','許月卿','宋','宋诗','song-poetry','','[]','悶來時暫作兒嬉，沽酒溪邊就買魚。',64,'全唐诗/poet.song.225000.json','["悶來時暫作兒嬉，沽酒溪邊就買魚。", "鷗鳥水雲天一色，梅花雪月地三奇。", "水西何况景尤絕，雪後懸知畫不如。", "安得扁舟更簑笠，悶來時暫作兒嬉。"]'),
('1055e904-c5fc-4bb4-87a0-c65e7f757210','次韻程說和','許月卿','宋','宋诗','song-poetry','','[]','燈花昨夜爲誰開，誰笑泉田處士來。',64,'全唐诗/poet.song.225000.json','["燈花昨夜爲誰開，誰笑泉田處士來。", "不染一塵宜寶界，長如三月似天台。", "頻摇麈尾頻揮翰，每看蟾輪每舉盃。", "和氣滿堂春拍拍，燈花昨夜爲誰開。"]'),
('acf4baca-5c56-41e6-b569-fbe1cac73bb2','贈朱野拙','許月卿','宋','宋诗','song-poetry','','[]','官樣何如野，謀生拙最宜。',24,'全唐诗/poet.song.225000.json','["官樣何如野，謀生拙最宜。", "君門標野拙，篆刻大精奇。"]'),
('2505971b-057c-48aa-a69f-085f46c55294','千年','許月卿','宋','宋诗','song-poetry','','[]','千年光景東西漢，一把春風大小喬。',32,'全唐诗/poet.song.225000.json','["千年光景東西漢，一把春風大小喬。", "坐嘯行吟芳草碧，杜鵑時節雨瀟瀟。"]'),
('d98aab8b-dca9-4516-83f1-24c12d7f544a','黄菊','許月卿','宋','宋诗','song-poetry','','[]','黄菊飄零滿地金，詩人枉用一生心。',32,'全唐诗/poet.song.225000.json','["黄菊飄零滿地金，詩人枉用一生心。", "木犀滿地金英落，消得詩人曉夕吟。"]'),
