('1921c9a8-18bc-4809-a59f-42b33679d70f','偈頌一百二十三首  其二○','釋祖欽','宋','宋诗','song-poetry','','[]','兩岸夭桃花欲燃，一絲風動釣魚船。',32,'全唐诗/poet.song.225000.json','["兩岸夭桃花欲燃，一絲風動釣魚船。", "莫言世上無仙客，須信壺中別有天。"]'),
('f0852ab2-89dd-4ef3-8e76-f00bd9aa8a7b','偈頌一百二十三首  其二一','釋祖欽','宋','宋诗','song-poetry','','[]','杜鵑啼血滿花枝，底事匆匆苦勸歸。',32,'全唐诗/poet.song.225000.json','["杜鵑啼血滿花枝，底事匆匆苦勸歸。", "歸到故鄉還似客，村村綠暗與紅稀。"]'),
('fc1c4837-2d71-481d-8b0a-e22efe9a003a','偈頌一百二十三首  其二二','釋祖欽','宋','宋诗','song-poetry','','[]','落花三月雨，殘夢五更鐘。',24,'全唐诗/poet.song.225000.json','["落花三月雨，殘夢五更鐘。", "聲色俱銷盡，玄關又一重。"]'),
('95187a46-27a2-40e2-b784-f8848babf85a','偈頌一百二十三首  其二三','釋祖欽','宋','宋诗','song-poetry','','[]','一心三觀，一句三玄。',46,'全唐诗/poet.song.225000.json','["一心三觀，一句三玄。", "曾無彼此，休分教禪。", "迴途復妙也，枯木岩前差路。", "窮淵極流兮，海底紅塵亙天。"]'),
('b1914ab9-e7a1-4b65-a824-f4d1a64b5d85','偈頌一百二十三首  其二四','釋祖欽','宋','宋诗','song-poetry','','[]','竟日窗開坐寂寥，岩前笋稚欲齊腰。',32,'全唐诗/poet.song.225000.json','["竟日窗開坐寂寥，岩前笋稚欲齊腰。", "幽禽忽起藤花落，磵瀑吹聲度石橋。"]'),
('556d90ce-895b-4f33-b9b6-865c55d96852','偈頌一百二十三首  其二五','釋祖欽','宋','宋诗','song-poetry','','[]','前四十五日，知進不知退。',52,'全唐诗/poet.song.225000.json','["前四十五日，知進不知退。", "後四十五日，知退不知進。", "正當今日，進退兩忘。", "季夏極熱，薰風自凉。", "時聞一陣藕花香。"]'),
('1a54fa10-8af8-4f45-aca8-e16cbecd9793','偈頌一百二十三首  其二六','釋祖欽','宋','宋诗','song-poetry','','[]','聞名不如見面，見面不如聞名。',30,'全唐诗/poet.song.225000.json','["聞名不如見面，見面不如聞名。", "三十年不識個一字，元來却是枚丁。"]'),
('d9ca8daa-718b-4a80-a2fb-a2f83f846ea8','偈頌一百二十三首  其二七','釋祖欽','宋','宋诗','song-poetry','','[]','斷臂立雪，負石踏碓。',39,'全唐诗/poet.song.225000.json','["斷臂立雪，負石踏碓。", "取人心肝，克由尀耐。", "護聖遮裡，使不得你露面作竊，且退且退。"]'),
('0a1d6464-a410-474f-b8e6-9059a79ab5cd','偈頌一百二十三首  其二八','釋祖欽','宋','宋诗','song-poetry','','[]','皇圖更統，佛運亦新。',30,'全唐诗/poet.song.225000.json','["皇圖更統，佛運亦新。", "四海八蠻，咸傾化日，窮巖絕壑，共舞陽春。"]'),
('413d16b1-0748-48f9-9c20-1e2ea40de7d2','偈頌一百二十三首  其二九','釋祖欽','宋','宋诗','song-poetry','','[]','夜月透靈犀，寒光吞老蚌。',24,'全唐诗/poet.song.225000.json','["夜月透靈犀，寒光吞老蚌。", "如是轉法輪，平沉乎萬象。"]'),
('eff96a1d-fc63-4c79-bef9-acd75d57b8d6','偈頌一百二十三首  其三○','釋祖欽','宋','宋诗','song-poetry','','[]','釋迦已滅，彌勒未生。',37,'全唐诗/poet.song.225000.json','["釋迦已滅，彌勒未生。", "於此二千年內，有法誰說，有令誰行。", "雲門鼻直，德山眼橫。"]'),
('8c6d5880-9758-4120-afe2-b19358644a71','偈頌一百二十三首  其三一','釋祖欽','宋','宋诗','song-poetry','','[]','你有一丈還你一丈，你有一尺還你一尺。',34,'全唐诗/poet.song.225000.json','["你有一丈還你一丈，你有一尺還你一尺。", "若只咬定不肯囘頭，白日青天霹靂。"]'),
('563de7e3-236a-41b2-94a7-2195b7f5fcc1','偈頌一百二十三首  其三二','釋祖欽','宋','宋诗','song-poetry','','[]','佛法本無多子，堂堂日用之間。',57,'全唐诗/poet.song.225000.json','["佛法本無多子，堂堂日用之間。", "只因自信不及，却於易處艱難。", "今夜不免作些方便，爲諸人豁開戶牖拶碎疑團。", "星在秤兮不在盤。"]'),
('ea0752db-f67d-4d02-ae26-2578fa2c807b','偈頌一百二十三首  其三三','釋祖欽','宋','宋诗','song-poetry','','[]','叢林雖未整肅，更點却要分明。',28,'全唐诗/poet.song.225000.json','["叢林雖未整肅，更點却要分明。", "粒米須還粒飯，八兩定要半斤。"]'),
('a160f7d1-ab35-49bf-bd53-3ecff84303d5','偈頌一百二十三首  其三四','釋祖欽','宋','宋诗','song-poetry','','[]','萬化之源，萬物之母。',60,'全唐诗/poet.song.225000.json','["萬化之源，萬物之母。", "德被河沙，量包海宇。", "聖中之聖，主中之主。", "慶會一時，壽崇千古。", "以坤自貴，月朗太虛。", "以乾爲子，紅日卓午。"]'),
('140eae92-3a3d-44b6-8cc1-af1b4e9609ad','偈頌一百二十三首  其三五','釋祖欽','宋','宋诗','song-poetry','','[]','一切法離分別相，依前諸相自如如。',32,'全唐诗/poet.song.225000.json','["一切法離分別相，依前諸相自如如。", "春風影裡乾坤大，無限江山開畫圖。"]'),
('d5818b96-6767-4d71-8222-cf8948543955','偈頌一百二十三首  其三六','釋祖欽','宋','宋诗','song-poetry','','[]','是亦剗，非亦剗。',18,'全唐诗/poet.song.225000.json','["是亦剗，非亦剗。", "令下無私，棒頭有眼。"]'),
('cc9bff37-8c4f-4bf7-8d2d-5f467512f3f5','偈頌一百二十三首  其三七','釋祖欽','宋','宋诗','song-poetry','','["\u592a\u6e56"]','年來年去，去來不動乾坤。',66,'全唐诗/poet.song.225000.json','["年來年去，去來不動乾坤。", "歲舊歲新，新舊一般時節。", "蒼卞山風骨自露，太湖水徹底無波。", "冷冷落落，哆哆和和。", "門外雪消春水滑，庭前玉立桂婆娑。"]'),
('02e52c49-e8e7-443f-a7f3-bec92e04eed1','偈頌一百二十三首  其三八','釋祖欽','宋','宋诗','song-poetry','','[]','我此潑天門戶，大地一網俱收。',28,'全唐诗/poet.song.225000.json','["我此潑天門戶，大地一網俱收。", "若是祥麟瑞鳳，從教戴角擎頭。"]'),
('aded0946-dc8b-4e26-af6e-9c904bdb8dcb','偈頌一百二十三首  其三九','釋祖欽','宋','宋诗','song-poetry','','[]','弄晴微雨濕春風，柳自青青花自紅。',32,'全唐诗/poet.song.225000.json','["弄晴微雨濕春風，柳自青青花自紅。", "寄語遊人急囘首，歌樓不在畫橋東。"]'),
('4a8385af-6081-4bbf-888d-64d31c136b4b','偈頌一百二十三首  其四○','釋祖欽','宋','宋诗','song-poetry','','[]','岸柳摇金，溪桃吐玉。',36,'全唐诗/poet.song.225000.json','["岸柳摇金，溪桃吐玉。", "波旬無端起舞，阿難平地悲哭。", "因甚如此，親見如來面目。"]'),
('b9777136-7461-4634-b595-5bd0d4e87218','偈頌一百二十三首  其四一','釋祖欽','宋','宋诗','song-poetry','','[]','春日遲遲，綠暗紅稀。',32,'全唐诗/poet.song.225000.json','["春日遲遲，綠暗紅稀。", "尀耐深山百舌，也學江南杜宇，聲聲報道不如歸。"]'),
('9400baeb-9ae6-47c7-bab2-9e032577b4b2','偈頌一百二十三首  其四二','釋祖欽','宋','宋诗','song-poetry','','[]','洗面摸著鼻孔，不知打破漆桶。',35,'全唐诗/poet.song.225000.json','["洗面摸著鼻孔，不知打破漆桶。", "園裏蓬頭道者，全無供養之心，爛却瓜秧瓠種。"]'),
('eb29f919-1a04-4f0d-af92-27fad669bb96','偈頌一百二十三首  其四三','釋祖欽','宋','宋诗','song-poetry','','[]','只聞子聲，不見子形，忒煞分明。',30,'全唐诗/poet.song.225000.json','["只聞子聲，不見子形，忒煞分明。", "只得其體，不得其用，可煞現成。"]'),
('7c107978-312e-4395-a458-0e82fcd53728','偈頌一百二十三首  其四四','釋祖欽','宋','宋诗','song-poetry','','[]','有體有用，無正無偏。',44,'全唐诗/poet.song.225000.json','["有體有用，無正無偏。", "一法忽爾，萬法亦然。", "麻三斤，乾屎橛，庭前柏樹子，這裏會得，不直半錢。"]'),
('3314818e-0b80-4ade-b4c2-28873bbb550f','偈頌一百二十三首  其四五','釋祖欽','宋','宋诗','song-poetry','','[]','轉求轉遠，不求更遠。',27,'全唐诗/poet.song.225000.json','["轉求轉遠，不求更遠。", "豈不見東野菴前水磨，轆轆機輪自轉。"]'),
('0608d978-c2ba-4384-ac60-7065aa45fa2d','偈頌一百二十三首  其四六','釋祖欽','宋','宋诗','song-poetry','','[]','水不洗水，金不博金。',20,'全唐诗/poet.song.225000.json','["水不洗水，金不博金。", "青天白日，自古自今。"]'),
('a966c906-5cfd-4ee0-b4e5-a022843b25fb','偈頌一百二十三首  其四七','釋祖欽','宋','宋诗','song-poetry','','[]','事有萬殊，法無異說。',20,'全唐诗/poet.song.225000.json','["事有萬殊，法無異說。", "寒但言寒，熱但言熱。"]'),
('655e8e9c-06bf-4b49-8eff-57f09ecaad95','偈頌一百二十三首  其四八','釋祖欽','宋','宋诗','song-poetry','','[]','千說萬說，不如親面一見。',52,'全唐诗/poet.song.225000.json','["千說萬說，不如親面一見。", "千討萬討，不知只在手頭。", "寒風蕭蕭，黄葉飄飄。", "鶴眠松頂，雲卧山腰。", "幾番今日又明朝。"]'),
('5e75cbe1-ca83-47fb-a27e-caf265990279','偈頌一百二十三首  其四九','釋祖欽','宋','宋诗','song-poetry','','[]','道在日用，日用不知。',42,'全唐诗/poet.song.225000.json','["道在日用，日用不知。", "饑只喫飯，寒只添衣，晴天愛日挂枯藜。", "點檢溪頭梅樹，向陽偷放南枝。"]'),
('798f32b7-b405-47f0-bc6a-bcedbfd7bf29','偈頌一百二十三首  其五○','釋祖欽','宋','宋诗','song-poetry','','[]','松直棘曲，鳬短鶴長。',22,'全唐诗/poet.song.225000.json','["松直棘曲，鳬短鶴長。", "日移山影轉，風送野花香。"]'),
('8c6e5f78-fd4c-4432-a39e-8c89a731ae54','偈頌一百二十三首  其五一','釋祖欽','宋','宋诗','song-poetry','','[]','春雨溟濛，春雲靉靆。',27,'全唐诗/poet.song.225000.json','["春雨溟濛，春雲靉靆。", "忽然杲日當空，天不能遮，地不能載。"]'),
('92f2906f-d6f8-4429-85b6-d87e51b76eb0','偈頌一百二十三首  其五二','釋祖欽','宋','宋诗','song-poetry','','[]','解語非干舌，能言不是聲。',24,'全唐诗/poet.song.225000.json','["解語非干舌，能言不是聲。", "碧班班碧剝，當滴帝都丁。"]'),
('23a5d4ee-6b4c-466c-b4c9-289ffde6d0cc','偈頌一百二十三首  其五三','釋祖欽','宋','宋诗','song-poetry','','[]','進則撞頭磕額，退則墮坑落壍。',42,'全唐诗/poet.song.225000.json','["進則撞頭磕額，退則墮坑落壍。", "動則犯手傷鋒，佛法何曾夢見。", "咄，莫道仰山今日無爲人方便。"]'),
('94b794bd-066f-4f53-9724-e75b0f72c17d','偈頌一百二十三首  其五四','釋祖欽','宋','宋诗','song-poetry','','[]','插一莖草建梵剎，捏雙空手豎僧堂。',32,'全唐诗/poet.song.225000.json','["插一莖草建梵剎，捏雙空手豎僧堂。", "古今相去知多少，七尺單前自較量。"]'),
('3b9c41f8-2c92-4fd9-873a-91dcc4d61b91','偈頌一百二十三首  其五五','釋祖欽','宋','宋诗','song-poetry','','[]','暈入靈犀，胎含老蚌。',52,'全唐诗/poet.song.225000.json','["暈入靈犀，胎含老蚌。", "正好修行，正好供養。", "有人於此拂袖便行，脚跟下已喫三十拄杖。", "何以見得，禪歸海，經歸藏。"]'),
('d6ede9e8-bc56-4e81-b367-9abbfd774bd0','偈頌一百二十三首  其五六','釋祖欽','宋','宋诗','song-poetry','','[]','秋風生夜凉，壞壁吟寒螿。',24,'全唐诗/poet.song.225000.json','["秋風生夜凉，壞壁吟寒螿。", "的的祖師意，明明不覆藏。"]'),
('67345c24-2908-4e78-809f-4f019fd12192','偈頌一百二十三首  其五七','釋祖欽','宋','宋诗','song-poetry','','[]','父母未生前，畢竟是什麽。',36,'全唐诗/poet.song.225000.json','["父母未生前，畢竟是什麽。", "當體沒蹤由，求之即蹉過。", "不蹉過，南北東西豈非我。"]'),
('44539b51-dd60-4d74-806b-a7a726e4a288','偈頌一百二十三首  其五八','釋祖欽','宋','宋诗','song-poetry','','[]','秋氣凄清，秋光淡蕩。',24,'全唐诗/poet.song.225000.json','["秋氣凄清，秋光淡蕩。", "鷺鷥飛下遥天，明月蘆花一樣。"]'),
('6c54b224-3fab-4885-a9da-ae92185bcfda','偈頌一百二十三首  其五九','釋祖欽','宋','宋诗','song-poetry','','[]','修造工夫已辨，龍神土地亦安。',28,'全唐诗/poet.song.225000.json','["修造工夫已辨，龍神土地亦安。", "因甚水雲來往，尚如月曉星殘。"]'),
('8e2d5f70-e714-45b5-b2d7-c7cbeac3a3ed','偈頌一百二十三首  其六○','釋祖欽','宋','宋诗','song-poetry','','[]','不冷不熱爐鞴，半真半假金鍮。',28,'全唐诗/poet.song.225000.json','["不冷不熱爐鞴，半真半假金鍮。", "鑄作瓶盤釵釧，却成品字柴頭。"]'),
('7d5766ac-0618-409f-a096-4c468b8706ec','偈頌一百二十三首  其六一','釋祖欽','宋','宋诗','song-poetry','','[]','是法非思量分別之所到，是義非見聞覺知之所造。',56,'全唐诗/poet.song.225000.json','["是法非思量分別之所到，是義非見聞覺知之所造。", "三冬和氣暖烘烘，半夜日頭紅杲杲。", "搭著便回，點即不到，已是無端入荒草。"]'),
('dc561d03-7ff6-49b1-ad51-f17968be1ed1','偈頌一百二十三首  其六二','釋祖欽','宋','宋诗','song-poetry','','[]','火炙胸前暖，風吹背後寒。',24,'全唐诗/poet.song.225000.json','["火炙胸前暖，風吹背後寒。", "西來的的意，親切不相干。"]'),
('684b3128-0f1c-4347-a8ba-fc6fc3dc4325','偈頌一百二十三首  其六三','釋祖欽','宋','宋诗','song-poetry','','[]','好雨知時節，當春乃發生。',38,'全唐诗/poet.song.225000.json','["好雨知時節，當春乃發生。", "倒栽石上無根樹，枝葉通身一夜萌。", "情塵未脫，有眼如盲。"]'),
('b2dfc130-c5ab-490a-aaf4-4b115c08b3dc','偈頌一百二十三首  其六四','釋祖欽','宋','宋诗','song-poetry','','[]','心是根，法是塵，兩種猶如鏡上痕。',40,'全唐诗/poet.song.225000.json','["心是根，法是塵，兩種猶如鏡上痕。", "鏡已破，法不存，疏影橫斜水清淺，暗香浮動月黄昏。"]'),
('7a6cdd54-d577-4475-91a3-f0d56837b668','偈頌一百二十三首  其六五','釋祖欽','宋','宋诗','song-poetry','','[]','南薰入奏，殿閣生凉。',25,'全唐诗/poet.song.225000.json','["南薰入奏，殿閣生凉。", "西來祖意，切忌商量。", "向下文長。"]'),
('7e7d7a8a-b9c9-40e3-a51c-2d49c55515ff','偈頌一百二十三首  其六六','釋祖欽','宋','宋诗','song-poetry','','[]','非闕不知圓，非圓不知闕。',24,'全唐诗/poet.song.225000.json','["非闕不知圓，非圓不知闕。", "圓闕本相因，本無圓與闕。"]'),
('c5743148-ad89-4743-95c4-7ad1be832419','偈頌一百二十三首  其六七','釋祖欽','宋','宋诗','song-poetry','','[]','一棒打不殺，千古阿剌剌。',29,'全唐诗/poet.song.225000.json','["一棒打不殺，千古阿剌剌。", "是阿誰兮名悉達，更問如何兮四月八。"]'),
('0d104e72-95b9-48e6-8f16-59888135bbbf','偈頌一百二十三首  其六八','釋祖欽','宋','宋诗','song-poetry','','[]','禪禪碌碡，道道木頭。',32,'全唐诗/poet.song.225000.json','["禪禪碌碡，道道木頭。", "會得全無巴鼻，不會却有來由，何似雲門六不收。"]'),
('b8c46456-0c30-4109-9823-a4d2599fc692','偈頌一百二十三首  其六九','釋祖欽','宋','宋诗','song-poetry','','[]','坐本無拘，何必曰放。',50,'全唐诗/poet.song.225000.json','["坐本無拘，何必曰放。", "動靜但見一如，日用自然虛曠。", "鵲噪鴉鳴，水綠山青。", "騰騰任運不知名，也是錯認定盤星。"]'),
('9dba2204-6c7e-4016-9b93-897e19b53d42','偈頌一百二十三首  其七○','釋祖欽','宋','宋诗','song-poetry','','[]','有權有實，有照有用。',66,'全唐诗/poet.song.225000.json','["有權有實，有照有用。", "匆匆夏影將殘，颯颯凉飈又動。", "四時代謝，日月如流，萬法乘除，有無似夢。", "獨有老趙州，太惺惺，復懞懂，却道蘿蔔三斤重。"]'),
('2dfc3e10-8410-43d6-9728-251fdf0230b6','偈頌一百二十三首  其七一','釋祖欽','宋','宋诗','song-poetry','','[]','連朝淹黑豆，黑豆已萌芽。',24,'全唐诗/poet.song.225000.json','["連朝淹黑豆，黑豆已萌芽。", "滿地天風起，吹開劫外花。"]'),
('541fbdb1-c645-4af4-8131-80560091fe69','偈頌一百二十三首  其七二','釋祖欽','宋','宋诗','song-poetry','','[]','油油，開口不在舌頭。',43,'全唐诗/poet.song.225000.json','["油油，開口不在舌頭。", "莫莫，滋味看來太薄。", "細思量，休卜度。", "令人常憶老龍牙，手裡把柄木杓。"]'),
('9d3283df-71be-4c17-a161-a5a910028682','偈頌一百二十三首  其七三','釋祖欽','宋','宋诗','song-poetry','','[]','人從興化來，接得劍州信。',46,'全唐诗/poet.song.225000.json','["人從興化來，接得劍州信。", "說道淩霄峰頂碁盤，元是錢王石鏡。", "二十年前一共看，今日重逢，有何照證。"]'),
('735ac4db-b865-47c7-8c36-20153e72988c','偈頌一百二十三首  其七四','釋祖欽','宋','宋诗','song-poetry','','[]','雨中燈，雲中月。',16,'全唐诗/poet.song.225000.json','["雨中燈，雲中月。", "最分明，太皎潔。"]'),
('8b9b7045-f5bd-4e63-ac6a-9b12fe3215a3','偈頌一百二十三首  其七五','釋祖欽','宋','宋诗','song-poetry','','[]','巴陵三轉語，大仰一甌茶。',32,'全唐诗/poet.song.225000.json','["巴陵三轉語，大仰一甌茶。", "有恩成怨恨，無事是讎家。", "杜鵑啼血染山花。"]'),
('8f7d02ab-1fb0-4a16-9b2a-5a040d3d9855','偈頌一百二十三首  其七六','釋祖欽','宋','宋诗','song-poetry','','[]','晨朝喫粥，齋時喫飯，人人盡知有。',34,'全唐诗/poet.song.225000.json','["晨朝喫粥，齋時喫飯，人人盡知有。", "開單展鉢，拈匙放筯，一一不借他人手。"]'),
('63c3dae7-48b7-4f78-828e-ac4c03bbb7b5','偈頌一百二十三首  其七七','釋祖欽','宋','宋诗','song-poetry','','[]','露地白牛黑黑，是處尋他不得。',92,'全唐诗/poet.song.225000.json','["露地白牛黑黑，是處尋他不得。", "山青水綠，似有如無。", "眼見耳聞，依稀彷彿。", "全不顧時，蹄角却在。", "纔動著時，蹤由已沒。", "月下閑將短笛吹，風前休把長繩勒。", "阿呵呵，也奇特，如今趁亦不去，自在東西南北。"]'),
('8d955215-a88e-49e9-a195-33a590bf190f','偈頌一百二十三首  其七八','釋祖欽','宋','宋诗','song-poetry','','[]','市行高下不須疑，問著平人自得知。',32,'全唐诗/poet.song.225000.json','["市行高下不須疑，問著平人自得知。", "紅豆啄殘鸚鵡粒，碧梧棲老鳳凰枝。"]'),
('2e51471b-c707-4209-9581-962a99fd60eb','偈頌一百二十三首  其七九','釋祖欽','宋','宋诗','song-poetry','','[]','雲影重重，山色濛濛。',44,'全唐诗/poet.song.225000.json','["雲影重重，山色濛濛。", "天晴日出，柳綠花紅。", "雲門大師颺下乾屎橛，直得清香遍地，散爲萬物春風。"]'),
('8eb46215-927c-4cb6-adef-31ad53f85ef8','偈頌一百二十三首  其八○','釋祖欽','宋','宋诗','song-poetry','','[]','閏月月望，月即尋常。',20,'全唐诗/poet.song.225000.json','["閏月月望，月即尋常。", "雲埋即闇，雲散即光。"]'),
('c3f2a6c7-e473-4e55-b64d-07748408337f','偈頌一百二十三首  其八一','釋祖欽','宋','宋诗','song-poetry','','[]','插鍬而立，去死十分。',36,'全唐诗/poet.song.225000.json','["插鍬而立，去死十分。", "拔鍬便去，弄鬼精魂。", "山鳥山花笑殺人，慚惶炷此一爐薰。"]'),
('041bd6c8-846b-4113-af36-c99b59293be1','偈頌一百二十三首  其八二','釋祖欽','宋','宋诗','song-poetry','','[]','集雲一關，似乎等閑。',48,'全唐诗/poet.song.225000.json','["集雲一關，似乎等閑。", "看時容易，透時即難。", "森羅萬象，從教側目，三世諸佛，迥絕躋攀。", "一徑古松苔蘚斑。"]'),
('fbac803b-5b09-42e4-84dc-aade479915b2','偈頌一百二十三首  其八三','釋祖欽','宋','宋诗','song-poetry','','[]','東行西行，指天指地。',44,'全唐诗/poet.song.225000.json','["東行西行，指天指地。", "盡謂如來降生，我道魔王出世。", "一棒打殺，貴圖太平。", "時當孟夏，麥綠桑青。"]'),
('f3ea922b-40ec-4a70-a6c0-4bf8cb2fb2f6','偈頌一百二十三首  其八四','釋祖欽','宋','宋诗','song-poetry','','[]','呼六爲五，破二作三。',38,'全唐诗/poet.song.225000.json','["呼六爲五，破二作三。", "眼觀東北，意在西南。", "仰山門下却不用遮般茶飯，佛法不怕爛。"]'),
('5525f254-958e-4511-86d7-4e2b4812eeaa','偈頌一百二十三首  其八五','釋祖欽','宋','宋诗','song-poetry','','[]','眼空東魯，口吸西江。',73,'全唐诗/poet.song.225000.json','["眼空東魯，口吸西江。", "機鋒峻捷，不讓老龐。", "仰山遮裏別無禪道佛法，只有一口吹毛利劍凜凜如霜。", "要爲人剪除毛病，換骨洗腸。", "長憶江南三月裡，鷓鴣啼處百花香。"]'),
('5d590e60-2fd6-4e12-bbce-5af987a62169','偈頌一百二十三首  其八六','釋祖欽','宋','宋诗','song-poetry','','[]','高而無上，低而無下。',41,'全唐诗/poet.song.225000.json','["高而無上，低而無下。", "上下三指，彼此七馬。", "臨濟大師到此咬嚼不破，被黄蘗拄杖再三痛打。"]'),
('4c79cc4c-3b7e-43bb-871b-6734645fbe2c','偈頌一百二十三首  其八七','釋祖欽','宋','宋诗','song-poetry','','[]','成龍者升天，成蛇者攛草。',42,'全唐诗/poet.song.225000.json','["成龍者升天，成蛇者攛草。", "將謂隨一切性任其所適，誰知憤憤悱悱却成煩惱。", "集雲峰高日杲杲。"]'),
('0bba43f6-a1e0-4819-a5f5-f6b9b18fb856','偈頌一百二十三首  其八八','釋祖欽','宋','宋诗','song-poetry','','[]','無憂樹下，右脇誕生。',58,'全唐诗/poet.song.225000.json','["無憂樹下，右脇誕生。", "已是造妖捏怪，那堪七步周行。", "雲門一棒打殺，未爲勦絕。", "看來只好活葬，解脫無底深坑，依前日午打三更。"]'),
('528a88cc-8c6d-4f0b-a81f-f5bee742711f','偈頌一百二十三首  其八九','釋祖欽','宋','宋诗','song-poetry','','[]','九龍吐水，七步周行。',38,'全唐诗/poet.song.225000.json','["九龍吐水，七步周行。", "雲門一棒打殺，正是摩頂授記。", "葛藤枝蔓重生，從教徧地縱橫。"]'),
('d907daea-fdad-4aae-b6ef-c63b6207d881','偈頌一百二十三首  其九○','釋祖欽','宋','宋诗','song-poetry','','[]','有物先天地，無形本寂寥。',24,'全唐诗/poet.song.225000.json','["有物先天地，無形本寂寥。", "能爲萬象主，不逐四時凋。"]'),
('447a8149-97c6-4e2d-92f7-a6a5fece27a3','偈頌一百二十三首  其九一','釋祖欽','宋','宋诗','song-poetry','','[]','天寒人寒，五藴山頭仔細看。',26,'全唐诗/poet.song.225000.json','["天寒人寒，五藴山頭仔細看。", "風動幡動，明眼人前休說夢。"]'),
('8474c9fa-5a2f-4eab-a5d5-ecc83104eeb4','偈頌一百二十三首  其九二','釋祖欽','宋','宋诗','song-poetry','','[]','休擬議，莫商量。',52,'全唐诗/poet.song.225000.json','["休擬議，莫商量。", "無朕兆，絕承當。", "君不見江路野梅無主，自開自落，分外馨香。", "一枝橫亞清波上，引得遊蜂上下忙。"]'),
('e57f8f6e-44c6-4dc8-aab2-40a377eed11e','偈頌一百二十三首  其九三','釋祖欽','宋','宋诗','song-poetry','','[]','坐教直，猛著力。',61,'全唐诗/poet.song.225000.json','["坐教直，猛著力。", "提個狗子佛性無，萬緣俱屏息。", "似銀山，如鐵壁。", "驀然一拶粉碎，天地空，人境忘，寤寐如，死生一。", "萬別千差盡空寂。"]'),
('6e40da24-6a54-49c8-9fc5-126b24f298fa','偈頌一百二十三首  其九四','釋祖欽','宋','宋诗','song-poetry','','[]','元宵令節，且喜天晴。',20,'全唐诗/poet.song.225000.json','["元宵令節，且喜天晴。", "高燒銀燭，照佛光明。"]'),
('55ce226b-b066-48a5-93fc-7a89ffdbc7bc','偈頌一百二十三首  其九五','釋祖欽','宋','宋诗','song-poetry','','[]','盡道先師今日死，誰知今日是生朝。',32,'全唐诗/poet.song.225000.json','["盡道先師今日死，誰知今日是生朝。", "不知却有何憑據，紫柏黄檀一處燒。"]'),
('6e5ffe64-57d4-49c6-987f-d74c79902f76','偈頌一百二十三首  其九六','釋祖欽','宋','宋诗','song-poetry','','[]','晝影當軒夏日長，只知喫粥著衣裳。',32,'全唐诗/poet.song.225000.json','["晝影當軒夏日長，只知喫粥著衣裳。", "光陰倏忽催人老，嫩綠駸駸已過牆。"]'),
('2a0dd5a3-74c8-4024-8304-d1610e977c97','偈頌一百二十三首  其九七','釋祖欽','宋','宋诗','song-poetry','','[]','薰風自南來，殿閣生微凉。',24,'全唐诗/poet.song.225000.json','["薰風自南來，殿閣生微凉。", "諸佛出身處，切忌錯商量。"]'),
('8e2e4fa9-23cf-45e5-88ca-c6078eff5600','偈頌一百二十三首  其九八','釋祖欽','宋','宋诗','song-poetry','','[]','天寒人寒，大寒小寒。',48,'全唐诗/poet.song.225000.json','["天寒人寒，大寒小寒。", "熱則普天匝地熱，寒則普天匝地寒。", "熱不自熱，寒不自寒。", "紅日上三竿，當陽仔細看。"]'),
('50033ed5-febf-49ae-badf-d16a4ba5408e','偈頌一百二十三首  其九九','釋祖欽','宋','宋诗','song-poetry','','[]','只此見聞非見聞，無餘聲色可呈君。',32,'全唐诗/poet.song.225000.json','["只此見聞非見聞，無餘聲色可呈君。", "嶺梅破雪偷開眼，一點清香欲斷魂。"]'),
('b7011994-88be-49fa-96b0-c7c9e79c5e88','偈頌一百二十三首  其一○○','釋祖欽','宋','宋诗','song-poetry','','[]','去歲元宵節，無油不點燈。',24,'全唐诗/poet.song.225000.json','["去歲元宵節，無油不點燈。", "今歲元宵節，有月照危層。"]'),
('9eb4ab59-248b-4b18-ae19-8f9eacccaca1','偈頌一百二十三首  其一○一','釋祖欽','宋','宋诗','song-poetry','','[]','歲舊年新，夜暗晝明，未嘗移易。',78,'全唐诗/poet.song.225000.json','["歲舊年新，夜暗晝明，未嘗移易。", "日遷月化，山青水綠，依舊尋常。", "小盡二十九，大盡三十日，也是鎮州蘿蔔，漢地生薑。", "休咬嚼，沒商量。", "梅花紙帳一爐香，衲被蒙頭春晝長。"]'),
('207965b6-9eaf-4282-aa9e-7c83cc4c9f85','偈頌一百二十三首  其一○二','釋祖欽','宋','宋诗','song-poetry','','[]','春風陌上郎，得錢隨手使。',24,'全唐诗/poet.song.225000.json','["春風陌上郎，得錢隨手使。", "貨物忽相當，撞得恰好子。"]'),
('79d53283-0ebb-4a88-9402-bdf4c38a5a2b','偈頌一百二十三首  其一○三','釋祖欽','宋','宋诗','song-poetry','','[]','湛湛澄澄，孤明歷歷，未是到家消息。',36,'全唐诗/poet.song.225000.json','["湛湛澄澄，孤明歷歷，未是到家消息。", "直饒盡底掀翻，不留朕迹，其奈參天荆棘。"]'),
('57970968-16eb-4914-8e5e-7e3638c3cdd7','偈頌一百二十三首  其一○四','釋祖欽','宋','宋诗','song-poetry','','[]','指天指地，點胸點肋。',32,'全唐诗/poet.song.225000.json','["指天指地，點胸點肋。", "將謂六識未具初生孩兒，元來通身是膽白拈正賊。"]'),
('95686e12-98d5-4a53-be51-849e3702b687','偈頌一百二十三首  其一○五','釋祖欽','宋','宋诗','song-poetry','','[]','久雨不晴，浸爛衲僧鼻孔。',36,'全唐诗/poet.song.225000.json','["久雨不晴，浸爛衲僧鼻孔。", "如何是衲僧鼻孔，浮雲散盡碧天寬，赫赫金盆海裏湧。"]'),
('f6a3ac92-ba61-494b-a385-02de87e3b68a','偈頌一百二十三首  其一○六','釋祖欽','宋','宋诗','song-poetry','','[]','禪，樹止叫喧喧。',46,'全唐诗/poet.song.225000.json','["禪，樹止叫喧喧。", "道，門前風浩浩。", "冷地思量真可笑。", "笑什麽，等閑拾得一顆蘇州梨，看來却是青州棗。"]'),
('a478fddf-353c-48f7-926e-124bf5ba3038','偈頌一百二十三首  其一○七','釋祖欽','宋','宋诗','song-poetry','','[]','九旬禁足，三月護生。',76,'全唐诗/poet.song.225000.json','["九旬禁足，三月護生。", "逗到功成行滿，依前日午三更。", "龍淵水風恬浪靜，獺逕橋霧鎖雲橫。", "去者自去，住者自住，坐者自坐，行者自行。", "杖頭縱有通霄路，且共扶持折脚鐺。"]'),
('e713ded3-ac61-43c7-a4e9-4fef876aeb8b','偈頌一百二十三首  其一○八','釋祖欽','宋','宋诗','song-poetry','','[]','動絃別曲，葉落知秋。',34,'全唐诗/poet.song.225000.json','["動絃別曲，葉落知秋。", "大千沙界，一舉全收。", "一毛頭上師子，示現百億毛頭。"]'),
('2fd634fd-4973-467c-8897-a757a1188890','偈頌一百二十三首  其一○九','釋祖欽','宋','宋诗','song-poetry','','[]','好供養，好修行。',18,'全唐诗/poet.song.225000.json','["好供養，好修行。", "拂袖便去，也不多爭。"]'),
('d54b7ce2-6238-4d00-970f-30480ea0f32b','偈頌一百二十三首  其一一○','釋祖欽','宋','宋诗','song-poetry','','[]','火冷灰寒炭又無，大家兀坐嘴盧都。',32,'全唐诗/poet.song.225000.json','["火冷灰寒炭又無，大家兀坐嘴盧都。", "冷灰堆裡忽豆爆，大地通紅火一爐。"]'),
('47fff799-6b43-49bc-99c4-73615706ef9c','偈頌一百二十三首  其一一一','釋祖欽','宋','宋诗','song-poetry','','[]','覓起處不得，尋覓處無地。',40,'全唐诗/poet.song.225000.json','["覓起處不得，尋覓處無地。", "見色元來見心，見了元來不是。", "是不是，鏡不照鏡兮水不洗水。"]'),
('88dfc601-4f97-4119-906b-18b1f3642f5b','偈頌一百二十三首  其一一二','釋祖欽','宋','宋诗','song-poetry','','[]','法逐心生，心隨法變。',63,'全唐诗/poet.song.225000.json','["法逐心生，心隨法變。", "心法雙忘，千化萬變。", "扇子𨁝跳上三十三天，𡎺著帝釋鼻孔。", "盞子撲落地，楪子成七片。", "雖是一期方便，聞名不如見面。"]'),
('67b08894-da21-4740-a16b-797fc7d604a9','偈頌一百二十三首  其一一三','釋祖欽','宋','宋诗','song-poetry','','[]','澄潭月影，靜夜鐘聲。',32,'全唐诗/poet.song.225000.json','["澄潭月影，靜夜鐘聲。", "不留而照，不待而鳴。", "而亦離聞絕見，非色非聲。"]'),
('ec7af578-4cb6-456f-b5f6-ffcce876c219','偈頌一百二十三首  其一一四','釋祖欽','宋','宋诗','song-poetry','','[]','昏沉散亂，莫非本地風光。',56,'全唐诗/poet.song.225000.json','["昏沉散亂，莫非本地風光。", "絕點純清，正是真常流注。", "非不非，是不是。", "差之毫釐，失之千里。", "幸然無些子事，何須强說道理。"]'),
('0026b4ce-941e-4b65-80d9-55082a62d1f9','偈頌一百二十三首  其一一五','釋祖欽','宋','宋诗','song-poetry','','[]','晷影推移線日長，無言童子自商量。',32,'全唐诗/poet.song.225000.json','["晷影推移線日長，無言童子自商量。", "雖然不是神仙藥，海上傳來第一方。"]'),
('1b9e2eb3-b6e5-4ff1-b933-26df660f4d0f','偈頌一百二十三首  其一一六','釋祖欽','宋','宋诗','song-poetry','','[]','箇事本成現，覓則不可見。',68,'全唐诗/poet.song.225000.json','["箇事本成現，覓則不可見。", "白圭本無瑕，琢磨乃成玷。", "執之以實法，空中生閃電。", "視之以等閑，脚下添紅線。", "若是學道人，好好看方便。", "莫看仙人手中扇。"]'),
('8c93a30e-d19a-4e6d-b87d-8ca9c465dbc1','偈頌一百二十三首  其一一七','釋祖欽','宋','宋诗','song-poetry','','[]','集雲峰頭獨立，仰祝聖壽無極。',35,'全唐诗/poet.song.225000.json','["集雲峰頭獨立，仰祝聖壽無極。", "百千甲子春秋，臣僧今日七十，乙酉正月初一。"]'),
('8604caa3-762c-4d68-b359-c9e9cd4edfee','偈頌一百二十三首  其一一八','釋祖欽','宋','宋诗','song-poetry','','[]','春風蕩蕩，春日熙熙。',79,'全唐诗/poet.song.225000.json','["春風蕩蕩，春日熙熙。", "花開笑面，柳展歡眉。", "處處呢喃紫燕，聲聲睍睆黄鸝。", "麻三斤，乾屎橛，庭前柏樹子，遮裡見得，全理全事，無是無非。", "坐斷集雲峰頂上，大家齊賀太平時。"]'),
('a3130c23-d4b1-435a-92c1-bbce9cd071ac','偈頌一百二十三首  其一一九','釋祖欽','宋','宋诗','song-poetry','','[]','一夜雨聲滴滴，元是簷前雪消。',28,'全唐诗/poet.song.225000.json','["一夜雨聲滴滴，元是簷前雪消。", "冷地令人憶著，相國寺裡芭蕉。"]'),
('0a2c465b-4c19-4db8-89f7-4d1fe5eb7414','偈頌一百二十三首  其一二○','釋祖欽','宋','宋诗','song-poetry','','[]','久雨忽晴，心光發明。',65,'全唐诗/poet.song.225000.json','["久雨忽晴，心光發明。", "團團紅日，寥寥太清。", "非特好曬㫰，亦乃好經營。", "下秧種粟，桑麻漸青，綠楊枝上曉鶑鳴。", "長連牀上，開單展鉢，可煞現成。"]'),
('839a9cc3-e198-429f-b126-1cbf5b70c5d6','偈頌一百二十三首  其一二一','釋祖欽','宋','宋诗','song-poetry','','[]','至化無方，至德有光。',37,'全唐诗/poet.song.225000.json','["至化無方，至德有光。", "遲日江山麗，春風花草香。", "玉壺影裡劫春長，乾坤獨露堂堂。"]'),
('6547f7a1-06f7-480e-b7c5-5153acb8fc2d','偈頌一百二十三首  其一二二','釋祖欽','宋','宋诗','song-poetry','','[]','春山重重，夜雨濛濛。',45,'全唐诗/poet.song.225000.json','["春山重重，夜雨濛濛。", "長連床上，閉眉合眼，睡到曉鐘。", "心也空，法也空，不起第二念，坐斷主人翁。"]'),
('896ad8ef-d848-4dc5-a4e9-a8145df6f885','偈頌一百二十三首  其一二三','釋祖欽','宋','宋诗','song-poetry','','[]','進無前，退無後。',30,'全唐诗/poet.song.225000.json','["進無前，退無後。", "毫髮參差，便成窠臼。", "八月二十五，洞山離查渡。"]'),
('99119ee8-d6ea-4a0c-a23e-c29591f2cc6f','偈頌二首  其一','釋祖欽','宋','宋诗','song-poetry','','[]','面前明暗兩忘時，莽蕩乾坤都不知。',32,'全唐诗/poet.song.225000.json','["面前明暗兩忘時，莽蕩乾坤都不知。", "到此若生毫髮見，依前越國又依稀。"]'),
('f109f650-4ec3-435e-9ba9-55b7b7c6ad7b','偈頌二首  其二','釋祖欽','宋','宋诗','song-poetry','','[]','八十餘人十七州，相看盡是惡冤讎。',32,'全唐诗/poet.song.225000.json','["八十餘人十七州，相看盡是惡冤讎。", "諸方有道不肯學，來共山僧作對頭。"]'),
('1c1cf1aa-5af2-48b8-9061-eb716cacf29a','偈頌七十二首  其一','釋祖欽','宋','宋诗','song-poetry','','[]','無影枝頭一點春，笑他無地可藏身。',32,'全唐诗/poet.song.225000.json','["無影枝頭一點春，笑他無地可藏身。", "黄金自有黄金價，何必和沙賣與人。"]'),
('388adc3e-f3a1-47ae-9459-ab63d6f2f6fb','偈頌七十二首  其二','釋祖欽','宋','宋诗','song-poetry','','[]','西來十萬路迢迢，智鑑當軒影莫逃。',32,'全唐诗/poet.song.225000.json','["西來十萬路迢迢，智鑑當軒影莫逃。", "四海浪平龍睡穩，九霄雲浄鶴飛高。"]'),
('a34a5bb5-94b2-43d9-8537-a7dd288b3b2a','偈頌七十二首  其三','釋祖欽','宋','宋诗','song-poetry','','[]','玉樹瓊林，寶階銀闕。',44,'全唐诗/poet.song.225000.json','["玉樹瓊林，寶階銀闕。", "皓若蘆花，恍然明月。", "直鈎垂釣，自有金鱗上鈎。", "地平如掌，依舊七凹八凸。"]'),
('de9a837e-94bb-479d-b52d-0a2e566573e8','偈頌七十二首  其四','釋祖欽','宋','宋诗','song-poetry','','[]','利刀拈起白如霜，可惜無端成自傷。',32,'全唐诗/poet.song.225000.json','["利刀拈起白如霜，可惜無端成自傷。", "消盡少林三尺雪，古今天地只尋常。"]'),
('0f364b39-44be-469c-af92-aabd3f1dae57','偈頌七十二首  其五','釋祖欽','宋','宋诗','song-poetry','','[]','時勤拂拭與掀翻，錯莫無端認定盤。',32,'全唐诗/poet.song.225000.json','["時勤拂拭與掀翻，錯莫無端認定盤。", "點石化爲金玉易，勸人除却是非難。"]'),
('8b60ed21-2fb6-486f-a890-73cf6276bd05','偈頌七十二首  其六','釋祖欽','宋','宋诗','song-poetry','','[]','三界惟心，萬法惟識。',34,'全唐诗/poet.song.225000.json','["三界惟心，萬法惟識。", "譬如擲劍揮空，莫論及與不及。", "真不掩僞，曲不藏直。"]'),
('585eb8b5-a5e1-4802-9ada-278023cf5943','偈頌七十二首  其七','釋祖欽','宋','宋诗','song-poetry','','[]','兩岸桃花紅欲然，洞中流出自涓涓。',32,'全唐诗/poet.song.225000.json','["兩岸桃花紅欲然，洞中流出自涓涓。", "仙家不曾論春夏，石爛松枯是一年。"]'),
('3f3d629f-5b0c-4def-a370-6d887a26b79e','偈頌七十二首  其八','釋祖欽','宋','宋诗','song-poetry','','[]','堂堂日用妙無痕，纔涉纖毫即是塵。',32,'全唐诗/poet.song.225000.json','["堂堂日用妙無痕，纔涉纖毫即是塵。", "照水銀蟾沉夜魄，戀花香蝶醉芳魂。"]'),
('c04e8285-32bc-4dda-a3c5-0a99fe4c7fd8','偈頌七十二首  其九','釋祖欽','宋','宋诗','song-poetry','','[]','白衣拜相，平地登仙。',20,'全唐诗/poet.song.225000.json','["白衣拜相，平地登仙。", "是人知有，別無秘傳。"]'),
('049d01bf-097b-4ae3-848d-ddf9f356a74f','偈頌七十二首  其一○','釋祖欽','宋','宋诗','song-poetry','','[]','萬法俱忘百念灰，等閑驀鼻拽將囘。',32,'全唐诗/poet.song.225000.json','["萬法俱忘百念灰，等閑驀鼻拽將囘。", "鏡光一照明如日，直得木人心眼開。"]'),
('7c1ab2e7-e496-4adc-8c9f-c1544f96c261','偈頌七十二首  其一一','釋祖欽','宋','宋诗','song-poetry','','[]','語默俱忘非是非，聖凡情盡絕玄微。',32,'全唐诗/poet.song.225000.json','["語默俱忘非是非，聖凡情盡絕玄微。", "穿花蛺蝶深深見，點水蜻蜓款款飛。"]'),
('d1fe853b-cdc3-4534-9c06-9096a244c639','偈頌七十二首  其一二','釋祖欽','宋','宋诗','song-poetry','','[]','言發非聲，色前不物。',44,'全唐诗/poet.song.225000.json','["言發非聲，色前不物。", "當機覿面全提，豈在拈槌豎拂。", "山河大地，不礙眼光，萬象森羅，形端影直。"]'),
('959070a3-c555-48fa-a95a-b5e2f6691b18','偈頌七十二首  其一三','釋祖欽','宋','宋诗','song-poetry','','[]','那下飛來水面浮，却來遮裏問蹤由。',32,'全唐诗/poet.song.225000.json','["那下飛來水面浮，却來遮裏問蹤由。", "只因回首不知處，一捏通身冷汗流。"]'),
('01c7d708-35dd-43c1-afb1-8fbb5b857d05','偈頌七十二首  其一四','釋祖欽','宋','宋诗','song-poetry','','[]','一喝當頭雷電奔，人聞說亦闇消魂。',32,'全唐诗/poet.song.225000.json','["一喝當頭雷電奔，人聞說亦闇消魂。", "看來何止聾三日，直到如今海岳昏。"]'),
('81ef1635-142e-4b0f-9366-ed5ca7922219','偈頌七十二首  其一五','釋祖欽','宋','宋诗','song-poetry','','[]','寰中日月，量外乾坤。',26,'全唐诗/poet.song.225000.json','["寰中日月，量外乾坤。", "舉起也千差萬別，放下也不立纖塵。"]'),
('138daf8b-34b5-4d85-9eda-6493006af32c','偈頌七十二首  其一六','釋祖欽','宋','宋诗','song-poetry','','[]','南山雲起北山雲，上界鐘聲下界聞。',32,'全唐诗/poet.song.225000.json','["南山雲起北山雲，上界鐘聲下界聞。", "遥望衆僧行道處，天香桂子落紛紛。"]'),
('6449ca80-a3e2-48b9-9e3e-9c61ab06e87f','偈頌七十二首  其一七','釋祖欽','宋','宋诗','song-poetry','','[]','發越朕兆，未形消息。',30,'全唐诗/poet.song.225000.json','["發越朕兆，未形消息。", "提持佛祖，未行號令。", "虛空斫額，萬象拱聽。"]'),
('d4b3edde-c181-4c23-944a-ec98d037006d','偈頌七十二首  其一八','釋祖欽','宋','宋诗','song-poetry','','[]','聲前一句蓋諸方，指出乾坤是大唐。',32,'全唐诗/poet.song.225000.json','["聲前一句蓋諸方，指出乾坤是大唐。", "但見皇風成一片，不知何處是封疆。"]'),
('d4d9edbd-82a5-4b57-9c3d-b2860a2c6708','偈頌七十二首  其一九','釋祖欽','宋','宋诗','song-poetry','','[]','擘開太華，放出黄河。',34,'全唐诗/poet.song.225000.json','["擘開太華，放出黄河。", "青天白日，平地風波。", "逗到伎窮力盡，元來所得不多。"]'),
('8728785e-d913-46e5-aabe-ac77c54f5267','偈頌七十二首  其二○','釋祖欽','宋','宋诗','song-poetry','','[]','東君有令不虛行，三頓烏藤大險生。',32,'全唐诗/poet.song.225000.json','["東君有令不虛行，三頓烏藤大險生。", "龍得水時增意氣，虎逢山色長威獰。"]'),
('22a7dbf2-c236-4fed-ba48-fd6680a558fd','偈頌七十二首  其二一','釋祖欽','宋','宋诗','song-poetry','','[]','雨散雲收月正明，無端平地鼓雷霆。',32,'全唐诗/poet.song.225000.json','["雨散雲收月正明，無端平地鼓雷霆。", "慣曾坐斷乾坤客，喚作竅中蚯蚓聲。"]'),
('2fba6634-5866-4287-b345-13cd7b6a9086','偈頌七十二首  其二二','釋祖欽','宋','宋诗','song-poetry','','[]','喫飯著衣，事事成現。',20,'全唐诗/poet.song.225000.json','["喫飯著衣，事事成現。", "俯仰折旋，一見便見。"]'),
('0d1898cd-ca3b-4a1e-9cd6-2a1f5090f420','偈頌七十二首  其二三','釋祖欽','宋','宋诗','song-poetry','','[]','當機覿面黑漫漫，且待輕輕著眼看。',32,'全唐诗/poet.song.225000.json','["當機覿面黑漫漫，且待輕輕著眼看。", "剔起眉毛纔擬議，便爲聞見色聲瞞。"]'),
('918a2239-3e77-4c9f-bc60-8fd10b2bcbbf','偈頌七十二首  其二四','釋祖欽','宋','宋诗','song-poetry','','[]','山花似錦，澗水如藍。',20,'全唐诗/poet.song.225000.json','["山花似錦，澗水如藍。", "面目現在，誰是同參。"]'),
('83b5705e-904c-4f7b-835a-467495fb475f','偈頌七十二首  其二五','釋祖欽','宋','宋诗','song-poetry','','[]','殺活縱橫得自由，懸崖撒手覓冤讎。',32,'全唐诗/poet.song.225000.json','["殺活縱橫得自由，懸崖撒手覓冤讎。", "瞎馿滅却正法眼，射斗寒光夜不收。"]'),
('e5dbd9f9-d5b5-4bf4-a4c7-028a93cde500','偈頌七十二首  其二六','釋祖欽','宋','宋诗','song-poetry','','[]','箭鋒相拄，機栝相投。',30,'全唐诗/poet.song.225000.json','["箭鋒相拄，機栝相投。", "得人一馬，還人一牛，更看靴裏輕輕動指頭。"]'),
('b4d0ec8b-be4f-4a3d-a77d-c6b183107af2','偈頌七十二首  其二七','釋祖欽','宋','宋诗','song-poetry','','[]','劍爲不平離寶匣，藥因救病出金瓶。',32,'全唐诗/poet.song.225000.json','["劍爲不平離寶匣，藥因救病出金瓶。", "南方自古清如鏡，何必無端用甲兵。"]'),
('d4e74e95-3c90-46cd-bf29-ce177255d23b','偈頌七十二首  其二八','釋祖欽','宋','宋诗','song-poetry','','[]','電光莫追，石火猶遲。',25,'全唐诗/poet.song.225000.json','["電光莫追，石火猶遲。", "搆弗及處，心不可識，智不可知。"]'),
('df5ef1c6-2fdc-4772-8901-920a28446d69','偈頌七十二首  其二九','釋祖欽','宋','宋诗','song-poetry','','[]','同時照用不同時，權實雙行作者知。',32,'全唐诗/poet.song.225000.json','["同時照用不同時，權實雙行作者知。", "有得雖然亦有失，還他龍虎自交馳。"]'),
('1502837a-4f6d-45d9-98c4-c2a1b87f2955','偈頌七十二首  其三○','釋祖欽','宋','宋诗','song-poetry','','[]','量外機，格外句。',33,'全唐诗/poet.song.225000.json','["量外機，格外句。", "凡聖迷魂，佛祖罔措。", "有來由，無本據，聲前切忌錯舉。"]'),
('168ff0e5-7c6d-4616-a59e-f7c0c8703321','偈頌七十二首  其三一','釋祖欽','宋','宋诗','song-poetry','','[]','阿師昨日赴村齋，幾被他人一窖埋。',32,'全唐诗/poet.song.225000.json','["阿師昨日赴村齋，幾被他人一窖埋。", "暴雨卒風迴避得，也成平地露屍骸。"]'),
('fccdfa3f-b01a-4a87-af0a-8928b23d9147','偈頌七十二首  其三二','釋祖欽','宋','宋诗','song-poetry','','[]','機奪機，句奪句。',38,'全唐诗/poet.song.225000.json','["機奪機，句奪句。", "覿面相呈，更無回互。", "棒頭有眼，迥出常情，語下無私，如何分付。"]'),
('3835015d-d80e-4d6c-b889-a4c6ea6aebf9','偈頌七十二首  其三三','釋祖欽','宋','宋诗','song-poetry','','[]','同時啐啄不同時，石火電光猶較遲。',32,'全唐诗/poet.song.225000.json','["同時啐啄不同時，石火電光猶較遲。", "燈影裏行今已會，蹉跎非是落便宜。"]'),
('9eff85aa-1d08-4f28-be6f-cdb91d74605f','偈頌七十二首  其三四','釋祖欽','宋','宋诗','song-poetry','','[]','人與境空，境與人會。',20,'全唐诗/poet.song.225000.json','["人與境空，境與人會。", "百尺竿頭，一采兩賽。"]'),
('068fc73c-95b9-46bc-bb87-46231d26c0c1','偈頌七十二首  其三五','釋祖欽','宋','宋诗','song-poetry','','[]','即此見聞非見聞，無餘聲色可呈君。',32,'全唐诗/poet.song.225000.json','["即此見聞非見聞，無餘聲色可呈君。", "箇中若了全無事，體用何妨分不分。"]'),
('dda53fc6-b260-4a7c-a99b-d10797130ca4','偈頌七十二首  其三六','釋祖欽','宋','宋诗','song-poetry','','[]','且看雙放更雙收，有底歡聲無底愁。',32,'全唐诗/poet.song.225000.json','["且看雙放更雙收，有底歡聲無底愁。", "一切聖賢如電拂，大千沙界海中漚。"]'),
('8462c241-be44-4489-9380-4f59daf7fc42','偈頌七十二首  其三七','釋祖欽','宋','宋诗','song-poetry','','[]','聲前句，格外機。',26,'全唐诗/poet.song.225000.json','["聲前句，格外機。", "無得無失，無是無非。", "無孔由來是鐵鎚。"]'),
