('cc1eea22-4fc9-47da-bd62-e09cf4b589ca','偈頌七十二首  其三九','釋祖欽','宋','宋诗','song-poetry','','[]','巇嶮中平實，平實處誵訛。',26,'全唐诗/poet.song.225000.json','["巇嶮中平實，平實處誵訛。", "覿面承當得去，元來用處不多。"]'),
('405b307a-2f3b-4ea5-b599-41bfdc1c959e','偈頌七十二首  其四○','釋祖欽','宋','宋诗','song-poetry','','[]','暑往寒來春復秋，夕陽西去水東流。',32,'全唐诗/poet.song.225000.json','["暑往寒來春復秋，夕陽西去水東流。", "茫茫宇宙人無數，那箇親曾到地頭。"]'),
('009283e7-3739-4727-92b5-f71d59e0c460','偈頌七十二首  其四一','釋祖欽','宋','宋诗','song-poetry','','[]','當陽拈起足清風，似月團團樣不同。',32,'全唐诗/poet.song.225000.json','["當陽拈起足清風，似月團團樣不同。", "臘月也知無用處，暑天消得打蚊蟲。"]'),
('7794cc96-e5ab-4ea6-80ec-a2205e79c522','偈頌七十二首  其四二','釋祖欽','宋','宋诗','song-poetry','','[]','上無敵，下無比。',36,'全唐诗/poet.song.225000.json','["上無敵，下無比。", "擬議思量，劍去久矣。", "見得親，用得到。", "信手拈來，又却恰好。"]'),
('d01f6763-53a9-40f2-9aac-5f2715d4d2a9','偈頌七十二首  其四三','釋祖欽','宋','宋诗','song-poetry','','[]','步行騎水牛，空手把鋤頭。',54,'全唐诗/poet.song.225000.json','["步行騎水牛，空手把鋤頭。", "人從橋上過，橋流水不流。", "一理足，萬事周。", "一塵起，大地收。", "機先別有活路，開口不在舌頭。"]'),
('7160b649-1030-4738-98cd-482f66c75806','偈頌七十二首  其四四','釋祖欽','宋','宋诗','song-poetry','','[]','老杜風前得句時，等閑開口便成詩。',32,'全唐诗/poet.song.225000.json','["老杜風前得句時，等閑開口便成詩。", "就中一著沒巴鼻，却把馿兒當馬騎。"]'),
('a96ed827-9fe1-4689-b7c4-46993926587d','偈頌七十二首  其四五','釋祖欽','宋','宋诗','song-poetry','','[]','動即影現，覺即冰生。',20,'全唐诗/poet.song.225000.json','["動即影現，覺即冰生。", "見聞俱盡，視聽如盲。"]'),
('5725f167-323d-425e-9555-829a71a142b7','偈頌七十二首  其四六','釋祖欽','宋','宋诗','song-poetry','','[]','一掬澄潭鏡樣磨，無風何必自生波。',32,'全唐诗/poet.song.225000.json','["一掬澄潭鏡樣磨，無風何必自生波。", "轉身縱不離初際，仔細看來較幾何。"]'),
('0fce2f50-ad42-4841-8b43-3122956ec50b','偈頌七十二首  其四七','釋祖欽','宋','宋诗','song-poetry','','[]','本無位次，不涉安排。',20,'全唐诗/poet.song.225000.json','["本無位次，不涉安排。", "泯然自盡，一種平懷。"]'),
('0167a165-d5d1-499e-a988-15d9b5ea7ce3','偈頌七十二首  其四八','釋祖欽','宋','宋诗','song-poetry','','[]','平常閑坐與閑行，嶺上無心雲片生。',32,'全唐诗/poet.song.225000.json','["平常閑坐與閑行，嶺上無心雲片生。", "照鏡俱亡人不立，依前日午打三更。"]'),
('b3e6c681-828f-4193-8e86-68305522de8e','偈頌七十二首  其四九','釋祖欽','宋','宋诗','song-poetry','','[]','樹頭金果鐵團欒，千聖猶難著眼看。',32,'全唐诗/poet.song.225000.json','["樹頭金果鐵團欒，千聖猶難著眼看。", "莫謂臨機曾掇退，當陽托出已和盤。"]'),
('a7b91f94-3ace-4562-84d9-175c27796f28','偈頌七十二首  其五○','釋祖欽','宋','宋诗','song-poetry','','[]','虛而靈，空而妙。',32,'全唐诗/poet.song.225000.json','["虛而靈，空而妙。", "冷而看，默而照。", "亭亭雪，沒青松，杳杳雲，藏白鳥。"]'),
('b0d1af45-eb88-495f-b1fa-fcad57a80f05','偈頌七十二首  其五一','釋祖欽','宋','宋诗','song-poetry','','[]','洪蒙未判絕疏親，畢竟難將事理分。',32,'全唐诗/poet.song.225000.json','["洪蒙未判絕疏親，畢竟難將事理分。", "夜半正明還不露，金剛腦後鐵崑崙。"]'),
('29540c64-a79a-4293-a112-a7930facba17','偈頌七十二首  其五二','釋祖欽','宋','宋诗','song-poetry','','[]','雲重重又水重重，步不曾移到九峰。',32,'全唐诗/poet.song.225000.json','["雲重重又水重重，步不曾移到九峰。", "遠涉若還言不易，主人却在半途中。"]'),
('74795d30-f6fc-4876-8bf1-53c2de5af68b','偈頌七十二首  其五三','釋祖欽','宋','宋诗','song-poetry','','[]','石女高歌木人和，妙用縱橫無不可。',32,'全唐诗/poet.song.225000.json','["石女高歌木人和，妙用縱橫無不可。", "三更初夜月明前，開口幾人曾蹉過。"]'),
('318f69f0-1e8c-4b04-901d-0381c66398c8','偈頌七十二首  其五四','釋祖欽','宋','宋诗','song-poetry','','[]','白玉階前金鳳舞，黄金殿上玉雞鳴。',32,'全唐诗/poet.song.225000.json','["白玉階前金鳳舞，黄金殿上玉雞鳴。", "正中來與兼中到，昨夜雲深月正明。"]'),
('bf8e6381-5b21-48c7-a89c-16812b17723e','偈頌七十二首  其五五','釋祖欽','宋','宋诗','song-poetry','','[]','雲藏無縫襖，花綻不萌枝。',30,'全唐诗/poet.song.225000.json','["雲藏無縫襖，花綻不萌枝。", "銅壺漏靜，玉戶春熙。", "敢問時人知不知。"]'),
('2c58175f-b9d4-489b-ae0c-9efe86b11e32','偈頌七十二首  其五六','釋祖欽','宋','宋诗','song-poetry','','[]','天黑雲深飛暮鴉，鷺鷥立雪對蘆花。',32,'全唐诗/poet.song.225000.json','["天黑雲深飛暮鴉，鷺鷥立雪對蘆花。", "幸然不屬今時事，句後聲前會即差。"]'),
('8ab7ea7b-c4b2-4d26-be18-ca0563ebe50e','偈頌七十二首  其五七','釋祖欽','宋','宋诗','song-poetry','','[]','內紹外紹，有偏有正。',18,'全唐诗/poet.song.225000.json','["內紹外紹，有偏有正。", "失曉老婆逢古鏡。"]'),
('6ed6b837-9b85-4355-9411-ead979ea5b4d','偈頌七十二首  其五八','釋祖欽','宋','宋诗','song-poetry','','[]','鷺鷥立雪非同色，明月蘆花不似他。',32,'全唐诗/poet.song.225000.json','["鷺鷥立雪非同色，明月蘆花不似他。", "若作龍生龍子會，目前一路已千差。"]'),
('80508ca6-7cd7-4d1f-b278-b3c19b6034a1','偈頌七十二首  其五九','釋祖欽','宋','宋诗','song-poetry','','[]','聲色無依，見聞不立。',22,'全唐诗/poet.song.225000.json','["聲色無依，見聞不立。", "渡水問魚踪，過山尋蟻跡。"]'),
('6a8f4637-c2ae-434a-bc34-4845a32d8d67','偈頌七十二首  其六○','釋祖欽','宋','宋诗','song-poetry','','[]','動弦別曲古今稀，覿面相呈第二機。',32,'全唐诗/poet.song.225000.json','["動弦別曲古今稀，覿面相呈第二機。", "祖父不曾離正位，一簾化日自遲遲。"]'),
('77e394a3-494e-4e79-a8cc-9e16ab7295a0','偈頌七十二首  其六一','釋祖欽','宋','宋诗','song-poetry','','[]','動即影現，拂即成痕。',20,'全唐诗/poet.song.225000.json','["動即影現，拂即成痕。", "聽其自在，萬法無根。"]'),
('75ff9178-eadf-4d17-8f82-ad3d9e4b6f9f','偈頌七十二首  其六二','釋祖欽','宋','宋诗','song-poetry','','[]','玄路絕時分鳥道，見聞泯處涉功勳。',32,'全唐诗/poet.song.225000.json','["玄路絕時分鳥道，見聞泯處涉功勳。", "何如只麽閑閑地，月浸冰壺夜不痕。"]'),
('2fb3c5e0-260f-4a8f-8348-d158df8d3753','偈頌七十二首  其六三','釋祖欽','宋','宋诗','song-poetry','','[]','形名未立，朕兆未分。',20,'全唐诗/poet.song.225000.json','["形名未立，朕兆未分。", "全無巴鼻，徹底渾崙。"]'),
('e2c9d9ee-226a-40f5-996d-db8ae68b1047','偈頌七十二首  其六四','釋祖欽','宋','宋诗','song-poetry','','[]','層層落落影團團，切忌當陽著眼看。',32,'全唐诗/poet.song.225000.json','["層層落落影團團，切忌當陽著眼看。", "直下有無俱不立，白漫漫又黑漫漫。"]'),
('cd35e191-3011-4e8b-9452-c24478e4df11','偈頌七十二首  其六五','釋祖欽','宋','宋诗','song-poetry','','[]','行也是，坐也是。',18,'全唐诗/poet.song.225000.json','["行也是，坐也是。", "俯仰折旋，無是不是。"]'),
('78570260-69e1-4aed-8cb7-0470a242d723','偈頌七十二首  其六六','釋祖欽','宋','宋诗','song-poetry','','[]','道箇爐中無火時，一團冷焰正騰輝。',32,'全唐诗/poet.song.225000.json','["道箇爐中無火時，一團冷焰正騰輝。", "深深撥出一星子，未免翻成節外枝。"]'),
('5b155936-2be1-406d-b3e2-256ac6fb8c15','偈頌七十二首  其六七','釋祖欽','宋','宋诗','song-poetry','','[]','寸長尺短，三平二滿。',20,'全唐诗/poet.song.225000.json','["寸長尺短，三平二滿。", "覿面相呈，語言道斷。"]'),
('57231855-3779-49f5-9150-b78f338de316','偈頌七十二首  其六八','釋祖欽','宋','宋诗','song-poetry','','[]','岸草青青得自由，等閑牽著便昂頭。',32,'全唐诗/poet.song.225000.json','["岸草青青得自由，等閑牽著便昂頭。", "通身露地一般白，莫是山前水牯牛。"]'),
('8a91e9d3-be9d-41de-af0e-483528d48927','偈頌七十二首  其六九','釋祖欽','宋','宋诗','song-poetry','','[]','一有多種，二無兩般。',20,'全唐诗/poet.song.225000.json','["一有多種，二無兩般。", "鈎頭識取，莫認定盤。"]'),
('9c71079c-4abf-4dfe-bf34-453c9a0e490d','偈頌七十二首  其七○','釋祖欽','宋','宋诗','song-poetry','','[]','何須特地弄精魂，摘葉尋枝我不能。',32,'全唐诗/poet.song.225000.json','["何須特地弄精魂，摘葉尋枝我不能。", "固是話頭成兩橛，不妨同玩雨前春。"]'),
('11345c72-9288-472b-a1b5-3ddde14722c2','偈頌七十二首  其七一','釋祖欽','宋','宋诗','song-poetry','','[]','覿面提來付與伊，分明此意沒東西。',32,'全唐诗/poet.song.225000.json','["覿面提來付與伊，分明此意沒東西。", "腕頭有力千鈞重，誰道通身是水泥。"]'),
('13bdb162-1540-4bbf-bc01-d7a9633be50c','偈頌七十二首  其七二','釋祖欽','宋','宋诗','song-poetry','','[]','一種平懷，泯然自盡。',20,'全唐诗/poet.song.225000.json','["一種平懷，泯然自盡。", "明闇情忘，事理平等。"]'),
('d3321319-953a-4664-9cae-b2c0b01e778f','偈頌七十二首  其七三','釋祖欽','宋','宋诗','song-poetry','','[]','一杯晴雪早茶香，午睡方醒春晝長。',32,'全唐诗/poet.song.225000.json','["一杯晴雪早茶香，午睡方醒春晝長。", "拶著通身俱是眼，半窗疏影轉斜陽。"]'),
('05e161e3-3f0b-41bb-9545-c3adda244f2e','靜山偈','釋祖欽','宋','宋诗','song-poetry','','[]','一跡無餘萬籟沈，巒光月色共深深。',32,'全唐诗/poet.song.225000.json','["一跡無餘萬籟沈，巒光月色共深深。", "誰知尚有些兒閙，龍在霜枯木裏吟。"]'),
('993cebe9-6947-425b-8f23-2244aa1e49b1','秋江偈','釋祖欽','宋','宋诗','song-poetry','','[]','漾漾銀河玉宇流，浄如白練冷光浮。',32,'全唐诗/poet.song.225000.json','["漾漾銀河玉宇流，浄如白練冷光浮。", "老胡一葦踏不著，零落西風斷岸頭。"]'),
('ecd5d120-420c-4b78-820a-7f5789e55cbe','送德富藏主之衡','釋祖欽','宋','宋诗','song-poetry','','[]','集雲雲外小睡虎，毛色金斑威百步。',66,'全唐诗/poet.song.225000.json','["集雲雲外小睡虎，毛色金斑威百步。", "頂門正眼爍乾坤，等閑亦或生風雨。", "拂曉出門去何處，衡陽城中訪親故。", "記之早晚即歸來，震雷一喝了此末後句。"]'),
('b188845e-e1b2-45ed-bca0-5f7b0ac61762','送光後堂','釋祖欽','宋','宋诗','song-poetry','','[]','春風惡，春風惡，一夜梅花盡吹落。',54,'全唐诗/poet.song.225000.json','["春風惡，春風惡，一夜梅花盡吹落。", "人來話別欲游吳，踏斷東南天一角。", "春風惡，春風惡，八千里外望西川，從前都是錯。"]'),
('a79c68fe-a4b5-4ff6-a1d9-485035b94a49','宗正上人','釋祖欽','宋','宋诗','song-poetry','','[]','金襴之外傳何物，應道門前倒剎竿。',96,'全唐诗/poet.song.225000.json','["金襴之外傳何物，應道門前倒剎竿。", "亙古亙今全提句，好向聲前著眼看。", "衲僧衣鉢只者是，汝今已得正宗旨。", "寄集雲單號別傳，枚數英才先屈指。", "忽來告假歸清江，窗前梅早春漸芳。", "一枝橫出蒼烟外，泉聲噴雪巖流香。"]'),
('cb3b7d2c-4f24-47ae-8bfd-7edd3a044539','惠洪上人','釋祖欽','宋','宋诗','song-poetry','','[]','洪濛既判，惠然紅日。',108,'全唐诗/poet.song.225000.json','["洪濛既判，惠然紅日。", "天地開明，即心是佛。", "塵沙剎海，遍界發輝。", "一絲毫頭，昧之不得。", "却須直下掀翻，休爲知見所執。", "受用只此平常，更無玄妙奇特。", "若是衲僧門下，難免痛棒三十。", "目今且贈四藤，任便東西南北。", "回首集雲峰，面前青突兀。"]'),
('dc0b966d-378e-40cb-96c5-809229720a2d','送契寧上人','釋祖欽','宋','宋诗','song-poetry','','[]','道契佛祖，身自康寧。',52,'全唐诗/poet.song.225000.json','["道契佛祖，身自康寧。", "行篤言寡，名香德馨。", "一塵不染，千里前程。", "番陽浩浩，集雲青青。", "穩泛扁舟短櫂，西風浪平。"]'),
('b3896146-9fc0-4cad-a67e-9525dc6cfdbe','紹隆上人','釋祖欽','宋','宋诗','song-poetry','','[]','行以德紹，道以時隆。',82,'全唐诗/poet.song.225000.json','["行以德紹，道以時隆。", "浮薄在彼，端確在躬。", "衣單下事還一同，道德言行誠明中。", "語默動靜昭日月，折旋俯仰生春風。", "上人夏在集雲峰，倏起湘江歸興濃。", "庭前索索飄井桐，赤肩擔瘦筇。"]'),
('5fa0fffd-9e0a-455b-816f-e7a6fb3444f9','真惠上人','釋祖欽','宋','宋诗','song-poetry','','[]','將謂如來，惠戒三昧。',68,'全唐诗/poet.song.225000.json','["將謂如來，惠戒三昧。", "此語雖真，此意未在。", "正似湘江兩半晴，岳面不開雲靉靆。", "一日升天四海明，杖頭掀轉却頭輕。", "不移跬步到潭城，相逢歷歷話前程。"]'),
('574e120d-dc61-4875-99f5-b1ae6c32f803','本來上人','釋祖欽','宋','宋诗','song-poetry','','[]','本不曾來亦不去，百二十日如是住。',64,'全唐诗/poet.song.225000.json','["本不曾來亦不去，百二十日如是住。", "昨夜西風忽轉頭，花開闌畔木犀樹。", "收拾行囊話起單，集雲東湖來去間。", "雙桂枝頭冷消息，却與荷花香一般。"]'),
('ea350279-a53b-4ba1-b76e-5bab2818ce4a','慶一上人','釋祖欽','宋','宋诗','song-poetry','','[]','識得一，萬事畢，慶快平生是今日。',78,'全唐诗/poet.song.225000.json','["識得一，萬事畢，慶快平生是今日。", "佛祖單傳無二心，生死洞然空四壁。", "匆匆聞訃來歸，不礙獨行特立。", "群峰疊亂青，遠水漾虛碧。", "寥寥天地間，來去有何極，韶華自轉春無迹。"]'),
('5eed7987-bb07-49dc-b859-b776bb62fc83','了恩典座','釋祖欽','宋','宋诗','song-poetry','','[]','十二時中，承誰恩力。',56,'全唐诗/poet.song.225000.json','["十二時中，承誰恩力。", "俯仰折旋，不須外覓。", "著衣喫飯，一了便了。", "開眼天明，是誰不曉。", "大地沙門隻眼睛，丈六金身一莖草。"]'),
('9776636d-76ef-4c76-8acc-0c49725e2ea3','志滿上人','釋祖欽','宋','宋诗','song-poetry','','[]','夫志在謙毋自滿，勿以其長跨人短。',65,'全唐诗/poet.song.225000.json','["夫志在謙毋自滿，勿以其長跨人短。", "海因有量天亦聾，人未有德休恃聰。", "君不見水涸山枯物憔悴，春暖風和蝶蜂至。", "欲在叢林立此身，學以成其志。"]'),
('4385e756-a068-4a94-af5f-283c4b2204de','祖機上人','釋祖欽','宋','宋诗','song-poetry','','[]','靈妙之機，佛祖莫知。',50,'全唐诗/poet.song.225000.json','["靈妙之機，佛祖莫知。", "疾則蹉過，遲非所宜。", "靈在自己，妙在日用。", "喫飯著衣，一靜一動。", "動靜兩忘，波停岳聳。"]'),
('939e36da-c477-4bb5-bb55-e87bffd49ac6','元覺上人','釋祖欽','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','妙覺明浄，元無所覺。',52,'全唐诗/poet.song.225000.json','["妙覺明浄，元無所覺。", "如鄱陽湖，秋波不作。", "亦若匡廬，雲平月壑。", "笠頂西風閑去來，拄杖頭邊空索索，打碎靈龜殻。"]'),
('11b183b6-17b8-4792-8190-07e35e08e804','智遠上人','釋祖欽','宋','宋诗','song-poetry','','[]','智聰則遠，機圓自轉。',57,'全唐诗/poet.song.225000.json','["智聰則遠，機圓自轉。", "似走盤珠，如萬花苑。", "開落不在春秋，動靜不滯去留。", "雲悠悠，水悠悠。", "天外月如鈎，雪峰衮出三箇木毬。"]'),
('dd9b7227-7cae-4252-bc10-799a894f62d6','克圓上人','釋祖欽','宋','宋诗','song-poetry','','[]','克期取證，功行已圓。',49,'全唐诗/poet.song.225000.json','["克期取證，功行已圓。", "湘南潭北，一月在天。", "五峰深處，萬象皎然。", "相見不須撫背，痛與肋下三拳，掣風掣顛。"]'),
('21ec41d0-c35c-4aa4-aff2-badfe0563c28','覺初上人','釋祖欽','宋','宋诗','song-poetry','','[]','靈覺之初，廓然太虛。',57,'全唐诗/poet.song.225000.json','["靈覺之初，廓然太虛。", "巘雲平岳頂，海月照珊瑚。", "描不如，畫不如，詠不如，一段靈光今古無。", "元是兜率橋頭，三生藏裏夜明珠。"]'),
('711fcd46-1a3c-4330-b0b9-1f60ee54c57a','道可道者','釋祖欽','宋','宋诗','song-poetry','','[]','道可道，非常道。',79,'全唐诗/poet.song.225000.json','["道可道，非常道。", "名可名，非常名。", "名既非常，如器中鍠。", "道既非常，如日之光。", "如器中鍠，聲出於內。", "如日之光，光照無方。", "夫如是乃可稱有道之者，非獨善一身，而達之萬邦。"]'),
('35badc24-69ef-4c7e-9657-84733fe07795','道從上人','釋祖欽','宋','宋诗','song-poetry','','[]','惟道是從，惟心是宗。',50,'全唐诗/poet.song.225000.json','["惟道是從，惟心是宗。", "空即是色，色即是空。", "夢幻了了，來去匆匆。", "水中之月，樹上之風。", "作如是觀，無塞不通。"]'),
('da8c58cc-4dde-4ea7-9f9f-d213b99f1e7d','了明上人','釋祖欽','宋','宋诗','song-poetry','','[]','了明明了，孤光皎皎。',66,'全唐诗/poet.song.225000.json','["了明明了，孤光皎皎。", "夜永月寒，雲開天曉。", "二浙江山拄杖頭，脫略根塵靜悄悄。", "大明當空，無幽不照。", "如是行脚，行脚事了。", "百煉精金，由指而遶。"]'),
('4df9e663-1e1f-4094-9583-76aad3969c2e','智賢上人','釋祖欽','宋','宋诗','song-poetry','','[]','智者必賢，正者不偏。',40,'全唐诗/poet.song.225000.json','["智者必賢，正者不偏。", "平坦性地，朗我心天。", "折旋俯仰，諸佛現前。", "一光同照，萬象樅然。"]'),
('20ef3f26-1330-4c43-bde5-fa633b1f7a20','本善上人','釋祖欽','宋','宋诗','song-poetry','','[]','本來面目，善自參詳。',43,'全唐诗/poet.song.225000.json','["本來面目，善自參詳。", "六般神用，晝夜放光。", "不須擬議，切忌承當。", "風前一陣木犀香，金粟花黄。"]'),
('084f102a-0f87-4ec8-a79b-4c7dc080f101','行坦上人','釋祖欽','宋','宋诗','song-poetry','','[]','細行循循，大道坦坦。',73,'全唐诗/poet.song.225000.json','["細行循循，大道坦坦。", "得處至要，用處至簡。", "從上一千七百人，七縱八橫，大機大用。", "肩上無過擔片橫版，頂門只具一隻正眼。", "譬如斬一握絲，一斬俱斬，一切盡斬。"]'),
('edfae7c8-609d-4085-9905-9479ffa49bb3','普義上人','釋祖欽','宋','宋诗','song-poetry','','[]','雲門普，趙州無。',53,'全唐诗/poet.song.225000.json','["雲門普，趙州無。", "二字一義，茄子落蘇。", "提起便會，直入聖賢閫域。", "聲前擬議，未免者也之乎。", "且聽端的下箇註脚，俱。"]'),
('bbed4d26-a576-49b1-9101-c969ac5c8a0d','如珠上人','釋祖欽','宋','宋诗','song-poetry','','[]','等閑剔出影團團，一一如珠走玉盤。',66,'全唐诗/poet.song.225000.json','["等閑剔出影團團，一一如珠走玉盤。", "風前燦燦寶光寒，落落誰從轉處看。", "當隨機括動，休被眼睛瞞，魚目光生也一般。", "天上蟾蜍水底浴，明暗不相干。"]'),
('cbf36900-cbf7-45a4-99f1-08876cbb358b','法立上人','釋祖欽','宋','宋诗','song-poetry','','[]','萬法無根，從何而立。',46,'全唐诗/poet.song.225000.json','["萬法無根，從何而立。", "一念心堅，銀山鐵壁。", "發大誓願，大解脫幢。", "萬木生秋風自凉，庭前一陣桂花香。"]'),
('0f0b00ed-8599-472f-b455-739421446902','法茂上人','釋祖欽','宋','宋诗','song-poetry','','[]','野鳥山花能說法，茂林脩竹是參徒。',59,'全唐诗/poet.song.225000.json','["野鳥山花能說法，茂林脩竹是參徒。", "時常舉一箇心字，覿面當機見也無。", "雲埋夜月，冰透玉壺。", "明暗雙忘，理事一如，差乎緣木求魚。"]'),
('04ab26b9-0cb5-4762-a668-e2c553f2dc8e','允寬上人','釋祖欽','宋','宋诗','song-poetry','','[]','初無允諾，寬著程限。',48,'全唐诗/poet.song.225000.json','["初無允諾，寬著程限。", "一似跳黄河，盡力要合眼。", "跳過跳不過，直要橫擔板。", "南北天高雲淡淡，漁歌秋色晚。"]'),
('4050e3de-cf4c-4f0e-9604-2ccd1294fad1','嗣牧上人','釋祖欽','宋','宋诗','song-poetry','','[]','先以放，嗣以牧。',56,'全唐诗/poet.song.225000.json','["先以放，嗣以牧。", "兩鼻穿，四蹄禿。", "有闌圈，無拘束。", "山自青，水自綠。", "從來饑飽不相干，幻泡影中休碌碌，單單贏得這題目。"]'),
('1ef4c239-142a-41c9-aa91-29f52e24e7d9','惠性上人','釋祖欽','宋','宋诗','song-poetry','','[]','惠性忽通，差別無礙。',60,'全唐诗/poet.song.225000.json','["惠性忽通，差別無礙。", "七縱八橫，得大自在。", "向微塵裏轉渾身，影落五湖雲水外。", "問時人，會不會。", "明白一句子，卞璧無瑕，驪珠絕纇。"]'),
('2a32b455-e181-4114-a844-de30b5a2934d','傳義上人','釋祖欽','宋','宋诗','song-poetry','','[]','直指之道，義不可傳。',55,'全唐诗/poet.song.225000.json','["直指之道，義不可傳。", "不立文字，昭昭現前。", "萬里不掛片雲，一亙白日青天。", "聲前有意，句後無言。", "理事雙遣也，木頭碌碡。"]'),
('bdadeb4c-52fa-4213-8f33-c82fdad98e6f','如山上人','釋祖欽','宋','宋诗','song-poetry','','[]','絕毫絕釐，如山如岳。',64,'全唐诗/poet.song.225000.json','["絕毫絕釐，如山如岳。", "萬里高飛，遥空一鶚。", "見不到處，天涯海角。", "智不及處，大圓滿覺。", "西風蕭條黄葉落，古殿深沈撼金鐸，却悔當初賺行脚。"]'),
('44f2f1c6-59f5-40d7-a6c7-14921a8e56b4','師亮禪者','釋祖欽','宋','宋诗','song-poetry','','[]','憶昔西山亮座主，曾有虛空解講語。',64,'全唐诗/poet.song.225000.json','["憶昔西山亮座主，曾有虛空解講語。", "喚得回頭是馬師，規鑒叢林照千古。", "上人學禪不學教，禪教初無二門戶。", "一拳打破太虛空，知音不在頻頻舉。"]'),
('9fad28ac-04c6-4bff-849f-86cd112aa1c3','出山相贊','釋祖欽','宋','宋诗','song-poetry','','[]','六年饑餓，半夜癡狂。',22,'全唐诗/poet.song.225000.json','["六年饑餓，半夜癡狂。", "貧兒拾得錫，赤脚走忙忙。"]'),
('46bbc4b0-c63a-47bd-b06f-672649bb16f9','觀音贊二首  其一','釋祖欽','宋','宋诗','song-poetry','','[]','鰲翔海運，地迥天空。',30,'全唐诗/poet.song.225000.json','["鰲翔海運，地迥天空。", "一瓶浄水，五濁惡風。", "安得衆生界具證圓通。"]'),
('b8637255-1ca1-4c03-81c9-ef84ea13d7a2','觀音贊二首  其二','釋祖欽','宋','宋诗','song-poetry','','[]','以耳返觀，夜濤傳別谷之聲。',47,'全唐诗/poet.song.225000.json','["以耳返觀，夜濤傳別谷之聲。", "以眼返聽，甘露散垂楊之碧。", "所返既忘，觀聽亦寂。", "夫是之謂救苦慈悲願力。"]'),
('c4c47581-5fb3-40d0-9e8a-53bf77a9f7d2','魚籃婦贊二首  其一','釋祖欽','宋','宋诗','song-poetry','','[]','行步輕盈，梳裝濟楚。',36,'全唐诗/poet.song.225000.json','["行步輕盈，梳裝濟楚。", "示大慈悲，救衆生苦。", "智眼堪憐盡不明，只道籃中賣錦鱗。"]'),
('eecb1f44-b666-4483-86bb-544ae40310b1','魚籃婦贊二首  其二','釋祖欽','宋','宋诗','song-poetry','','[]','籃裏清風，手頭生活。',35,'全唐诗/poet.song.225000.json','["籃裏清風，手頭生活。", "要將魚目換明珠，豈是慈悲菩薩。", "有智慧人，不消一劄。"]'),
('f3025860-0027-4ce8-acc0-c87e2178413c','馬郎婦','釋祖欽','宋','宋诗','song-poetry','','[]','謾說教人學誦經，胸中涇渭甚分明。',32,'全唐诗/poet.song.225000.json','["謾說教人學誦經，胸中涇渭甚分明。", "金沙影裏無窮數，散作一灘流水聲。"]'),
('05bceba0-54eb-4b64-ae2f-3d053c0007ce','維摩贊','釋祖欽','宋','宋诗','song-poetry','','[]','尪羸面孔，蹊蹺肚腸。',32,'全唐诗/poet.song.225000.json','["尪羸面孔，蹊蹺肚腸。", "憂愁苦惱，詐病在床。", "說離生死妙法，一默無雙。"]'),
('bf94dc47-7ba6-456d-855e-13e239ad5b2e','達磨贊','釋祖欽','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','九年壁觀顯家風，半是真誠半脫空。',32,'全唐诗/poet.song.225000.json','["九年壁觀顯家風，半是真誠半脫空。", "一葦不知何處在，長江依舊水流東。"]'),
('23ec4f67-0b4a-482e-acbe-776d6fb8ee8f','布袋贊','釋祖欽','宋','宋诗','song-poetry','','[]','一笑生春風，雙瞳湛秋水。',36,'全唐诗/poet.song.225000.json','["一笑生春風，雙瞳湛秋水。", "日月拄杖頭，乾坤布袋裏。", "彌勒忽然下生，何處尋你。"]'),
('6bbf6b3a-b5ea-4e5c-bc58-a3d381e73497','臨濟贊','釋祖欽','宋','宋诗','song-poetry','','[]','眼生三角，頭峭五嶽，三遭瞎棒折馿腰。',28,'全唐诗/poet.song.225000.json','["眼生三角，頭峭五嶽，三遭瞎棒折馿腰。", "一喝當空，星斗落錯。"]'),
('bdc05e44-d823-409c-be8b-36a275a1fe9f','朝陽贊二首  其一','釋祖欽','宋','宋诗','song-poetry','','[]','穴鼻針，無縫襖。',20,'全唐诗/poet.song.225000.json','["穴鼻針，無縫襖。", "一綫紅日頭，聯得似恰好。"]'),
('6cc2dabe-8a32-478b-9bae-991e91fc3883','朝陽贊二首  其二','釋祖欽','宋','宋诗','song-poetry','','[]','離離披披破骨董，補一孔了又一孔。',32,'全唐诗/poet.song.225000.json','["離離披披破骨董，補一孔了又一孔。", "三竿紅日透籬邊，看來何止七斤重。"]'),
('e47b9faa-01dc-46b3-8c9a-760e14e64e65','德富藏主請','釋祖欽','宋','宋诗','song-poetry','','[]','巍巍堂堂，煒煒煌煌。',45,'全唐诗/poet.song.225000.json','["巍巍堂堂，煒煒煌煌。", "佩小釋迦懸記，身穿御賜衣黄。", "人言有德可富，自羞伎倆尋常，蕭蕭兩鬢風霜。"]'),
('03d8d597-a691-49ab-af84-c5ff11458ffa','昭如長老請','釋祖欽','宋','宋诗','song-poetry','','[]','海印發光，昭然如日。',56,'全唐诗/poet.song.225000.json','["海印發光，昭然如日。", "曾對大元聖主，默說不二法門。", "默而說，說而默。", "中興大仰叢林，天下第一法窟。", "見者是誰，石頭古佛。"]'),
('e8dc5d73-241f-4346-8f8b-14e9ad0721ae','智坦西堂請','釋祖欽','宋','宋诗','song-poetry','','[]','大智洞明，大道坦平。',42,'全唐诗/poet.song.225000.json','["大智洞明，大道坦平。", "生鐵面具，不近人情。", "雲峯日朗，雪谷雷鳴。", "激起曝腮焦尾，同躍天庭。"]'),
('91c036e3-af0b-4333-a82b-829f08e76f14','原妙侍者請','釋祖欽','宋','宋诗','song-poetry','','[]','上大今已無人，雪巖可知禮也。',28,'全唐诗/poet.song.225000.json','["上大今已無人，雪巖可知禮也。", "虛名塞破乾坤，分付原妙侍者。"]'),
('e11d2520-2fb3-4df2-aa92-59305fc3acdc','嘯巖居士請','釋祖欽','宋','宋诗','song-poetry','','[]','湖山影裏，水月光中。',28,'全唐诗/poet.song.225000.json','["湖山影裏，水月光中。", "似我非我，朦朦朧朧。", "兩眼平生四海空。"]'),
('04120277-cafa-49ac-99d1-7f969654833a','如初禪人請','釋祖欽','宋','宋诗','song-poetry','','[]','身披御賜衣，名在江湖上。',49,'全唐诗/poet.song.225000.json','["身披御賜衣，名在江湖上。", "對面忽相呈，全全不似像。", "雪白眉毛頷下生，仔細看來何止長一丈，也是起模畫樣。"]'),
('300221df-e28b-44d4-8471-34ecfd84149f','覺圓居士請','釋祖欽','宋','宋诗','song-poetry','','[]','妙覺圓明，離諸聞見。',42,'全唐诗/poet.song.225000.json','["妙覺圓明，離諸聞見。", "纔涉安排，雲遮日面。", "若言即此是山僧，三尺竹篦如掣電，好好看方便。"]'),
('dbe0dd68-cac4-4463-a25d-f8fe8b465cf1','題羅漢手軸','釋祖欽','宋','宋诗','song-poetry','','[]','松風浩浩，澗水潺潺。',47,'全唐诗/poet.song.225000.json','["松風浩浩，澗水潺潺。", "白雲影裡，枯木寒巖。", "十八高人，行住坐卧，神通游戲其間。", "龍耳無聽，虎體元班。"]'),
('ced4b2bd-1d9d-4c23-9141-f68cb98d7795','跋圓覺經','釋祖欽','宋','宋诗','song-poetry','','[]','大虛圓滿，妙覺混融。',26,'全唐诗/poet.song.225000.json','["大虛圓滿，妙覺混融。", "如春化物，和而不同，力不在東風。"]'),
('6fcd5951-aaa7-49cf-ae4e-16dbc8bfa772','無準禪師鑄鐘偈','釋祖欽','宋','宋诗','song-poetry','','[]','通身只是一張口，百煉爐中袞出來。',32,'全唐诗/poet.song.225000.json','["通身只是一張口，百煉爐中袞出來。", "斷送夕陽歸去後，又催明月上樓臺。"]'),
('35cfee1b-e557-467e-9cff-ca65488f8ce6','己卯冬日陳世崇來訪仰山寺','釋祖欽','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','千里相尋慰寂寥，未嫌風雪路迢迢。',32,'全唐诗/poet.song.225000.json','["千里相尋慰寂寥，未嫌風雪路迢迢。", "廬山雖好且休去，更撥寒爐話一宵。"]'),
('fc4b70a7-b8ff-4030-8969-1025e8f60ab7','頌古四首  其一','釋祖欽','宋','宋诗','song-poetry','','[]','根尋到底得星兒，冷焰騰輝是此時。',32,'全唐诗/poet.song.225000.json','["根尋到底得星兒，冷焰騰輝是此時。", "拈一莖茅輕點著，不知燒殺五須彌。"]'),
('bc858e8c-5afb-46ee-9ae7-00ea806a5182','頌古四首  其二','釋祖欽','宋','宋诗','song-poetry','','[]','九九八十一，窮漢受罪畢。',24,'全唐诗/poet.song.225000.json','["九九八十一，窮漢受罪畢。", "纔擬展脚眠，蚊蟲獦蚤出。"]'),
